def _cfgvis_pool_keys(defaults):
    return tuple(sorted(
        k for k in defaults
        if (k.startswith(("DL_Pool_", "nnue_Pool_"))
            or k.endswith("_Engine_Index"))))


def _cfgvis_book_keys(defaults):
    return tuple(sorted(
        k for k in defaults
        if k == "Book_Path" or k.startswith("Book_Pool_")))


def _cfgvis_slot_keys(defaults):
    return tuple(sorted(
        k for k in defaults
        if (k.endswith("_Path") and "_Pool_" not in k and k != "Book_Path")
        or k in ("nnue_1_FV_Scale", "nnue_2_FV_Scale")))


_CONFIG_TXT_SECTIONS = (
    ("user",
     "日常設定: 主戦 NNUE の資源と floodgate 認証。ここ以外のキーも"
     "このファイルに手書きで足せば必ず override が効く (寛容マージ)。",
     lambda d: ()),
    ("book",
     "定跡: Book_Path と Book_Pool_{i}_{BookFile,Label,Trust}。",
     _cfgvis_book_keys),
    ("engine",
     "エンジン実体の定義と選択 — エンジンの入れ替えはここ。"
     "*_Pool_{letter}_Path がディスク上の実体、DL/nnue_Pool_{letter}_* が"
     "そのエンジン固有値、*_Engine_Index がスロット→プールの割当。",
     _cfgvis_pool_keys),
    ("slot",
     "役割スロット直付け override。★通常は使わない: ここに値を焼くと"
     "プール解決 (*_Engine_Index) を覆い隠す。スロットに何が入っても同じ値を"
     "強制したい稀なケース専用。",
     _cfgvis_slot_keys),
    ("core",
     "コア挙動・調整値。住処は spsa_config / setup_config 層 — "
     "config.txt に書けば最優先 override にはなる。",
     lambda d: tuple(sorted(d))),
)

_CONFIG_TXT_SECTION_SHOW = {
    "user":   False,
    "book":   False,
    "engine": False,
    "slot":   False,
    "core":   False,
}
_CONFIG_TXT_FORCE_SHOW = ()
_CONFIG_TXT_FORCE_HIDE = ()


def _config_txt_visible_keys():
    seen = set()
    out = []
    for sec_id, _hdr, resolver in _CONFIG_TXT_SECTIONS:
        show = _CONFIG_TXT_SECTION_SHOW.get(sec_id, False)
        for k in resolver(_CONFIG_DEFAULTS):
            if k in seen or k not in _CONFIG_DEFAULTS:
                continue
            seen.add(k)
            if k in _CONFIG_TXT_FORCE_HIDE:
                continue
            if show or k in _CONFIG_TXT_FORCE_SHOW:
                out.append((sec_id, k))
    return tuple(out)


_CONFIG_TXT_KEYS = tuple(k for _s, k in _config_txt_visible_keys())


def _build_config_txt_defaults():
    _hdrs = {s: h for s, h, _r in _CONFIG_TXT_SECTIONS}
    out = {}
    cur_sec = None
    for sec_id, k in _config_txt_visible_keys():
        if sec_id != cur_sec:
            out[f"_README_{sec_id}"] = _hdrs[sec_id]
            cur_sec = sec_id
        out[k] = _CONFIG_DEFAULTS[k]
    return out

def _lerp(lo: float, hi: float, t: float) -> float:
    return lo + (hi - lo) * t


def _checked_range(value, lo, hi, name: str):
    if value < lo or value > hi:
        clamped = max(lo, min(hi, value))
        _flog(f"[CONTRACT] {name}: {value} が範囲 [{lo}, {hi}] 外 — {clamped} にクランプ")
        return clamped
    return value

_LERP_SLOWMOVER = (_CONFIG_DEFAULTS["TA_Lerp_SlowMover_Lo"],
                   _CONFIG_DEFAULTS["TA_Lerp_SlowMover_Hi"])
_LERP_DL_RATIO  = (_CONFIG_DEFAULTS["TA_Lerp_DL_Ratio_Lo"],
                   _CONFIG_DEFAULTS["TA_Lerp_DL_Ratio_Hi"])
_LERP_DL_MAX_MS = (_CONFIG_DEFAULTS["TA_Lerp_DL_Max_Ms_Lo"],
                   _CONFIG_DEFAULTS["TA_Lerp_DL_Max_Ms_Hi"])

_TA_BASE_ANCHOR = float(_CONFIG_DEFAULTS["Time_Aggression"])
_TA_BASE_GAIN_LO = 0.55
_TA_BASE_GAIN_HI = 1.60
_TA_CEIL = 1.25
_TA_FAC_FLOOR = 0.05


def _time_aggression_base_gain(base: float) -> float:
    try:
        b = float(base)
    except (TypeError, ValueError):
        return 1.0
    if not (b == b) or b <= 1e-6 or _TA_BASE_ANCHOR <= 1e-6:
        return 1.0
    g = b / _TA_BASE_ANCHOR
    if g < _TA_BASE_GAIN_LO:
        return _TA_BASE_GAIN_LO
    if g > _TA_BASE_GAIN_HI:
        return _TA_BASE_GAIN_HI
    return g

def _same_config_value(a, b, tol=1e-9):
    try:
        return abs(float(a) - float(b)) <= tol
    except Exception:
        return str(a) == str(b)


def _could_be_auto_lerp(val, lo, hi, max_t=1.25, tol=0.001):
    try:
        val = float(val)
    except (TypeError, ValueError):
        return False
    v_min = min(lo, lo + (hi - lo) * max_t)
    v_max = max(lo, lo + (hi - lo) * max_t)
    return (v_min - tol) <= val <= (v_max + tol)

def _could_be_auto_scale(val, coeff, max_t=1.25, tol=0.01):
    try:
        val = float(val)
    except (TypeError, ValueError):
        return False
    return -tol <= val <= coeff * max_t + tol

def _resolve_auto_managed(key, auto_val, check_fn=None, tol=0.001):
    if key not in _user_cfg_keys:
        return auto_val, False
    try:
        user_val = float(_cfg[key])
    except (ValueError, TypeError):
        return auto_val, False
    if abs(user_val - float(auto_val)) <= tol:
        return auto_val, False
    if check_fn is not None and check_fn(user_val):
        return auto_val, False
    return user_val, True


def _normalize_auto_managed_config(cfg, user_cfg_keys):
    cfg = dict(cfg)
    user_cfg_keys = dict(user_cfg_keys)

    aggr = _cfloat(cfg, "Time_Aggression", _CONFIG_DEFAULTS["Time_Aggression"], 0.0, _TA_CEIL)
    nnue1_hash = _cint(cfg, "nnue_1_Hash", int(_CONFIG_DEFAULTS["nnue_1_Hash"]), 1)
    dl1_hash = _cint(cfg, "DL_1_Hash", int(_CONFIG_DEFAULTS["DL_1_Hash"]), 1)

    auto_values = {
        "nnue_1_SlowMover": str(round(_lerp(*_LERP_SLOWMOVER, _clamp(float(aggr), 0.0, _TA_CEIL)))),
        "nnue_2_SlowMover": str(round(_lerp(*_LERP_SLOWMOVER, _clamp(float(aggr), 0.0, _TA_CEIL)))),
        "DL_Time_Ratio": _lerp(*_LERP_DL_RATIO, _clamp(float(aggr), 0.0, _TA_CEIL)),
        "DL_Time_Max_ms": _lerp(*_LERP_DL_MAX_MS, _clamp(float(aggr), 0.0, _TA_CEIL)),
        "DL_2_Time_Margin_Min_ms": 5000.0 * aggr,
        "DL_3_Rescue_Eff_S_Min": 2.5 * aggr,
        "DL_3_Empty_Eff_S_Min": 2.5 * aggr,
        "nnue_2_Hash": str(nnue1_hash),
        "DL_2_Hash": str(dl1_hash),
        "DL_3_Hash": str(dl1_hash // 2),
    }

    legacy_auto_candidates = {}

    migrated_keys = []
    _auto_range_checks = {
        "nnue_1_SlowMover":        lambda v: _could_be_auto_lerp(v, *_LERP_SLOWMOVER),
        "nnue_2_SlowMover":        lambda v: _could_be_auto_lerp(v, *_LERP_SLOWMOVER),
        "DL_Time_Ratio":           lambda v: _could_be_auto_lerp(v, *_LERP_DL_RATIO),
        "DL_Time_Max_ms":          lambda v: _could_be_auto_lerp(v, *_LERP_DL_MAX_MS, tol=1.0),
        "DL_2_Time_Margin_Min_ms": lambda v: _could_be_auto_scale(v, 5000.0, tol=1.0),
        "DL_3_Rescue_Eff_S_Min":   lambda v: _could_be_auto_scale(v, 2.5),
        "DL_3_Empty_Eff_S_Min":    lambda v: _could_be_auto_scale(v, 2.5),
    }

    for key, auto_value in auto_values.items():
        if key in user_cfg_keys:
            user_value = user_cfg_keys[key]
            candidates = [auto_value]
            candidates.extend(v for v in legacy_auto_candidates.get(key, []) if v is not None)
            if any(_same_config_value(user_value, cand, tol=1e-3) for cand in candidates):
                user_cfg_keys.pop(key, None)
                if not _same_config_value(cfg.get(key), auto_value, tol=1e-3):
                    migrated_keys.append(key)
                cfg[key] = auto_value
            elif key in _auto_range_checks and _auto_range_checks[key](user_value):
                user_cfg_keys.pop(key, None)
                if not _same_config_value(cfg.get(key), auto_value, tol=1e-3):
                    migrated_keys.append(key)
                cfg[key] = auto_value
            else:
                cfg[key] = user_value
        else:
            if not _same_config_value(cfg.get(key), auto_value, tol=1e-3):
                migrated_keys.append(key)
            cfg[key] = auto_value

    return cfg, user_cfg_keys, migrated_keys


def _resolve_and_log(key, auto_val, check_fn=None, tol=0.001, unit="", time_aggression_label="", time_aggression_val=None):
    resolved, user_set = _resolve_auto_managed(key, auto_val, check_fn, tol)
    if user_set:
        _flog(f"{key}: fixed={resolved}{unit} (config.txt explicit; {time_aggression_label} override disabled)")
    else:
        resolved = auto_val
        if time_aggression_label:
            _flog(f"{key}: {resolved}{unit} ({time_aggression_label}={time_aggression_val} linked)")
        else:
            _flog(f"{key}: {resolved}{unit} (auto)")
    return resolved, user_set


def _load_config():
    cfg = dict(_CONFIG_DEFAULTS)

    spsa_path = _SPSA_CONFIG_PATH
    if os.path.exists(spsa_path):
        try:
            with open(spsa_path, encoding="utf-8") as f:
                spsa_loaded = json.load(f)
            _hw_dropped = [k for k in spsa_loaded if _spsa_hw_key_core(k)]
            for _hk in _hw_dropped:
                spsa_loaded.pop(_hk)
            if _hw_dropped:
                _flog("[SETUP] spsa_config.txt のデバイス依存キーを無視 "
                      "(setup 所有): " + " ".join(sorted(_hw_dropped)))
            for _rt in ("Resource_Threads_Share_NNUE1",
                        "Resource_Threads_Share_DL1",
                        "Resource_Threads_Share_DL2",
                        "Resource_Threads_Share_DL3"):
                if _rt in spsa_loaded:
                    _flog(f"[SPSA-RETIRE] spsa_config.txt の {_rt}="
                          f"{spsa_loaded[_rt]} を無視 (調整非対象キー)")
                    spsa_loaded.pop(_rt)
            cfg.update(spsa_loaded)
            _flog(f"spsa_config.txt loaded: {list(spsa_loaded.keys())}")
        except Exception as e:
            _flog(f"spsa_config.txt load error: {e}")

    if os.path.exists(_SETUP_CONFIG_PATH):
        try:
            with open(_SETUP_CONFIG_PATH, encoding="utf-8") as f:
                setup_loaded = json.load(f)
            cfg.update(setup_loaded)
            _flog(f"setup_config.txt loaded: {list(setup_loaded.keys())}")
        except Exception as e:
            _flog(f"setup_config.txt load error: {e}")

    user_cfg_keys = {}
    user_path = os.path.join(_BASE_DIR, "config.txt")
    if not _config_txt_io_enabled():
        _flog("[CFG-IO] config.txt の生成/読み込みを停止中 "
              "(_CONFIG_TXT_IO_ENABLE=False) — defaults + spsa_config + "
              "setup_config のみで動作")
    else:
        if not os.path.exists(user_path) and _config_txt_write_enabled():
            try:
                with open(user_path, "w", encoding="utf-8") as f:
                    json.dump(_build_config_txt_defaults(), f, indent=2, ensure_ascii=False)
                _flog(f"config.txt auto-generated at {user_path}")
            except Exception as e:
                _flog(f"config.txt auto-generation failed: {e}")

        if os.path.exists(user_path):
            try:
                with open(user_path, encoding="utf-8") as f:
                    user_cfg_keys = json.load(f)
                _annot_keys = {k: v for k, v in user_cfg_keys.items()
                               if isinstance(k, str) and k.startswith("_")}
                if _annot_keys:
                    user_cfg_keys = {k: v for k, v in user_cfg_keys.items()
                                     if k not in _annot_keys}
                _seeded_keys = {k: v for k, v in user_cfg_keys.items()
                                if k in _CONFIG_DEFAULTS
                                and str(v) == str(_CONFIG_DEFAULTS[k])}
                if _seeded_keys:
                    user_cfg_keys = {k: v for k, v in user_cfg_keys.items()
                                     if k not in _seeded_keys}
                    _flog(f"[SEED-SHADOW] config.txt のシード既定 {len(_seeded_keys)} 件を "
                          f"override 層から除外 (下位層 spsa/setup が有効)")
                cfg.update(user_cfg_keys)
                if globals().get("_log_config", False):
                    _flog(f"config.txt loaded: {list(user_cfg_keys.keys())}")
            except Exception as e:
                _flog(f"config.txt load error: {e}")
                _user_cfg_parse_failed = True
                print(f"[WARN] config.txt の JSON パースに失敗しました: {e} — "
                      "このファイルは無視されます (自動書き戻しも抑止)。"
                      "構文を修正してください", file=sys.stderr, flush=True)

    _on_disk_keys = list(user_cfg_keys.keys())
    _annot_payload = locals().get("_annot_keys") or {}
    _seeded_payload = locals().get("_seeded_keys") or {}

    cfg, user_cfg_keys, migrated_keys = _normalize_auto_managed_config(cfg, user_cfg_keys)

    if (migrated_keys and _config_txt_write_enabled() and os.path.exists(user_path)
            and not locals().get("_user_cfg_parse_failed", False)):
        try:
            out_cfg = dict(_annot_payload)
            out_cfg.update(_seeded_payload)
            out_cfg.update({k: cfg[k] for k in _on_disk_keys if k in cfg})
            _mig_tmp = user_path + ".tmp"
            with open(_mig_tmp, "w", encoding="utf-8") as f:
                json.dump(out_cfg, f, indent=2, ensure_ascii=False)
                f.write("\n")
            os.replace(_mig_tmp, user_path)
            _flog(f"config.txt auto-migrated latest auto-managed keys: {migrated_keys}")
        except Exception as e:
            _flog(f"config.txt auto-migration write failed: {e}")

    return cfg, user_cfg_keys


def _early_excepthook(exc_type, exc_value, exc_tb):
    msg = _safe_format_exc(exc_type, exc_value, exc_tb)
    _flog("FATAL during module init (before main()):\n" + msg)
    try:
        print(msg, file=sys.stderr)
    except Exception:
        pass

