def _resolve_pool_path(pool_prefix, pool_size, index_key, fallback_key):
    idx = _cfg.get(index_key, None)
    try:
        idx = int(idx)
    except (TypeError, ValueError):
        idx = None
    if idx is not None:
        if pool_size is not None:
            in_range = (0 <= idx < pool_size)
        else:
            _pool_idxs = _detect_pool_indices(pool_prefix)
            if _pool_idxs:
                in_range = (0 <= idx <= max(_pool_idxs))
            else:
                in_range = True
        if in_range:
            key = f"{pool_prefix}{_pool_letter(idx)}_Path"
            if key in _cfg:
                return str(_cfg[key])
    fb = str(_cfg[fallback_key])
    if not os.path.exists(fb):
        _pool_idxs = _detect_pool_indices(pool_prefix)
        if _pool_idxs:
            _try_order = []
            if idx is not None:
                _clamped = min(max(idx, _pool_idxs[0]), _pool_idxs[-1])
                if _clamped in _pool_idxs:
                    _try_order.append(_clamped)
            _try_order += [i for i in _pool_idxs if i not in _try_order]
            for _i in _try_order:
                _pkey = f"{pool_prefix}{_pool_letter(_i)}_Path"
                _pp = _cfg.get(_pkey)
                if _pp and os.path.exists(str(_pp)):
                    _flog(f"[OE5-C] {fallback_key} のフォールバック先が不在 "
                          f"({fb}) → 実在プール {_pkey} へ救済: {_pp} "
                          f"(index_key={index_key} idx={idx})")
                    print(f"[WARN] {fallback_key} 既定パス不在 → "
                          f"{_pkey} で代替起動します", file=sys.stderr, flush=True)
                    return str(_pp)
    return fb


def _detect_pool_indices(pool_prefix: str) -> list[int]:
    result = []
    pat = re.compile(r"^" + re.escape(pool_prefix) + r"([a-z])_Path$")
    for k in _cfg:
        m = pat.match(k)
        if m:
            result.append(_pool_letter_index(m.group(1)))
    return sorted(i for i in result if i >= 0)


def _detect_book_pool_indices() -> list[int]:
    result = []
    pat = re.compile(r"^Book_Pool_(\d+)_BookFile$")
    for k in _cfg:
        m = pat.match(k)
        if m and str(_cfg.get(k, "")).strip():
            result.append(int(m.group(1)))
    return sorted(result)

