def _resolve_dl_param(resolved_path: str, param_name: str, slot_cfg_key: str) -> str:
    norm = os.path.normcase(os.path.normpath(resolved_path))
    for idx, pool_norm in _DL_POOL_PATHS_NORM.items():
        if norm == pool_norm:
            auto_val = _DL_POOL_PARAMS[idx].get(param_name, "")
            if slot_cfg_key in _user_cfg_keys:
                return str(_cfg[slot_cfg_key])
            return auto_val
    return str(_cfg.get(slot_cfg_key, ""))


def _build_dl_mcts_opts(resolved_path: str, slot_prefix: str) -> dict:
    result: dict = {}
    for param in _DL_MCTS_PARAM_NAMES:
        val = _resolve_dl_param(resolved_path, param, f"{slot_prefix}_{param}")
        if val.strip():
            result[param] = val
    return result


