def _nnue1_hash_after_arb_reserve_core(base_mb, reserve_mb, reserve_active,
                                       floor_mb=256):
    base_mb = int(base_mb)
    if not reserve_active or int(reserve_mb) <= 0:
        return base_mb
    return max(int(floor_mb), base_mb - int(reserve_mb))


