def _probe_csa_mate_solver(path):
    try:
        _r = subprocess.run(
            [path], capture_output=True, timeout=5,
            stdin=subprocess.DEVNULL,
            creationflags=getattr(subprocess, "CREATE_NO_WINDOW", 0),
        )
        _out = (_r.stdout or b"").decode("utf-8", errors="replace") + \
               (_r.stderr or b"").decode("utf-8", errors="replace")
        _has_tsumero = "sfen-tsumero" in _out
        _has_tesuki = "sfen-tesuki" in _out
        _cleaned = _out.replace("sfen-tsumero", "X").replace("sfen-tesuki", "X")
        _has_solve = _has_tsumero or _has_tesuki or "sfen" in _cleaned
        _has_serve = "csa serve" in _out
        return _has_solve, _has_tsumero, _has_tesuki, _has_serve
    except Exception:
        return False, False, False, False

_zyfamate_enable = False
_zyfamate_has_tsumero = False
_zyfamate_has_tesuki = False
_zyfamate_has_serve = False
if _mate_solver_enable:
    try:
        if not (os.path.isabs(_mate_solver_path)
                and os.path.isfile(_mate_solver_path)):
            _zf_stem = os.path.splitext(os.path.basename(_mate_solver_path))[0]
            for _zf_cand in (_mate_solver_path,
                             os.path.join(_BASE_DIR, _mate_solver_path),
                             os.path.join(_BASE_DIR, _zf_stem),
                             os.path.join(_BASE_DIR, "csa")):
                if os.path.isfile(_zf_cand):
                    if _zf_cand != _mate_solver_path:
                        _flog(f"[ZYFAMATE] mate_solver_Path resolved: "
                              f"{_mate_solver_path} → {_zf_cand}")
                        _mate_solver_path = _zf_cand
                    break
    except Exception as _zfr_e:
        _flog(f"[ZYFAMATE] path resolve failed (ignored): {_zfr_e!r}")
    _zf_solve, _zf_tsu, _zf_tek, _zf_srv = _probe_csa_mate_solver(_mate_solver_path)
    if _zf_solve:
        _zyfamate_enable = True
        _zyfamate_has_tsumero = _zf_tsu
        _zyfamate_has_tesuki = _zf_tek
        _zyfamate_has_serve = _zf_srv
        if _zf_tsu and _zf_tek:
            _flog(f"[ZYFAMATE] csa.exe detected (solve+tsumero+tesuki): {_mate_solver_path}")
        else:
            _caps = "solve" + ("+tsumero" if _zf_tsu else "") + ("+tesuki" if _zf_tek else "")
            _flog(f"[CSA-MATE] CSA mate solver detected ({_caps}): {_mate_solver_path}")
    else:
        _flog(f"[MATE-SOLVER] USI engine: {_mate_solver_path}")

