_SBK_BOOK_CACHE: dict = {}

_SBK_PIECE_TYPE_TO_USI_CHAR = {
    1: "P", 2: "L", 3: "N", 4: "S", 5: "G", 6: "B", 7: "R", 8: "K",
}


def _sbk_read_varint(buf: bytes, pos: int):
    result = 0
    shift = 0
    while True:
        b = buf[pos]
        result |= (b & 0x7F) << shift
        pos += 1
        if not (b & 0x80):
            break
        shift += 7
    return result, pos


def _sbk_iter_fields(buf: bytes, start: int, end: int):
    pos = start
    while pos < end:
        tag, pos = _sbk_read_varint(buf, pos)
        field_no = tag >> 3
        wire_type = tag & 0x7
        if wire_type == 0:
            val, pos = _sbk_read_varint(buf, pos)
        elif wire_type == 1:
            val = buf[pos:pos + 8]
            pos += 8
        elif wire_type == 2:
            length, pos = _sbk_read_varint(buf, pos)
            val = buf[pos:pos + length]
            pos += length
        elif wire_type == 5:
            val = buf[pos:pos + 4]
            pos += 4
        else:
            raise ValueError(f"sbk: unsupported wire_type={wire_type} at pos={pos}")
        yield field_no, wire_type, val


def _sbk_move_int_to_usi(move_int: int):
    v = move_int & 0xFFFFFFFF
    from_dan = v & 0xF
    from_suji = (v >> 4) & 0xF
    to_dan = (v >> 8) & 0xF
    to_suji = (v >> 12) & 0xF
    promotion = (v >> 19) & 0x1
    piece = (v >> 24) & 0x1F

    suji_chars = "123456789"
    dan_chars = "abcdefghi"

    if from_dan == 0 and from_suji == 0:
        pt = piece & 0x07
        ch = _SBK_PIECE_TYPE_TO_USI_CHAR.get(pt)
        if ch is None or not (1 <= to_suji <= 9) or not (1 <= to_dan <= 9):
            return None
        return f"{ch}*{suji_chars[to_suji - 1]}{dan_chars[to_dan - 1]}"
    if not (1 <= from_suji <= 9 and 1 <= from_dan <= 9
            and 1 <= to_suji <= 9 and 1 <= to_dan <= 9):
        return None
    promo = "+" if promotion else ""
    return (f"{suji_chars[from_suji - 1]}{dan_chars[from_dan - 1]}"
            f"{suji_chars[to_suji - 1]}{dan_chars[to_dan - 1]}{promo}")


def _sbk_parse_move_bytes(buf: bytes):
    move_int = 0
    weight = 0
    next_id_raw = 0
    for fn, wt, val in _sbk_iter_fields(buf, 0, len(buf)):
        if fn == 1:
            move_int = val
        elif fn == 3:
            weight = val
        elif fn == 4:
            next_id_raw = val
    next_id = next_id_raw & 0xFFFFFFFF
    if next_id >= 0x80000000:
        next_id -= 0x100000000
    return move_int, weight, next_id


def _sbk_parse_state_bytes(buf: bytes):
    state_id = None
    position = None
    moves = []
    for fn, wt, val in _sbk_iter_fields(buf, 0, len(buf)):
        if fn == 1:
            state_id = val
        elif fn == 7:
            try:
                position = val.decode("utf-8")
            except Exception:
                position = None
        elif fn == 9:
            moves.append(val)
    return {"id": state_id, "position": position, "moves": moves}


def _sbk_parse_file(path: str):
    with open(path, "rb") as f:
        buf = f.read()
    pos = 0
    end = len(buf)
    author = None
    states = []
    while pos < end:
        tag, pos2 = _sbk_read_varint(buf, pos)
        field_no = tag >> 3
        wire_type = tag & 0x7
        pos = pos2
        if wire_type != 2:
            raise ValueError(f"sbk: unexpected top-level wire_type={wire_type}")
        length, pos = _sbk_read_varint(buf, pos)
        val = buf[pos:pos + length]
        pos += length
        if field_no == 1:
            author = val.decode("utf-8", errors="replace")
        elif field_no == 3:
            states.append(_sbk_parse_state_bytes(val))
    return author, states


def _sbk_build_position_dict(states: list) -> dict:
    n = len(states)
    if n > 0 and not states[0].get("position"):
        states[0]["position"] = (
            "lnsgkgsnl/1r5b1/ppppppppp/9/9/9/PPPPPPPPP/1B5R1/LNSGKGSNL b - 1")
    decoded_moves = []
    for st in states:
        dm = []
        for mv in st["moves"]:
            try:
                move_int, weight, next_id = _sbk_parse_move_bytes(mv)
            except Exception:
                continue
            usi = _sbk_move_int_to_usi(move_int)
            dm.append((usi, weight, next_id))
        decoded_moves.append(dm)

    roots = [i for i, st in enumerate(states) if st.get("position")]
    visited = [False] * n
    position_dict: dict = {}

    for root_id in roots:
        if visited[root_id]:
            continue
        try:
            root_board = ShogiBoard(sfen=states[root_id]["position"])
        except Exception:
            continue
        visited[root_id] = True
        stack = [(root_id, root_board)]
        while stack:
            sid, board = stack.pop()
            moves_here = decoded_moves[sid]
            if moves_here:
                key = _book_key_from_sfen(board.sfen())
                if key:
                    bucket = position_dict.setdefault(key, {})
                    for usi, weight, _next_id in moves_here:
                        if usi is None:
                            continue
                        if usi not in bucket or weight > bucket[usi]:
                            bucket[usi] = weight
            for usi, weight, next_id in moves_here:
                if usi is None or next_id == -1 or next_id is None:
                    continue
                if not (0 <= next_id < n) or visited[next_id]:
                    continue
                try:
                    nb = board.clone()
                    nb.apply_usi(usi)
                except Exception:
                    continue
                visited[next_id] = True
                stack.append((next_id, nb))

    return position_dict


def _sbk_cache_paths(sbk_path: str):
    base = os.path.basename(sbk_path)
    cache_dir = os.path.dirname(os.path.abspath(sbk_path))
    cache_path = os.path.join(cache_dir, base + ".pyfamate_cache.json")
    return cache_path


def _sbk_load_book(path: str):
    abspath = os.path.abspath(path)
    try:
        st = os.stat(abspath)
    except OSError as e:
        _flog(f"[bookloader-sbk] stat 失敗 path={abspath!r}: {e}")
        return None
    sig = (abspath, st.st_mtime_ns, st.st_size)

    cached = _SBK_BOOK_CACHE.get(abspath)
    if cached is not None and cached[0] == sig:
        return cached[1]

    cache_path = _sbk_cache_paths(abspath)
    if os.path.exists(cache_path):
        try:
            with open(cache_path, "r", encoding="utf-8") as cf:
                cache_obj = json.load(cf)
            if (cache_obj.get("mtime_ns") == st.st_mtime_ns
                    and cache_obj.get("size") == st.st_size):
                position_dict = cache_obj["positions"]
                _SBK_BOOK_CACHE[abspath] = (sig, position_dict)
                _flog(f"[bookloader-sbk] ディスクキャッシュから読込 path={abspath!r} "
                      f"positions={len(position_dict)}")
                return position_dict
            else:
                _flog(f"[bookloader-sbk] ディスクキャッシュが古い (mtime/size不一致) "
                      f"— 再パースします path={abspath!r}")
        except Exception as e:
            _flog(f"[bookloader-sbk] ディスクキャッシュ読込失敗 (再パースします): {e}")

    t0 = time.perf_counter()
    try:
        author, states = _sbk_parse_file(abspath)
        position_dict = _sbk_build_position_dict(states)
    except Exception as e:
        _flog(f"[bookloader-sbk] パース失敗 path={abspath!r}: {e}\n"
              + _safe_format_exc().strip())
        return None
    elapsed = time.perf_counter() - t0
    _flog(f"[bookloader-sbk] パース成功 path={abspath!r} author={author!r} "
          f"states={len(states)} positions={len(position_dict)} elapsed={elapsed:.2f}s")

    _SBK_BOOK_CACHE[abspath] = (sig, position_dict)
    try:
        _sbk_cache_data = {
            "mtime_ns": st.st_mtime_ns,
            "size": st.st_size,
            "source": os.path.basename(abspath),
            "positions": position_dict,
        }
        _atomic_write_file(cache_path,
                           lambda f: json.dump(_sbk_cache_data, f, ensure_ascii=False),
                           label="bookloader-sbk-cache")
        _flog(f"[bookloader-sbk] ディスクキャッシュ書込 path={cache_path!r}")
    except Exception as e:
        _flog(f"[bookloader-sbk] ディスクキャッシュ書込失敗 (無視して続行): {e}")

    return position_dict


def _book_file_is_sbk(filename: str) -> bool:
    return (filename or "").strip().lower().endswith(".sbk")



_DB_BOOK_CACHE: dict = {}

_YBB_MAGIC          = b"YANE-BINBOOK-V1\0"
_YBB_FLAG_MOVE_DEPTH = 1
_YBB_KNOWN_FLAGS    = _YBB_FLAG_MOVE_DEPTH
_YBB_HEADER_STRUCT     = _struct.Struct("<16sQQ")
_YBB_INDEX_STRUCT      = _struct.Struct("<32sQHH")
_YBB_MOVE_STRUCT       = _struct.Struct("<Hh")
_YBB_MOVE_DEPTH_STRUCT = _struct.Struct("<HhH")


def _book_file_is_db(filename: str) -> bool:
    return (filename or "").strip().lower().endswith(".db")


def _book_file_is_ybb(filename: str) -> bool:
    return (filename or "").strip().lower().endswith(".ybb")


def _book_file_is_dbybb(filename: str) -> bool:
    return _book_file_is_db(filename) or _book_file_is_ybb(filename)


def _db_parse_db_text(path: str) -> dict:
    position_dict: dict = {}
    with open(path, "r", encoding="utf-8", errors="ignore") as f:
        f.readline()
        cur_key = None
        for line in f:
            s = line.strip()
            if not s or s.startswith("#"):
                continue
            if s.startswith("sfen "):
                cur_key = _book_key_from_sfen(s)
                continue
            if cur_key is None:
                continue
            toks = s.split()
            if not toks:
                continue
            usi = toks[0]
            value = _book_parse_int(toks[2] if len(toks) > 2 else None, 0)
            count = _book_parse_int(toks[4] if len(toks) > 4 else None, 1)
            if count < 1:
                count = 1
            position_dict.setdefault(cur_key, []).append((usi, value, count))
    return position_dict


def _db_parse_ybb(path: str) -> dict:
    with open(path, "rb") as f:
        raw = f.read()
    if len(raw) < _YBB_HEADER_STRUCT.size:
        raise ValueError("ybb: header too short")
    magic, record_count, flags = _YBB_HEADER_STRUCT.unpack(
        raw[:_YBB_HEADER_STRUCT.size])
    if magic != _YBB_MAGIC:
        raise ValueError(f"ybb: invalid magic {magic!r}")
    if flags & ~_YBB_KNOWN_FLAGS:
        raise ValueError(f"ybb: unknown flags {flags}")
    move_struct = (_YBB_MOVE_DEPTH_STRUCT if (flags & _YBB_FLAG_MOVE_DEPTH)
                   else _YBB_MOVE_STRUCT)
    moves_base = _YBB_HEADER_STRUCT.size + record_count * _YBB_INDEX_STRUCT.size
    if len(raw) < moves_base:
        raise ValueError("ybb: index area truncated")

    position_dict: dict = {}
    idx_off = _YBB_HEADER_STRUCT.size
    for _ in range(record_count):
        packed_sfen, move_offset, _ply, move_count = _YBB_INDEX_STRUCT.unpack(
            raw[idx_off:idx_off + _YBB_INDEX_STRUCT.size])
        idx_off += _YBB_INDEX_STRUCT.size
        try:
            key = _book_key_from_sfen(_fast_psfen_to_sfen(packed_sfen))
        except Exception:
            continue
        if not key:
            continue
        mbase = moves_base + move_offset
        moves = []
        for k in range(move_count):
            off = mbase + k * move_struct.size
            chunk = raw[off:off + move_struct.size]
            if len(chunk) != move_struct.size:
                break
            if flags & _YBB_FLAG_MOVE_DEPTH:
                move16, value, _depth = move_struct.unpack(chunk)
            else:
                move16, value = move_struct.unpack(chunk)
            usi = _move16_to_usi(move16 & 0xFFFF)
            if usi in ("none", "null", "resign", "win"):
                continue
            moves.append((usi, int(value), 1))
        if moves:
            position_dict[key] = moves
    return position_dict


def _db_cache_path(path: str) -> str:
    base = os.path.basename(path)
    cache_dir = os.path.dirname(os.path.abspath(path))
    return os.path.join(cache_dir, base + ".pyfamate_dbcache.json")


def _db_load_book(path: str):
    abspath = os.path.abspath(path)
    try:
        stt = os.stat(abspath)
    except OSError as e:
        _flog(f"[bookloader-db] stat 失敗 path={abspath!r}: {e}")
        return None
    sig = (abspath, stt.st_mtime_ns, stt.st_size)

    cached = _DB_BOOK_CACHE.get(abspath)
    if cached is not None and cached[0] == sig:
        return cached[1]

    cache_path = _db_cache_path(abspath)
    if os.path.exists(cache_path):
        try:
            with open(cache_path, "r", encoding="utf-8") as cf:
                cache_obj = json.load(cf)
            if (cache_obj.get("mtime_ns") == stt.st_mtime_ns
                    and cache_obj.get("size") == stt.st_size):
                pd = {k: [tuple(m) for m in v]
                      for k, v in cache_obj["positions"].items()}
                _DB_BOOK_CACHE[abspath] = (sig, pd)
                _flog(f"[bookloader-db] ディスクキャッシュから読込 path={abspath!r} "
                      f"positions={len(pd)}")
                return pd
            _flog(f"[bookloader-db] ディスクキャッシュが古い — 再パース path={abspath!r}")
        except Exception as e:
            _flog(f"[bookloader-db] ディスクキャッシュ読込失敗 (再パース): {e}")

    t0 = time.perf_counter()
    try:
        if _book_file_is_ybb(abspath):
            pd = _db_parse_ybb(abspath)
        else:
            pd = _db_parse_db_text(abspath)
    except Exception as e:
        _flog(f"[bookloader-db] パース失敗 path={abspath!r}: {e}\n"
              + _safe_format_exc().strip())
        return None
    elapsed = time.perf_counter() - t0
    _flog(f"[bookloader-db] パース成功 path={abspath!r} positions={len(pd)} "
          f"elapsed={elapsed:.2f}s")

    _DB_BOOK_CACHE[abspath] = (sig, pd)
    try:
        _db_cache_data = {
            "mtime_ns": stt.st_mtime_ns,
            "size": stt.st_size,
            "source": os.path.basename(abspath),
            "positions": pd,
        }
        _atomic_write_file(cache_path,
                           lambda f: json.dump(_db_cache_data, f, ensure_ascii=False),
                           label="bookloader-db-cache")
        _flog(f"[bookloader-db] ディスクキャッシュ書込 path={cache_path!r}")
    except Exception as e:
        _flog(f"[bookloader-db] ディスクキャッシュ書込失敗 (無視): {e}")

    return pd


class _NullBookEngine(USIEngine):

    def __init__(self):
        super().__init__(path="", name="bookloader-sbk-null")
        self._alive = True

    def start(self):
        pass

    def send(self, cmd):
        pass

    def quit(self):
        pass

    def wait_for(self, keyword, timeout=300.0):
        return f"{keyword} (sbk-null stub)"

    def read_until(self, keyword, timeout=60.0):
        return [f"{keyword} (sbk-null stub)"]

    def readline(self, timeout=5.0):
        return ""

    def initialize(self, options):
        pass

    def setoption(self, key, val):
        pass


def _book_apply_file(ctx, which: str, idx: int, book_file: str, *, send_isready: bool) -> bool:
    eng = ctx.book if which == "book" else ctx.book2
    st = ctx.book_state if which == "book" else ctx.book2_state
    log_tag = "[bookloader]" if which == "book" else "[bookloader2]"

    st.index = idx
    st.book_file = book_file
    st.label = _book_pool_label(idx)
    st.trust = _book_pool_trust(idx, default=(_TRUST_ABSOLUTE if which == "book"
                                               else ctx.cfg.book2_default_trust))

    if _book_file_is_sbk(book_file):
        if not _eng_alive(eng):
            _flog(f"{log_tag} sbk 切替: 子エンジン不在/死亡 — 辞書のみ保持し次回 probe 時に備える。")
        position_dict = _sbk_load_book(book_file)
        if position_dict is None:
            _flog(f"{log_tag} sbk ロード失敗 path={book_file!r} — このプールは定跡なし扱い。")
            st.sbk_position_dict = {}
        else:
            st.sbk_position_dict = position_dict
            _flog(f"{log_tag} sbk 切替成功 path={book_file!r} positions={len(position_dict)} "
                  f"index={idx} trust={st.trust!r}")
        st.db_position_dict = None
        st.db_pool_index = idx
        return True

    if _book_file_is_dbybb(book_file) and _book_pool_db_inmemory(idx):
        if not _eng_alive(eng):
            _flog(f"{log_tag} db 切替: 子エンジン不在/死亡 — 辞書のみ保持し次回 probe 時に備える。")
        position_dict = _db_load_book(book_file)
        if position_dict is None:
            _flog(f"{log_tag} db ロード失敗 path={book_file!r} — このプールは定跡なし扱い。")
            st.db_position_dict = {}
        else:
            st.db_position_dict = position_dict
            _flog(f"{log_tag} db 切替成功 path={book_file!r} positions={len(position_dict)} "
                  f"index={idx} trust={st.trust!r} mode={_db_pool_select_mode(idx)} "
                  f"eval_diff={_db_pool_eval_diff(idx)} ply_range={_db_pool_ply_range(idx)}")
            _HAND_ORDER = "RBGSNLPrbgsnlp"
            _bad_hand = 0
            for _hk in list(position_dict.keys())[:100]:
                _hp = _hk.split()
                if len(_hp) >= 3 and _hp[2] != "-":
                    _hi = -1
                    for _hc in _hp[2]:
                        if _hc.isdigit():
                            continue
                        _hj = _HAND_ORDER.find(_hc)
                        if _hj < 0 or _hj < _hi:
                            _bad_hand += 1
                            break
                        _hi = _hj
            if _bad_hand:
                _flog(f"[BOOK-DB][WARN] 非正準持駒順キーが {_bad_hand}/100 件 "
                      f"(FlippedBook 偽陰性の恐れ) path={book_file!r}")
        st.db_pool_index = idx
        st.sbk_position_dict = None
        return True

    st.sbk_position_dict = None
    st.db_position_dict = None
    if not _eng_alive(eng):
        _flog(f"{log_tag} BookFile 差し替えスキップ — 子エンジン不在/死亡 (book_file={book_file!r})。")
        return False
    try:
        eng.setoption("BookFile", book_file)
        if send_isready:
            eng.send("isready")
            if eng.wait_for("readyok", timeout=30) is None:
                _flog(f"{log_tag} BookFile 差し替え後の readyok timeout (book_file={book_file!r})。")
                return False
    except Exception as e:
        _flog(f"{log_tag} BookFile 差し替え例外 (book_file={book_file!r}): {e}")
        return False
    return True



@dataclasses.dataclass
class _BookState:
    active:      bool = False
    consec:      int  = 0
    turn:        str  = ""
    turn_hint:   str  = ""
    index:       int  = -1
    book_file:   str  = ""
    label:       str  = ""
    trust:       str  = _TRUST_ABSOLUTE
    initialized: bool = False
    sbk_position_dict: object = None
    db_position_dict: object = None
    db_pool_index: int = -1
    firing:      bool = False
    exhausted:   bool = False

    def reset(self):
        self.consec      = 0
        self.turn        = ""
        self.index       = -1
        self.book_file   = ""
        self.label       = ""
        self.trust       = _TRUST_ABSOLUTE
        self.initialized = False
        self.firing      = False
        self.exhausted   = False


def _book_pool_get(index: int, suffix: str, default: str = "") -> str:
    return str(_cfg.get(f"Book_Pool_{index}_{suffix}", default)).strip()


def _book_pool_file(index: int) -> str:
    return _book_pool_get(index, "BookFile")


def _book_pool_label(index: int) -> str:
    return _book_pool_get(index, "Label")


_BOOK_TRUST_VALID = (_TRUST_ABSOLUTE, _TRUST_ADVISORY, _TRUST_SUSPECT)


def _book_pool_trust(index: int, default: str = _TRUST_ABSOLUTE) -> str:
    t = _norm_str(_cfg.get(f"Book_Pool_{index}_Trust", ""))
    if t in _BOOK_TRUST_VALID:
        return t
    return default if default in _BOOK_TRUST_VALID else _TRUST_ABSOLUTE


def _book_council_bias_for_trust(trust: str, cfg) -> float:
    if trust == _TRUST_ADVISORY:
        return cfg.book_council_bias_advisory
    if trust == _TRUST_SUSPECT:
        return cfg.book_council_bias_suspect
    return 0.0


def _book_normalize_turn(turn) -> str:
    if turn is None:
        return ""
    t = _norm_str(turn)
    if t in ("+", "b", "black", "sente"):
        return "+"
    if t in ("-", "w", "white", "gote"):
        return "-"
    return ""


def _book_resolve_index(turn: str, cfg) -> int:
    nt = _book_normalize_turn(turn)
    if nt == "+":
        return cfg.book_sente_index
    if nt == "-":
        return cfg.book_gote_index
    return cfg.book_default_index


def _book_normalize_filename(name: str) -> str:
    n = (name or "").strip()
    if not n or n.lower() == "no_book":
        return n
    _low = n.lower()
    if _low.endswith((".ybb", ".db", ".bin", ".sbk")):
        return n
    return n + ".ybb"


def _book_resolve_file(index: int) -> str:
    f = _book_pool_file(index)
    if not f:
        f = _book_file_name
    f = _book_normalize_filename(f)
    if (f and f.lower() != "no_book"
            and not os.path.isabs(f)
            and "/" not in f and "\\" not in f
            and _book_dir and os.path.isabs(_book_dir)):
        direct = os.path.join(_book_dir, f)
        if os.path.isfile(direct):
            f = direct
        else:
            ext = os.path.splitext(f)[1].lstrip(".").lower()
            if ext:
                sub = os.path.join(_book_dir, ext, f)
                if os.path.isfile(sub):
                    f = sub
                else:
                    f = direct
            else:
                f = direct
    return f


def _book_start_engine(ctx) -> bool:
    if not _book_enabled:
        _flog("[bookloader] disabled — Book_Path 未設定 または プール空。在来探索のみで動作。")
        ctx.book = None
        ctx.book_state.active = False
        return False

    _idx = ctx.cfg.book_default_index
    _bf = _book_resolve_file(_idx)

    ctx.book = _NullBookEngine()
    ctx.book_state.active = True
    _book_apply_file(ctx, "book", _idx, _bf, send_isready=False)
    _flog(f"[bookloader] 起動成功 pool_indices={_book_pool_indices} "
          f"default_index={_idx} book_file={_bf!r} label={ctx.book_state.label!r} "
          f"trust={ctx.book_state.trust!r}")
    return True

def _book_begin_game(ctx, turn: str = "") -> None:
    if getattr(ctx, "shitei_active", False):
        _flog("[bookloader] 指定局面戦 — 本局は定跡なしで続行 "
              "([SHITEIKYOKUMEN-FIX 2026-07-10])")
        ctx.book_state.active = False
        return
    if not _eng_alive(ctx.book):
        if _book_enabled:
            _flog("[bookloader] usinewgame: Book エンジンが不在/死亡 — 再起動を試みます。")
            if ctx.book is not None:
                try:
                    ctx.book.quit()
                except Exception as _qe:
                    _flog(f"[bookloader] 既存ハンドルの quit 例外 (無視): {_qe}")
                ctx.book = None
            _book_start_engine(ctx)
        if not _eng_alive(ctx.book):
            ctx.book_state.active = False
            return
    st = ctx.book_state
    st.active = True
    nt = _book_normalize_turn(turn)
    st.turn = nt
    st.turn_hint = ""
    idx = _book_resolve_index(nt, ctx.cfg)
    bf = _book_resolve_file(idx)
    if not ctx.cfg.book_auto_turn:
        _route = "Default_Index 固定 (Auto_Turn=false)" if not nt else "turn 指定 (Auto_Turn=false)"
    elif nt:
        _route = "Auto_Turn 使用 (CSA turn / 明示 turn)"
    else:
        _route = "フォールバック (turn 未取得 → Default_Index)"
    _flog(
        f"[bookloader] usinewgame: turn={nt or '?'} → index={idx} "
        f"book_file={bf!r} label={_book_pool_label(idx)!r} 経路={_route}"
    )
    try:
        ctx.book.send("usinewgame")
        _applied = _book_apply_file(ctx, "book", idx, bf, send_isready=True)
        _bf_no_child = (_book_file_is_sbk(bf)
                        or (_book_file_is_dbybb(bf) and _book_pool_db_inmemory(idx)))
        if not _applied and not _bf_no_child:
            _flog("[bookloader] usinewgame 後の BookFile 差し替え失敗 — Book 無効化。")
            _book_kill(ctx, reason="usinewgame BookFile 差し替え失敗")
            return
    except Exception as e:
        _flog(f"[bookloader] usinewgame 送信例外 — Book 無効化: {e}")
        _book_kill(ctx, reason="usinewgame exception")
        return
    st.initialized = True


def _book_maybe_resolve_turn_from_position(ctx, position_cmd: str) -> None:
    st = ctx.book_state
    if not st.active or st.turn:
        return
    if not ctx.cfg.book_auto_turn:
        return
    n_moves = 0
    m = re.search(r"\bmoves\b(.*)$", position_cmd)
    if m:
        n_moves = len([t for t in m.group(1).split() if t])
    nt = "+" if (n_moves % 2 == 0) else "-"
    idx = _book_resolve_index(nt, ctx.cfg)
    bf = _book_resolve_file(idx)
    if idx != st.index or bf != st.book_file:
        st.turn = nt
        _flog(
            f"[bookloader] position から手番判定: n_moves={n_moves} turn={nt} "
            f"→ index={idx} book_file={bf!r} (BookFile 差し替え)"
        )
        try:
            _book_apply_file(ctx, "book", idx, bf, send_isready=True)
        except Exception as e:
            _flog(f"[bookloader] BookFile 差し替え例外: {e}")
    else:
        st.turn = nt


def _book_pool_db_inmemory(index: int) -> bool:
    v = _book_pool_get(index, "DB_InMemory", "false").lower()
    return v in ("true", "1", "yes", "on")


def _db_pool_select_mode(index: int) -> str:
    m = _book_pool_get(index, "DB_SelectMode", "head").lower()
    return m if m in ("head", "value") else "head"


def _db_pool_eval_diff(index: int) -> int:
    try:
        return max(0, int(_book_pool_get(index, "DB_EvalDiff", "0")))
    except Exception:
        return 0



def _mirror_sfen_board(board_s: str) -> str:
    def _mirror_rank(rank: str) -> str:
        toks = []
        i = 0
        n = len(rank)
        while i < n:
            ch = rank[i]
            if ch.isdigit():
                toks.append(ch)
                i += 1
            elif ch == "+":
                toks.append(rank[i:i + 2])
                i += 2
            else:
                toks.append(ch)
                i += 1
        out = []
        for t in reversed(toks):
            if t.isdigit():
                out.append(t)
            else:
                out.append(t.swapcase())
        return "".join(out)

    ranks = board_s.split("/")
    flipped = [_mirror_rank(r) for r in reversed(ranks)]
    return "/".join(flipped)


def _mirror_sfen_hand(hand_s: str) -> str:
    if hand_s == "-" or not hand_s:
        return "-"
    _canon = "RBGSNLP"
    upper = {}
    lower = {}
    for _cnt, _pc in re.findall(r"(\d*)([A-Za-z])", hand_s):
        _flip = _pc.swapcase()
        (upper if _flip.isupper() else lower)[_flip.upper()] = _cnt
    out = []
    for _p in _canon:
        if _p in upper:
            out.append(upper[_p] + _p)
    for _p in _canon:
        if _p in lower:
            out.append(lower[_p] + _p.lower())
    return "".join(out) if out else "-"


def _mirror_sfen_key(key: str) -> str:
    parts = key.split()
    if len(parts) < 4:
        return ""
    board_s, turn_s, hand_s = parts[0], parts[-3], parts[-2]
    fb = _mirror_sfen_board(board_s)
    ft = "w" if turn_s == "b" else "b"
    fh = _mirror_sfen_hand(hand_s)
    return f"{fb} {ft} {fh} 0"


_USI_SQ_RE = re.compile(r"^([1-9])([a-i])$")


def _mirror_usi_square(sq: str) -> str:
    m = _USI_SQ_RE.match(sq)
    if not m:
        return sq
    f = int(m.group(1))
    r = ord(m.group(2)) - ord("a") + 1
    nf = 10 - f
    nr = 10 - r
    return f"{nf}{chr(ord('a') + nr - 1)}"


def _mirror_usi_move(usi: str) -> str:
    if not usi or usi in ("none", "null", "resign", "win", "pass"):
        return usi
    if "*" in usi:
        piece, dst = usi.split("*", 1)
        return f"{piece}*{_mirror_usi_square(dst)}"
    promo = ""
    body = usi
    if body.endswith("+"):
        promo = "+"
        body = body[:-1]
    if len(body) != 4:
        return usi
    src, dst = body[:2], body[2:]
    return f"{_mirror_usi_square(src)}{_mirror_usi_square(dst)}{promo}"


def _db_pool_ply_range(index: int):
    raw = _book_pool_get(index, "DB_PlyRange", "")
    if not raw or "-" not in raw:
        return None
    lo_s, _, hi_s = raw.partition("-")
    try:
        lo = int(lo_s) if lo_s.strip() else 0
        hi = int(hi_s) if hi_s.strip() else (1 << 30)
    except Exception:
        return None
    if lo > hi:
        lo, hi = hi, lo
    return (lo, hi)


def _db_current_ply(position_cmd: str) -> int:
    m = re.search(r"\bmoves\b(.*)$", position_cmd or "")
    if not m:
        return 0
    return len([t for t in m.group(1).split() if t])


def _db_probe_position(st, position_cmd: str):
    pd = getattr(st, "db_position_dict", None)
    if not pd:
        return (False, None)
    try:
        _lbk = _LIVE_BOOK_KEY
        if _lbk[0] == position_cmd and _lbk[1]:
            key = _lbk[1]
        else:
            key = _book_key_from_sfen(_board_for_position(position_cmd).sfen())
        if _LIVE_BOOK_KEY_VERIFY and _lbk[0] == position_cmd and _lbk[1]:
            _ref_key = _book_key_from_sfen(_board_for_position(position_cmd).sfen())
            if key != _ref_key:
                _flog(f"[BOOK-KEY][WARN] cached != rebuilt key={key!r} ref={_ref_key!r}")
                key = _ref_key
    except Exception as e:
        _flog(f"[bookloader-db] 局面復元失敗 (定跡切れ扱い): {e}")
        return (False, None)
    if not key:
        return (False, None)

    idx = getattr(st, "db_pool_index", -1)
    _flipped_hit = False
    moves = pd.get(key)
    if not moves:
        _fkey = _mirror_sfen_key(key)
        if _fkey:
            _fmoves = pd.get(_fkey)
            if _fmoves:
                moves = [(_mirror_usi_move(u), v, c) for (u, v, c) in _fmoves]
                _flipped_hit = True
                _flog(f"[bookloader-db] FlippedBook ヒット key={key} → flip={_fkey} "
                      f"候補={len(moves)}")
    if not moves:
        return (False, None)

    mode = _db_pool_select_mode(idx)
    eval_diff = _db_pool_eval_diff(idx)
    ply_range = _db_pool_ply_range(idx)

    apply_diff = eval_diff > 0
    if apply_diff and ply_range is not None:
        ply = _db_current_ply(position_cmd)
        lo, hi = ply_range
        if not (lo <= ply <= hi):
            apply_diff = False

    cand = moves
    if apply_diff:
        best_v = max(v for (_u, v, _c) in moves)
        cand = [t for t in moves if (best_v - t[1]) <= eval_diff]
        if not cand:
            cand = moves

    if mode == "value":
        move = max(cand, key=lambda t: t[1])[0]
    else:
        move = cand[0][0]

    _flog(f"[bookloader-db] 定跡ヒット key={key} 候補={len(moves)}→{len(cand)} "
          f"mode={mode} eval_diff={eval_diff} ply_range={ply_range} "
          f"flipped={_flipped_hit} move={move}")
    return (True, move)


def _sbk_probe_position(st, position_cmd: str):
    pd = getattr(st, "sbk_position_dict", None)
    if not pd:
        return (False, None)
    try:
        _lbk = _LIVE_BOOK_KEY
        if _lbk[0] == position_cmd and _lbk[1]:
            key = _lbk[1]
        else:
            key = _book_key_from_sfen(_board_for_position(position_cmd).sfen())
        if _LIVE_BOOK_KEY_VERIFY and _lbk[0] == position_cmd and _lbk[1]:
            _ref_key = _book_key_from_sfen(_board_for_position(position_cmd).sfen())
            if key != _ref_key:
                _flog(f"[BOOK-KEY][WARN] cached != rebuilt key={key!r} ref={_ref_key!r}")
                key = _ref_key
    except Exception as e:
        _flog(f"[bookloader-sbk] 局面復元失敗 (定跡切れ扱い): {e}")
        return (False, None)
    if not key:
        return (False, None)
    bucket = pd.get(key)
    _flipped_hit = False
    if not bucket:
        _fkey = _mirror_sfen_key(key)
        if _fkey:
            _fbucket = pd.get(_fkey)
            if _fbucket:
                bucket = {_mirror_usi_move(u): w for u, w in _fbucket.items()}
                _flipped_hit = True
                _flog(f"[bookloader-sbk] FlippedBook ヒット key={key} → flip={_fkey} "
                      f"候補={len(bucket)}")
    if not bucket:
        return (False, None)
    moves = list(bucket.keys())
    weights = [max(int(bucket[m] or 0), 0) for m in moves]
    if sum(weights) <= 0:
        move = random.choice(moves)
    else:
        move = random.choices(moves, weights=weights, k=1)[0]
    _flog(f"[bookloader-sbk] 定跡ヒット key={key} 候補={len(moves)} "
          f"flipped={_flipped_hit} move={move} weight={bucket.get(move)}")
    return (True, move)


def _book_probe(ctx, position_cmd: str, eng=None, st=None):
    if eng is None:
        eng = ctx.book
    if st is None:
        st = ctx.book_state
    if st is not None and getattr(st, "sbk_position_dict", None) is not None:
        return _sbk_probe_position(st, position_cmd)
    if st is not None and getattr(st, "db_position_dict", None) is not None:
        return _db_probe_position(st, position_cmd)
    if not _eng_alive(eng):
        return (False, None)
    while True:
        try:
            eng._q.get_nowait()
        except queue.Empty:
            break
    try:
        eng.send(position_cmd)
        eng.send(f"go movetime {ctx.cfg.book_timeout_ms}")
    except Exception as e:
        _flog(f"[bookloader] probe 送信例外: {e}")
        return (False, None)

    scored_info_seen = False
    book_info_seen   = False
    bestmove         = None
    global _BOOK_PROBE_TRACE_LEFT
    _trace_this = _BOOK_PROBE_TRACE_LEFT > 0
    if _trace_this:
        _BOOK_PROBE_TRACE_LEFT -= 1
        _flog(f"[bookloader] probe trace start: {position_cmd}")
    t_start = time.perf_counter()
    _bk_grace_s = 2.0
    try:
        _bk_ck = ctx.ps.go_clock or ctx.ps.ponder_clock
        if _bk_ck is not None:
            _bk_tot_ms = ((_bk_ck.remaining_ms or 0) + (_bk_ck.floor_ms or 0)
                          + (_bk_ck.inc_ms or 0))
            if _bk_tot_ms > 0:
                _bk_grace_s = _clamp(_bk_tot_ms / 1000.0 * 0.10, 0.3, 2.0)
                if _bk_tot_ms >= 8000:
                    _bk_grace_s = max(_bk_grace_s, 1.5)
    except Exception:
        pass
    deadline = t_start + (ctx.cfg.book_timeout_ms / 1000.0) + _bk_grace_s
    while True:
        remaining = deadline - time.perf_counter()
        if remaining <= 0:
            _flog(f"[bookloader] probe タイムアウト (bestmove 未到達, "
                  f"{ctx.cfg.book_timeout_ms}ms+余裕 超過)")
            try:
                eng.send("stop")
            except Exception as _ie:
                _flog(f"[ignored] _book_probe: {_ie!r}")
            return (False, None)
        line = eng.readline(timeout=min(remaining, 1.0))
        if line is None:
            _flog("[bookloader] probe 中にエンジン死亡 (readline None)")
            return (False, None)
        if line == "":
            continue
        if _trace_this:
            _flog(f"[bookloader] probe<< {line}")
        if line.startswith("info"):
            low = line.lower()
            if "depth" in line and "score" in line:
                scored_info_seen = True
            if line.startswith("info string") and (
                    "book" in low
                    or "moves to" in low
                    or "bookeval" in low):
                book_info_seen = True
            continue
        if line.startswith("bestmove"):
            m = _RE_BESTMOVE.match(line)
            bestmove = m.group(1) if m else None
            break
    elapsed = time.perf_counter() - t_start
    if bestmove is None:
        return (False, None)
    if book_info_seen:
        _flog(f"[bookloader] 定跡ヒット (info string book) move={bestmove} "
              f"elapsed={elapsed:.3f}s")
        return (True, bestmove)
    if scored_info_seen:
        _flog(f"[bookloader] 探索手 (book シグナル無し) move={bestmove} "
              f"elapsed={elapsed:.3f}s → 定跡切れ")
    else:
        _flog(f"[bookloader] 定跡シグナル無し move={bestmove} "
              f"elapsed={elapsed:.3f}s → 定跡切れ")
    return (False, None)


def _book_try_move(ctx, position_cmd: str, eng=None, st=None, kill_fn=None,
                   consec_max=None):
    if eng is None:
        eng = ctx.book
    if st is None:
        st = ctx.book_state
    if kill_fn is None:
        kill_fn = _book_kill
    if consec_max is None:
        consec_max = ctx.cfg.book_consec_max
    if not _book_enabled or not st.active or not _eng_alive(eng):
        return None
    if st is ctx.book_state:
        _book_maybe_resolve_turn_from_position(ctx, position_cmd)
    hit, move = _book_probe(ctx, position_cmd, eng=eng, st=st)
    if hit and move not in (None, ""):
        st.consec = 0
        _flog(f"[bookloader] 定跡ヒット turn={st.turn or '?'} move={move} "
              f"trust={st.trust} consec=0/{consec_max} book_file={st.book_file!r}")
        return move
    st.consec += 1
    _flog(f"[bookloader] 定跡切れ turn={st.turn or '?'} "
          f"consec={st.consec}/{consec_max}")
    _hard_kill_consec = ctx.cfg.book_hard_kill_consec
    if _hard_kill_consec and st.consec >= _hard_kill_consec:
        kill_fn(ctx, reason=f"連続定跡切れ {st.consec} 回 "
                            f"(hard_kill={_hard_kill_consec}; エンジン応答不能とみなす)")
    return None


def _book_consult(ctx, position_cmd: str):
    move = _book_try_move(ctx, position_cmd)
    if move:
        return (move, ctx.book_state.trust)

    if (ctx.book_state.turn == "+"
            and not ctx.book2_state.exhausted
            and ctx.book_state.consec >= ctx.cfg.book2_fire_consec
            and (not _eng_alive(ctx.book2))):
        _book2_fire_async(ctx)

    return (None, "")


def _book2_fire(ctx) -> None:
    if _eng_alive(ctx.book2):
        return
    _idx = ctx.cfg.book2_pool_index
    _bf = _book_resolve_file(_idx)
    if not _bf:
        _flog(f"[bookloader2] Book2_Pool_Index={_idx} の BookFile 未解決 — 第2 Book 起動中止。")
        return
    _b2_kind = "sbk" if _book_file_is_sbk(_bf) else "db"
    _flog(f"[bookloader2] 定跡切れ検出 (main consec={ctx.book_state.consec}) — "
          f"第2 Book ({_b2_kind}) を Fire します pool={_idx} book_file={_bf!r}")
    try:
        ctx.book2 = _NullBookEngine()
        st = ctx.book2_state
        st.active = True
        st.consec = 0
        st.turn = ctx.book_state.turn
        _ok = _book_apply_file(ctx, "book2", _idx, _bf, send_isready=False)
        st.initialized = _ok
        if not _ok:
            _flog(f"[bookloader2] 第2 Book ({_b2_kind}) apply 失敗 pool={_idx} "
                  f"book_file={_bf!r} — 初期化未完了扱い。")
        else:
            _flog(f"[bookloader2] 第2 Book ({_b2_kind}) 起動成功 pool={_idx} book_file={_bf!r} "
                  f"label={st.label!r} trust={st.trust!r}")
    except Exception as e:
        _flog(f"[bookloader2] {_b2_kind} 起動例外 — 第2 Book 無効化: {e}")
        ctx.book2 = None
        ctx.book2_state.active = False


def _book2_fire_async(ctx) -> None:
    st = ctx.book2_state
    if st.firing:
        return
    if _eng_alive(ctx.book2):
        return
    st.firing = True

    def _run():
        try:
            _book2_fire(ctx)
        except Exception as _e:
            _flog(f"[bookloader2] async fire 例外 (無視): {_e}")
        finally:
            ctx.book2_state.firing = False

    threading.Thread(target=_run, daemon=True, name="book2-async-fire").start()
    _flog("[bookloader2] 非同期 fire 開始 — council を回す裏で第2 Book を起動")


def _book2_probe_seed_if_ready(ctx, position_cmd: str):
    st = ctx.book2_state
    if not (_eng_alive(ctx.book2)
            and st.active and st.initialized):
        return (None, "")
    hit, move = _book_probe(ctx, position_cmd, eng=ctx.book2, st=st)
    if hit and move not in (None, ""):
        return (move, st.trust)
    return (None, "")


def _book2_kill(ctx, reason: str = "") -> None:
    st = ctx.book2_state
    st.active = False
    st.initialized = False
    st.exhausted = True
    if ctx.book2 is None:
        return
    _flog(f"[bookloader2] 終了: {reason} — 第2 Book エンジンを quit します。")
    try:
        ctx.book2.quit()
    except Exception as e:
        _flog(f"[bookloader2] quit 例外 (無視): {e}")
    ctx.book2 = None


def _book_any_active(ctx) -> bool:
    if not _book_enabled:
        return False
    if (_eng_alive(ctx.book)
            and ctx.book_state.active and ctx.book_state.initialized):
        return True
    if (_eng_alive(ctx.book2)
            and ctx.book2_state.active and ctx.book2_state.initialized):
        return True
    return False


def _book_kill(ctx, reason: str = "") -> None:
    st = ctx.book_state
    st.active = False
    st.initialized = False
    if ctx.book is None:
        return
    _flog(f"[bookloader] 終了: {reason} — Book エンジンを quit します。")
    try:
        ctx.book.quit()
    except Exception as e:
        _flog(f"[bookloader] quit 例外 (無視): {e}")
    ctx.book = None



