def _handle_spsa(ctx, line):
    _flog("[SPSA] 'spsa' command received — starting built-in SPSA tuning")
    print("info string [setup] SPSA チューニングを開始しました (内蔵ワーカー)", flush=True)
    _spsa_args = line.split()[1:]
    def _run():
        for _sh_attr in ("nnue_1", "nnue_2"):
            _sh_eng = getattr(ctx, _sh_attr, None)
            if _sh_eng is None or not getattr(_sh_eng, "_alive", False):
                continue
            try:
                _sh_eng.send("stop")
                _sh_eng.setoption("USI_Hash", "1")
                _sh_eng.send("isready")
                _sh_eng.flush_until_ready(timeout=30.0)
                _flog("[FIX-SPSA-PARENT-HASH] %s Hash→1MB (WSL RAM released)"
                      % _sh_attr)
            except Exception as _sh_e:
                _flog("[FIX-SPSA-PARENT-HASH] %s shrink failed: %s"
                      % (_sh_attr, _sh_e))
        for _dq_attr in ("dl_1", "dl_2", "dl_3"):
            _dq_eng = getattr(ctx, _dq_attr, None)
            if _dq_eng is None or not getattr(_dq_eng, "_alive", False):
                continue
            try:
                _dq_eng.quit()
                _flog("[FIX-SPSA-PARENT-DL-QUIESCE] %s quit "
                      "(DirectML/VRAM+host RAM released; "
                      "auto-revive at next real go)" % _dq_attr)
            except Exception as _dq_e:
                _flog("[FIX-SPSA-PARENT-DL-QUIESCE] %s quit failed: %s"
                      % (_dq_attr, _dq_e))
        if not _spsa_wsl_health_reset():
            _wsl_abort_msg = (
                "[SPSA] 中止: WSL が利用不能 (wedge) — WSL bridge の nnue が"
                "起動できず全ワーカー死亡が確定するため。管理者 PowerShell で "
                "Restart-Service WSLService を実行するか、OS 再起動後に再実行"
                "してください。")
            _flog(_wsl_abort_msg)
            print("info string " + _wsl_abort_msg, flush=True)
            return
        if not _ensure_prereqs("spsa", _spsa_args):
            _flog("[SPSA] 前提工程 (DLP/Setup) 失敗 — SPSA を開始しない")
            return
        _saved = sys.argv[:]
        _state_path = os.path.join(_BASE_DIR, "spsa_state.txt")
        _argv = [sys.argv[0], "--spsa", "--run"]
        if os.path.exists(_state_path):
            _argv += ["--resume", _state_path]
            _flog("[SPSA] auto-resuming from %s" % _state_path)
        sys.argv = _argv
        try:
            _spsa_cli()
        except SystemExit:
            pass
        except Exception as e:
            _flog("[SPSA] tuning error: %s" % e)
        finally:
            sys.argv = _saved
    t = threading.Thread(target=_run, name="spsa-tuner", daemon=True)
    t.start()


def _handle_game(ctx, line):
    if _reject_if_session_active("game"):
        return

    if _game_thread_started:
        _flog("[GAME] 'game' command rejected — CSA thread already running")
        _console("info string [WARN] game command を拒否: CSA スレッドが既に動作中です。")
        return

    _flog("[GAME] 'game' command received — starting CSA connection in background thread")
    _game_args = line.split()[1:]

    def _run():
        global _game_thread_started
        _game_thread_started = True
        try:
            if not _ensure_prereqs("game", _game_args):
                _flog("[GAME] 前提工程 (DLP/Setup) 失敗 — CSA 接続を開始しない")
                return
            _csa_main([], existing_ctx=ctx)
        except SystemExit:
            pass
        except Exception as e:
            _flog("[GAME] CSA thread error: %s" % e)
        finally:
            _game_thread_started = False
            _flog("[GAME] CSA background thread exited")

    t = threading.Thread(target=_run, name="csa-game", daemon=True)
    t.start()


