def _is_bare_sfen(line: str) -> bool:
    first = line.split()[0] if line.split() else ""
    return first.count("/") == 8

PREFIX_DISPATCH = [
    ("setoption",  _handle_setoption),
    ("position",   _handle_position),
    ("go ponder",  _handle_go_ponder),
    ("go",         _handle_go),
    ("ponderhit",  _handle_ponderhit),
    ("gameover",   _handle_gameover),
]

def _dispatch(ctx, line):
    handler = EXACT_DISPATCH.get(line)
    if handler:
        handler(ctx, line)
        return
    for prefix, handler in PREFIX_DISPATCH:
        if line.startswith(prefix):
            handler(ctx, line)
            return
    handler = TOKEN_DISPATCH.get(line.split()[0])
    if handler:
        handler(ctx, line)
        return
    if _is_bare_sfen(line):
        _handle_bare_sfen(ctx, line)
        return
    _flog(f"unknown command: {line!r}")



def _stats_avg(xs):
    return (sum(xs) / len(xs)) if xs else 0.0


def _stats_rate(recs, n_games):
    ovs = [1 for m in recs if m.get("council_override")]
    phs = [1 for m in recs if m.get("prefetch_hit")]
    pns = [1 for m in recs if m.get("dl_cache_src") == "ponder"]
    dlu = [1 for m in recs if m.get("dl_used")]
    return {
        "n": len(recs),
        "games": n_games,
        "override_rate": (len(ovs) / len(recs)) if recs else 0.0,
        "prefetch_rate": (len(phs) / len(dlu)) if dlu else 0.0,
        "ponder_rate":   (len(pns) / len(dlu)) if dlu else 0.0,
        "avg_eff_s":   _stats_avg([float(m.get("eff_s",    0.0) or 0.0) for m in recs]),
        "avg_nnue_cp": _stats_avg([float(m.get("nnue_score_cp", 0.0) or 0.0) for m in recs]),
    }


def _tuner_percentile(sorted_vals, p):
    if not sorted_vals:
        return None
    idx = _clamp(int(len(sorted_vals) * p / 100), 0, len(sorted_vals) - 1)
    return sorted_vals[idx]


def _tuner_rate(num, den):
    return round(num / den, 3) if den else None


def _tuner_fmt_rate(r):
    return "N/A" if r is None else f"{r:.1%}"


def _tuner_load_games(path):
    games = []
    try:
        with open(path, encoding="utf-8") as f:
            for raw in f:
                raw = raw.strip()
                if not raw:
                    continue
                try:
                    game = json.loads(raw)
                except json.JSONDecodeError:
                    continue
                if not (isinstance(game, dict) and "moves" in game):
                    continue
                if (game.get("infra_void")
                        or game.get("reason") in _SPSA_INFRA_VOID_REASONS):
                    continue
                games.append(game)
    except FileNotFoundError:
        pass
    return games


def _tuner_load_records(path):
    records = []
    n_games = 0
    version_counter = {}

    try:
        with open(path, encoding="utf-8") as f:
            for raw in f:
                raw = raw.strip()
                if not raw:
                    continue
                try:
                    game = json.loads(raw)
                except json.JSONDecodeError:
                    continue
                if not (isinstance(game, dict) and "moves" in game):
                    continue
                if (game.get("infra_void")
                        or game.get("reason") in _SPSA_INFRA_VOID_REASONS):
                    continue
                n_games += 1
                ver = game.get("formula", {}).get("version", "unknown")
                version_counter[ver] = version_counter.get(ver, 0) + 1
                for move in game.get("moves", []):
                    move["_game_result"] = game.get("result", "unknown")
                    move["_formula_version"] = ver
                    if ver and ver < "v6.7":
                        move.pop("regime", None)
                        move.pop("dl_gap_min_game_phase_coef", None)
                        move.pop("dl_stab_game_phase_tighten", None)
                        move["regime_conviction"] = None
                        move["regime_label"] = None
                        move["regime_collapse"] = None
                        move["regime_force_crisis"] = None
                    records.append(move)
    except FileNotFoundError:
        print(f"[ERROR] ファイルが見つかりません: {path}", file=sys.stderr)
        sys.exit(1)

    return records, n_games, version_counter


def _tuner_report(records, n_games, version_counter):

    lines = []
    lines.append("=" * 64)
    lines.append("engine.py  --report  (tuner summary)")
    lines.append("=" * 64)
    lines.append(f"  対局数         : {n_games}")
    lines.append(f"  formula版別    : {dict(sorted(version_counter.items()))}")
    lines.append(f"  total moves    : {len(records)}")

    _time_aggression_vals = set()
    for game_ver, cnt in version_counter.items():
        if game_ver >= "v2.44":
            _time_aggression_vals.add(game_ver)
    if _time_aggression_vals:
        lines.append("  ※ v2.44+ レコード含む — formula.time_aggression が stats に記録されています")
        lines.append(f"    現在の実効値: DL_Time_Ratio={_time_dyn.dl_time_ratio:.3f}  DL_Time_Max={_time_dyn.dl_time_max_ms:.0f}ms  SlowMover={_nnue_1_opts.get('SlowMover','?')}  aggr={_time_dyn.time_aggression}")
    else:
        lines.append(f"  現在の実効値 (v2.44): DL_Time_Ratio={_time_dyn.dl_time_ratio:.3f}  DL_Time_Max={_time_dyn.dl_time_max_ms:.0f}ms  SlowMover={_nnue_1_opts.get('SlowMover','?')}  aggr={_time_dyn.time_aggression}")

    dl_moves = [m for m in records if m.get("dl_used")]
    cache_hit = [m for m in dl_moves if m.get("prefetch_hit")]
    overrides = [m for m in records if m.get("council_override")]
    agree     = [m for m in dl_moves if m.get("dl_nnue_agree")]

    _proxy_ran   = [m for m in records if m.get("dl3_proxy_nnue_weight") is not None]
    _proxy_tried = [m for m in records if m.get("dl3_proxy_reason") is not None]
    _proxy_busy  = [m for m in _proxy_tried if m.get("dl3_proxy_reason") == "dl3_busy"]

    lines.append("")
    lines.append("── 基本統計 ──")
    lines.append(f"  dl_used        : {len(dl_moves)}手  ({_tuner_fmt_rate(_tuner_rate(len(dl_moves), len(records)))})")
    lines.append(f"  prefetch_hit   : {len(cache_hit)}手  ({_tuner_fmt_rate(_tuner_rate(len(cache_hit), len(dl_moves)))})")
    _hit_pon = [m for m in cache_hit if m.get("dl_cache_src") == "ponder"]
    _hit_pre = [m for m in cache_hit if m.get("dl_cache_src") in ("prefetch", "j")]
    _hit_unk = len(cache_hit) - len(_hit_pon) - len(_hit_pre)
    _src_line = (f"    └ 内訳: ponder={len(_hit_pon)}  prefetch={len(_hit_pre)}")
    if _hit_unk:
        _src_line += f"  旧record(出所不明)={_hit_unk}"
    lines.append(_src_line)
    lines.append(f"  council_override: {len(overrides)}手 ({_tuner_fmt_rate(_tuner_rate(len(overrides), len(records)))})")
    lines.append(f"  dl_nnue_agree  : {len(agree)}手  ({_tuner_fmt_rate(_tuner_rate(len(agree), len(dl_moves)))})")

    if _proxy_tried:
        lines.append("")
        lines.append("── DL3 NNUE代弁 (proxy) ──")
        lines.append(f"  proxy 発動     : {len(_proxy_ran)}手 / 試行 {len(_proxy_tried)}手")
        if _proxy_busy:
            lines.append(f"  dl3_busy スキップ: {len(_proxy_busy)}手 "
                         f"({_tuner_fmt_rate(_tuner_rate(len(_proxy_busy), len(_proxy_tried)))} of 試行)")
            if _tuner_rate(len(_proxy_busy), len(_proxy_tried)) >= 0.10:
                lines.append("  ⚠  dl3_busy >= 10%。prefetch DL_3 と競合過多の可能性 (lock 直列化待ち)。")

    lock_waits = [m.get("dl_lock_wait_ms") for m in dl_moves
                  if m.get("dl_lock_wait_ms") is not None and not m.get("prefetch_hit")]
    if lock_waits:
        sv = sorted(lock_waits)
        lines.append("")
        lines.append("── dl_lock_wait_ms 分布 (cache miss 時) ──")
        lines.append(f"  n={len(sv)}  min={sv[0]}  max={sv[-1]}")
        lines.append(
            f"  p50={_tuner_percentile(sv,50)}  p90={_tuner_percentile(sv,90)}"
            f"  p99={_tuner_percentile(sv,99)}"
        )
        high = sum(1 for v in sv if v > 2000)
        lines.append(f"  > 2000ms: {high}手 ({_tuner_fmt_rate(_tuner_rate(high, len(sv)))})")
        if high / len(sv) > 0.1:
            lines.append("  ⚠  lock_wait > 2s が 10%超。DL_Prefetch_Nodes の削減を検討。")

    dl_2_invoked = [m for m in records if m.get("dl_2_invoked")]
    lines.append("")
    lines.append("── DL_2 統計 ──")
    lines.append(f"  dl_2_invoked    : {len(dl_2_invoked)}手 ({_tuner_fmt_rate(_tuner_rate(len(dl_2_invoked), len(records)))})")
    dl_2_agree = [m for m in dl_2_invoked if m.get("dl_2_top_move") and m.get("dl_2_top_move") == m.get("nnue_bestmove")]
    lines.append(f"  dl_2==nnue      : {len(dl_2_agree)}手 ({_tuner_fmt_rate(_tuner_rate(len(dl_2_agree), len(dl_2_invoked)))})")

    dl2_voted = [m for m in records if m.get("dl_2_top_move") is not None]
    if dl2_voted:
        lines.append("")
        lines.append("── フェーズ別 DL_2 vs nnue 一致率 (dl_2_top_move あり手) ──")
        for lo, hi, label in [(0, 39, "序盤 ply 0-39"),
                               (40, 79, "中盤 ply 40-79"),
                               (80, 9999, "終盤 ply 80+")]:
            sub = [m for m in dl2_voted if lo <= (m.get("ply") or 0) <= hi]
            ag  = sum(1 for m in sub
                      if m.get("dl_2_top_move") == m.get("nnue_bestmove"))
            lines.append(
                f"  {label}: n={len(sub)}  dl2==nnue={ag}  "
                f"({_tuner_fmt_rate(_tuner_rate(ag, len(sub)))})"
            )

    try:
        _ry3_games = _tuner_load_games(_STATS_PATH)
        if _ry3_games:
            lines.append("")
            lines.append("── 一致率・DL_2 発動率 推移 (直近12局; DL_1==NNUE / dl_2_invoked) ──")
            for _gi, _game in list(enumerate(_ry3_games, 1))[-12:]:
                _mvs = [m for m in _game.get("moves", [])
                        if m.get("dl_top_move") is not None
                        and m.get("nnue_bestmove") is not None]
                _agree = sum(1 for m in _mvs
                             if m.get("dl_top_move") == m.get("nnue_bestmove"))
                _all_mvs = _game.get("moves", [])
                _inv = sum(1 for m in _all_mvs if m.get("dl_2_invoked"))
                _oid = [m.get("opponent_id_sample") for m in _all_mvs]
                _oid_nn = sum(1 for s in _oid if s == "nnue")
                _oid_dl = sum(1 for s in _oid if s == "dl")
                _oid_ms = sum(1 for s in _oid if s == "miss")
                _oid_n  = _oid_nn + _oid_dl + _oid_ms
                _oid_style = _opponent_style_classify_core(
                    _oid_nn, _oid_dl, _oid_n, _opponent_id_min_n, _opponent_id_margin)
                lines.append(
                    f"  game {_gi:>3}: agree {_agree}/{len(_mvs)} "
                    f"({_tuner_fmt_rate(_tuner_rate(_agree, len(_mvs)))})  "
                    f"dl_2_invoked {_inv}/{len(_all_mvs)} "
                    f"({_tuner_fmt_rate(_tuner_rate(_inv, len(_all_mvs)))})  "
                    f"opponent_id n={_oid_n} (nnue {_oid_nn}/dl {_oid_dl}/miss {_oid_ms}) "
                    f"→ {_oid_style or '保留'}"
                )
    except Exception as _ry3e:
        lines.append(f"  [RY3] 推移集計エラー (無視): {_ry3e}")

    try:
        _stale_hits   = []
        _stale_games  = _tuner_load_games(_STATS_PATH)
        for _gi, _game in enumerate(_stale_games, 1):
            _prev_winners = []
            for _mv in _game.get("moves", []):
                _cw  = _mv.get("council_winner")
                _top = _mv.get("dl_top_move")
                _hit = _mv.get("prefetch_hit")
                if _hit and _top and _top in _prev_winners[-3:]:
                    _stale_hits.append((_gi, _mv.get("ply"), _top, _cw))
                if _cw:
                    _prev_winners.append(_cw)

        lines.append("")
        lines.append("── stale DL top 検出 (v2.51 回帰テスト) ──")
        lines.append("  [定義] prefetch_hit=True かつ dl_top_move == 直近 3 手の council_winner に一致")
        lines.append(f"  検出数: {len(_stale_hits)} 件 / {n_games} 局")
        if _stale_hits:
            lines.append("  ⚠  stale パターンを検出 — v2.51 修正が効いていない可能性があります。")
            lines.append("  ── 詳細 (最大 10 件) ──")
            for _gi, _ply, _top, _cw in _stale_hits[:10]:
                lines.append(f"    Game {_gi:3d}  ply={_ply}  dl_top={_top}  council_winner={_cw}")
            if len(_stale_hits) > 10:
                lines.append(f"    ... 他 {len(_stale_hits) - 10} 件 (省略)")
        else:
            lines.append("  ✓  stale パターンなし。")
    except Exception as _e:
        lines.append("")
        lines.append(f"  [stale 検出スキップ: {_e}]")

    try:
        _dw_games = _tuner_load_games(_STATS_PATH)
        if _dw_games and len(_dw_games) >= 4:
            lines.append("")
            lines.append("── 倍々窓テーブル (最終局から遡り) ──")
            lines.append(f"  {'窓':>6s}  {'W':>4s}  {'D':>4s}  {'L':>4s}  {'勝率':>8s}  {'Elo差':>8s}")
            lines.append("  " + "-" * 44)
            _dw_window = 10
            while _dw_window <= len(_dw_games):
                _dw_tail = _dw_games[-_dw_window:]
                _dw_w = _dw_d = _dw_l = 0
                for _dg in _dw_tail:
                    _res = _dg.get("result") or _dg.get("meta", {}).get("result", "")
                    if _res in ("win", "sente_win", "gote_win", "+"):
                        _dw_w += 1
                    elif _res in ("lose", "sente_lose", "gote_lose", "-"):
                        _dw_l += 1
                    else:
                        _dw_d += 1
                _dw_n = _dw_w + _dw_d + _dw_l
                _dw_score = (_dw_w + _dw_d * 0.5) / _dw_n if _dw_n > 0 else 0.5
                _dw_elo = _sprt_elo_from_score(_dw_score) if 0 < _dw_score < 1 else 0.0
                lines.append(
                    f"  {_dw_window:>6d}  {_dw_w:>4d}  {_dw_d:>4d}  {_dw_l:>4d}  "
                    f"{_dw_score:>7.1%}  {_dw_elo:>+7.1f}")
                _dw_window *= 2
    except Exception as _dwe:
        lines.append(f"  [倍々窓スキップ: {_dwe}]")

    lines.append("")
    lines.append("=" * 64)
    _report_text = "\n".join(lines)
    print(_report_text)
    return _report_text
def _ab_compare_stats(path_a: str, path_b: str) -> str:
    rec_a, games_a, _ = _tuner_load_records(path_a)
    rec_b, games_b, _ = _tuner_load_records(path_b)
    a = _stats_rate(rec_a, games_a)
    b = _stats_rate(rec_b, games_b)
    lines = []
    lines.append("=" * 64)
    lines.append("A/B stats comparison")
    lines.append("=" * 64)
    lines.append(f"A: {path_a}")
    lines.append(f"B: {path_b}")
    lines.append("")
    for k in ["n", "override_rate", "prefetch_rate", "ponder_rate", "avg_eff_s", "avg_nnue_cp"]:
        va, vb = a[k], b[k]
        if isinstance(va, float):
            lines.append(f"{k:<16s} A={va:.4f}  B={vb:.4f}  Δ(B-A)={vb-va:+.4f}")
        else:
            lines.append(f"{k:<16s} A={va}  B={vb}  Δ(B-A)={vb-va:+d}")
    lines.append("=" * 64)
    return "\n".join(lines)




def _spsa_param_is_int(p: dict) -> bool:
    if "is_int" in p:
        return bool(p["is_int"])
    for _k in ("min_val", "max_val", "step", "c"):
        _v = p.get(_k)
        if isinstance(_v, float) and not float(_v).is_integer():
            return False
    return True


@dataclasses.dataclass
class SpsaParam:
    name:    str
    value:   float
    min_val: float
    max_val: float
    step:    float
    is_int:  bool = True

    def clamp(self, v: float) -> float:
        return _clamp(v, self.min_val, self.max_val)

    def config_value(self) -> "int | float":
        return int(round(self.value)) if self.is_int else round(self.value, 4)


@dataclasses.dataclass
class SpsaState:
    params:       list
    k:            int   = 0
    a0:           float = 2.0
    c0:           float = 1.0
    A:            int   = 0
    alpha:        float = 0.602
    gamma:        float = 0.101
    total_iters:  int   = 1000
    _deltas: list = dataclasses.field(default_factory=list, repr=False, compare=False)
    polyak_sum:   list = dataclasses.field(default_factory=list)
    polyak_count: int  = 0

    def ck(self) -> float:
        return self.c0 / (1.0 + self.k) ** self.gamma

    def ak(self) -> float:
        return self.a0 / (self.A + 1.0 + self.k) ** self.alpha

    def rk(self) -> float:
        ck = self.ck()
        return self.ak() / (ck ** 2) if ck != 0.0 else 0.0

    @staticmethod
    def from_dict(d: dict) -> "SpsaState":
        params = [SpsaParam(
            name=p["name"], value=p["value"],
            min_val=p["min_val"], max_val=p["max_val"],
            step=p["step"],
            is_int=_spsa_param_is_int(p),
        ) for p in d.pop("params")]
        d.pop("_deltas", None)
        state  = SpsaState(params=params, **d)
        return state




def _spsa_filter_profile_core(params, profile: str):
    if profile == "hw":
        kept = [p for p in params if _spsa_hw_key_core(p.name)]
        dropped = [p.name for p in params if not _spsa_hw_key_core(p.name)]
        return kept, dropped
    if profile == "game":
        kept = [p for p in params if not _spsa_hw_key_core(p.name)]
        dropped = [p.name for p in params if _spsa_hw_key_core(p.name)]
        return kept, dropped
    return list(params), []


def _spsa_default_params() -> list:
    _scfg = EngineConfig.from_cfg(_cfg)
    params = []

    def _p(name, val, lo, hi, c=None, is_int=True):
        if c is None:
            c = max(0.01, (hi - lo) * 0.05)
        params.append(SpsaParam(
            name=name, value=float(val),
            min_val=float(lo), max_val=float(hi),
            step=c, is_int=is_int,
        ))

    _p("GP_Handover_Threshold", _scfg.game_phase_handover_threshold, 0.45, 0.95, c=0.04, is_int=False)
    _p("GP_Handover_Per_Sec", _scfg.game_phase_handover_per_sec, -0.01, 0.01, c=0.002, is_int=False)
    _inc_spend_ratio_clamped = min(0.90, _inc_spend_ratio)
    _p("Inc_Spend_Ratio", _inc_spend_ratio_clamped, 0.7, 0.90, c=0.03, is_int=False)
    _p("Fischer_Horizon_Moves", _fischer_horizon_moves, 20, 36, c=1.0, is_int=True)
    _p("Handover_Reverse_Hysteresis", _scfg.handover_reverse_hysteresis, 0.0, 0.15, c=0.01, is_int=False)
    _p("Endgame_DL_Veto_WR_Margin", _scfg.endgame_dl_veto_wr_margin, 0.05, 0.35, c=0.02, is_int=False)
    _p("Endgame_DL_Veto_GP_Lo_Scale", _scfg.endgame_dl_veto_game_phase_lo_scale, 0.3, 1.5, c=0.05, is_int=False)
    _p("Endgame_DL_Veto_GP_Hi_Scale", _scfg.endgame_dl_veto_game_phase_hi_scale, 0.1, 1.0, c=0.05, is_int=False)
    _p("Handover_Reverse_Hysteresis_Shrink", _scfg.handover_reverse_hysteresis_shrink, 0.1, 1.0, c=0.05, is_int=False)

    _p("DL_Score_Gap_Min_Base",    _dl_gap_min_base,    10,  40)
    _p("DL_Score_Gap_Min_Per_Sec", _dl_gap_min_per_sec, 0.2, 1.0, is_int=False)
    _p("DL_Score_Gap_Min_Min",     _dl_gap_min_min,     10,  40)
    _p("DL_Score_Gap_Min_Max",     _dl_gap_min_max,     25,  60)
    _p("DL_Score_Gap_Min_GP_Coef", _dl_gap_min_game_phase_coef, -30.0, 30.0, c=2.0, is_int=False)

    _p("DL_Stability_Threshold_Base",    _dl_stab_base,    90,  220)
    _p("DL_Stability_Threshold_Per_Sec", _dl_stab_per_sec, 1.5, 5.0, is_int=False)
    _p("DL_Stability_Threshold_Min",     _dl_stab_min,     50,  130)
    _p("DL_Stability_Threshold_Max",     _dl_stab_max,     160, 360)

    _p("SlowMover_Base",    _scfg.slow_mover_base,    60,  120)
    _p("SlowMover_Per_Sec", _scfg.slow_mover_per_sec, 4.0, 10.0, is_int=False)
    _p("SlowMover_Min",     _scfg.slow_mover_min,     70,  140)
    _p("SlowMover_Max",     _scfg.slow_mover_max,     140, 270)

    _dl_time_ratio_clamped = _clamp(_time_dyn.dl_time_ratio, 0.15, 0.38)
    _p("DL_Time_Ratio",  _dl_time_ratio_clamped,  0.15, 0.38, c=0.02, is_int=False)
    _p("DL_Time_Min_ms", _dl_time_min_ms, 900,  2500)
    _p("DL_Time_Max_ms", _time_dyn.dl_time_max_ms, 22000, 50000)

    _p("DL_2_Time_Margin_Ratio",  _scfg.dl_2_margin_ratio,  0.3, 0.9, c=0.05, is_int=False)
    _p("DL_2_Time_Margin_Min_ms", _time_dyn.dl_2_margin_min_ms, 2500, 7000)
    _p("DL_2_Time_Margin_Max_ms", _scfg.dl_2_margin_max_ms, 18000, 42000)
    _p("DL_2_Cold_Launch_Latency_Factor", _scfg.dl_2_cold_launch_latency_factor, 1.0, 6.0, c=0.3, is_int=False)
    _p("DL_2_Wall_Clock_Factor",          _scfg.dl_2_wall_clock_factor,          0.5, 2.5, c=0.15, is_int=False)

    _p("DL1_Council_Depth_Trust_Base",      _scfg.dl1_depth_trust_base,      0.25, 0.60, c=0.05, is_int=False)
    _p("DL1_Council_Depth_Trust_Per_Depth", _scfg.dl1_depth_trust_per_depth, 0.02, 0.08, c=0.01, is_int=False)
