def spsa_step(state: SpsaState, score: float) -> None:
    if score == 0.0:
        return

    ck = state.ck()
    rk = state.rk()

    for i, p in enumerate(state.params):
        delta_i = state._deltas[i]
        update  = score * ck * rk * p.step * delta_i
        p.value = p.clamp(p.value + update)

    _polyak_start_k = max(state.A, int(state.total_iters * 0.75))
    if state.total_iters > 0 and state.k >= _polyak_start_k:
        if not state.polyak_sum or len(state.polyak_sum) != len(state.params):
            state.polyak_sum = [0.0] * len(state.params)
            state.polyak_count = 0
        for i, p in enumerate(state.params):
            state.polyak_sum[i] += float(p.value)
        state.polyak_count += 1



def spsa_perturbation(state: SpsaState) -> "tuple[dict, dict]":
    ck = state.ck()
    deltas = [random.choice([-1.0, 1.0]) for _ in state.params]
    state._deltas = deltas

    cfg_plus  = {}
    cfg_minus = {}
    for p, d in zip(state.params, deltas):
        plus_val  = p.clamp(p.value + ck * p.step * d)
        minus_val = p.clamp(p.value - ck * p.step * d)
        if p.is_int:
            plus_val  = int(round(plus_val))
            minus_val = int(round(minus_val))
        else:
            plus_val  = round(plus_val,  4)
            minus_val = round(minus_val, 4)
        cfg_plus[p.name]  = plus_val
        cfg_minus[p.name] = minus_val

    return cfg_plus, cfg_minus


def spsa_save_config(state: SpsaState, cfg_path: str = None) -> None:
    if cfg_path is None:
        cfg_path = _SPSA_CONFIG_PATH

    existing = {}
    if os.path.exists(cfg_path):
        try:
            with open(cfg_path, encoding="utf-8") as f:
                existing = json.load(f)
        except Exception as _fe:
            _flog(f"[ignored] {__file__}:10564: {_fe}")

    _polyak_active = (state.polyak_count > 0
                       and state.polyak_sum
                       and len(state.polyak_sum) == len(state.params))
    for i, p in enumerate(state.params):
        if _polyak_active:
            _avg = state.polyak_sum[i] / state.polyak_count
            _avg = p.clamp(_avg)
            _v = int(round(_avg)) if p.is_int else round(_avg, 4)
        else:
            _v = p.config_value()
        existing[p.name] = _v

    for _as_try in range(2):
        try:
            _tmp_cfg = cfg_path + ".tmp"
            with open(_tmp_cfg, "w", encoding="utf-8") as f:
                json.dump(existing, f, indent=2, ensure_ascii=False)
                f.flush()
                try:
                    os.fsync(f.fileno())
                except Exception:
                    pass
            os.replace(_tmp_cfg, cfg_path)
            _flog(f"SPSA config saved to {cfg_path}: {list(existing.keys())}")
            break
        except Exception as _as_e:
            if _as_try == 0:
                time.sleep(0.2)
                continue
            _flog(f"[ATOMIC-SAVE] spsa config save failed twice ({_as_e!r}) — "
                  "skipped (run continues; next checkpoint retries)")

def _merge_cfg_for_temp(overrides: dict) -> dict:
    merged = dict(_cfg)
    merged.update(overrides or {})
    return merged



def _posix_scan_marked(needle_pid=None):
    out = []
    if sys.platform == "win32":
        return out
    _self = os.getpid()
    try:
        for _pd in os.listdir("/proc"):
            if not _pd.isdigit() or int(_pd) == _self:
                continue
            try:
                with open(f"/proc/{_pd}/environ", "rb") as _ef:
                    _blob = _ef.read(131072)
            except Exception:
                continue
            for _ent in _blob.split(b"\x00"):
                if _ent.startswith(b"PYFAMATE_CHILD_MARK="):
                    _mv = _ent.split(b"=", 1)[1].decode("ascii", "replace")
                    if needle_pid is None or _mv == str(needle_pid):
                        out.append((int(_pd), _mv))
                    break
    except Exception as _se:
        _flog(f"[POSIX-ORPHAN] /proc scan failed (ignored): {_se!r}")
    return out


def _posix_kill_marked_children(parent_pid, reason=""):
    killed = 0
    for _pid, _ in _posix_scan_marked(needle_pid=parent_pid):
        killed += _posix_kill_pid_safe(_pid)
    if killed:
        _flog(f"[POSIX-ORPHAN] killed {killed} marked child proc(s) "
              f"of pid={parent_pid} {reason}")
    return killed


def _posix_kill_pid_safe(pid) -> int:
    try:
        _target_pg = os.getpgid(pid)
    except Exception:
        _target_pg = None
    try:
        _own_pg = os.getpgid(0)
    except Exception:
        _own_pg = None
    try:
        if _target_pg is not None and _target_pg != _own_pg:
            os.killpg(_target_pg, signal.SIGKILL)
        else:
            os.kill(pid, signal.SIGKILL)
        return 1
    except Exception:
        try:
            os.kill(pid, signal.SIGKILL)
            return 1
        except Exception:
            return 0


def _posix_orphan_sweep_startup():
    killed = 0
    for _pid, _mv in _posix_scan_marked():
        try:
            if _mv.isdigit() and os.path.exists(f"/proc/{_mv}"):
                continue
        except Exception:
            continue
        killed += _posix_kill_pid_safe(_pid)
    if killed:
        _flog(f"[POSIX-ORPHAN] startup sweep: killed {killed} orphan proc(s) "
              "from dead previous-generation parents")
    return killed


def _spsa_kill_proc_tree(p, sig=None, ctrl_break: bool = False) -> None:
    if sys.platform == "win32":
        if ctrl_break:
            try:
                p.send_signal(signal.CTRL_BREAK_EVENT)
            except Exception as _fe:
                _flog(f"[ignored] _spsa_kill_proc_tree ctrl_break: {_fe!r}")
        try:
            subprocess.call(
                ["taskkill", "/F", "/T", "/PID", str(p.pid)],
                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
            )
        except Exception as _fe:
            _flog(f"[ignored] _spsa_kill_proc_tree taskkill: {_fe!r}")
    else:
        if sig is None:
            sig = signal.SIGKILL
        try:
            os.killpg(os.getpgid(p.pid), sig)
        except ProcessLookupError:
            pass
        except Exception as _fe:
            _flog(f"[ignored] _spsa_kill_proc_tree killpg: {_fe!r}")
        try:
            _posix_kill_marked_children(p.pid, reason="(kill-tree)")
        except Exception as _fe:
            _flog(f"[ignored] _spsa_kill_proc_tree marked-children: {_fe!r}")
    try:
        p.kill()
    except Exception as _fe:
        _flog(f"[ignored] _spsa_kill_proc_tree kill: {_fe!r}")
    try:
        p.wait(timeout=3)
    except Exception:
        pass


def _terminate_proc_full(proc, *, job=None, via_shell=False,
                         bat_path=None, wsl_tag=None, name="?") -> None:
    try:
        if job is not None:
            _job_terminate(job, 1)
            _job_close(job)
        elif via_shell and sys.platform == "win32":
            try:
                subprocess.run(
                    ["taskkill", "/F", "/T", "/PID", str(proc.pid)],
                    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                    creationflags=0x08000000,
                    timeout=5,
                )
            except Exception as _te:
                _flog(f"[{name}] taskkill failed ({_te}) — falling back to proc.kill()")
                try:
                    proc.kill()
                except Exception:
                    pass
        elif via_shell:
            try:
                os.killpg(os.getpgid(proc.pid), signal.SIGKILL)
            except ProcessLookupError:
                pass
            except Exception as _ke:
                _flog(f"[{name}] killpg failed ({_ke}) — falling back to proc.kill()")
                try:
                    proc.kill()
                except Exception:
                    pass
        else:
            _spsa_kill_proc_tree(proc)
        if bat_path:
            _wsl_kill_by_batpath(bat_path, wsl_tag)
        try:
            proc.wait(timeout=3)
        except Exception:
            pass
    except Exception as _e:
        _flog(f"[{name}] _terminate_proc_full error: {_e}")


def _quit_engines(*engines, timeout: float = 20.0, label: str = "quit") -> None:
    threads = []
    for eng in engines:
        t = threading.Thread(target=eng.quit, daemon=True,
                             name=f"{label}-{getattr(eng, 'name', '?')}")
        t.start()
        threads.append((t, eng))
    for t, eng in threads:
        t.join(timeout=timeout)
    for t, eng in threads:
        if t.is_alive():
            _flog(f"[{label}] quit thread still alive after {timeout}s — "
                  f"force-killing {getattr(eng, 'name', '?')}")
            try:
                _spsa_kill_proc_tree(getattr(eng, "proc", None))
            except Exception:
                pass
        try:
            eng._wsl_reap()
        except Exception:
            pass
        _ep = getattr(eng, "proc", None)
        if _ep is not None:
            try:
                _ep.wait(timeout=3)
            except Exception:
                pass


def _spsa_pgrp_kwargs() -> dict:
    return (
        {"creationflags": subprocess.CREATE_NEW_PROCESS_GROUP}
        if sys.platform == "win32"
        else {"start_new_session": True}
    )


def _spsa_engine_path() -> str:
    if _IS_FROZEN:
        return sys.executable
    return os.path.abspath(__file__)


def _spsa_engine_argv(mode: str) -> list:
    ep = _spsa_engine_path()
    if _IS_FROZEN:
        return [ep, mode]
    return [sys.executable, ep, mode]




def _build_child_env(role, *, tmpdir=None, stats_path=None, reap_key=None):
    env = os.environ.copy()
    for _k in list(env):
        if _k.startswith("PYFAMATE_TEST_CHILD_ARGV") or _k == "PYFAMATE_DLP_CAL":
            env.pop(_k, None)
    if tmpdir is not None:
        env["PYFAMATE_BASE_DIR"] = tmpdir
    if stats_path is not None:
        env["SPSA_STATS_PATH"] = stats_path
    if reap_key is not None:
        env["PYFAMATE_WSL_REAP_KEY"] = reap_key
    if role in ("spsa_worker", "grid_worker"):
        env["PYFAMATE_GEN_ACK"] = "1"
        env["PYFAMATE_REC_EMIT"] = "1"
    env.setdefault("PYTHONUTF8", "1")
    return env


class _SpsaUsiEngine:

    _REAP_SEQ = itertools.count(1)
    _DIAG_SEQ = itertools.count(1)

    _HALVE_KEYS = [
        "nnue_1_Hash", "nnue_2_Hash",
        "DL_1_Hash",   "DL_2_Hash",   "DL_3_Hash",
    ]
    _SELFPLAY_DL = {
        "DL_1_UCT_Threads1": "1",
        "DL_2_UCT_Threads1": "1",
        "DL_3_UCT_Threads1": "1",
    }
    _HALVE_PCT_KEYS = [
        "Resource_RAM_Budget_Pct",
    ]

    @staticmethod
    def _halve_cfg_dict(cfg: dict, halve: bool = True) -> dict:
        _budget_on = str(cfg.get("Resource_Budget_Enable",
                                 _CONFIG_DEFAULTS.get("Resource_Budget_Enable", True))
                         ).strip().lower() in ("true", "1")
        _total_cores = _safe_cpu_count()
        _wc = _cint(cfg, "Tuning_Worker_Count", 2, lo=1)
        _fixed_per_child = sum(int(v) for v in
                               _SpsaUsiEngine._SELFPLAY_DL.values()) + 1
        _remaining = _total_cores - _wc * _fixed_per_child
        _nnue_per = max(1, (_remaining - 1) // _wc)
        out = {}
        for key, val in cfg.items():
            if not halve:
                pass
            elif key in _SpsaUsiEngine._HALVE_KEYS:
                if _budget_on:
                    val = _CONFIG_DEFAULTS.get(key, val)
                else:
                    try:
                        val = max(1, int(val) // 2)
                    except (ValueError, TypeError):
                        pass
            elif key in _SpsaUsiEngine._HALVE_PCT_KEYS:
                try:
                    val = max(0.05, float(val) / 2.0)
                except (ValueError, TypeError):
                    pass
            elif key in _SpsaUsiEngine._SELFPLAY_DL:
                val = _SpsaUsiEngine._SELFPLAY_DL[key]
            elif key in ("nnue_1_Threads", "nnue_2_Threads"):
                val = str(_nnue_per)
            elif key == "Resource_Threads_Spare_Min":
                val = "1"
            out[key] = val
        for _dv in ("nnue_1_DrawValueBlack", "nnue_1_DrawValueWhite",
                    "nnue_2_DrawValueBlack", "nnue_2_DrawValueWhite"):
            if _dv in out:
                out[_dv] = "-2"
        out["nnue_1_ResignValue"] = 99999
        out["nnue_2_ResignValue"] = 99999
        return out

    @staticmethod
    def _halve_config(src_path: str, dst_path: str, halve: bool = True) -> None:
        try:
            with open(src_path, encoding="utf-8") as f:
                cfg = json.load(f)
        except Exception:
            import shutil as _sh_fallback
            _sh_fallback.copy2(src_path, dst_path)
            return
        out = _SpsaUsiEngine._halve_cfg_dict(cfg, halve=halve)
        with open(dst_path, "w", encoding="utf-8") as f:
            json.dump(out, f, indent=2, ensure_ascii=False)
            f.write("\n")

    def __init__(self, config_path: str, stats_path: str, label: str,
                 halve: bool = True):
        import shutil as _shutil
        import tempfile as _tmpmod
        self.name = label
        self._stats_path = stats_path
        self._tmpdir = _tmpmod.mkdtemp(prefix="pyfamate_%s_" % label)
        _SpsaUsiEngine._halve_config(
            config_path, os.path.join(self._tmpdir, "config.txt"),
            halve=halve,
        )
        _setup_src = _SETUP_CONFIG_PATH
        if os.path.exists(_setup_src):
            _shutil.copy2(_setup_src, os.path.join(self._tmpdir, "setup_config.txt"))
        _rseq = next(_SpsaUsiEngine._REAP_SEQ)
        self._reap_key = "%dz%dz%d" % (os.getpid(), _rseq, time.time_ns())
        env = _build_child_env("spsa_worker", tmpdir=self._tmpdir,
                               stats_path=stats_path, reap_key=self._reap_key)
        _test_argv = _TEST_CHILD_ARGV_STASH.get(f"PYFAMATE_TEST_CHILD_ARGV_{label}") or _TEST_CHILD_ARGV_STASH.get("PYFAMATE_TEST_CHILD_ARGV")
        argv = _test_argv.split("\x1f") if _test_argv else _spsa_engine_argv("--spsa-worker")
        self._start_worker_process(argv, env, label)

    def _start_worker_process(self, argv, env, label, reader_name_prefix="spsa"):
        import queue as _queue
        env.setdefault("PYTHONUTF8", "1")
        self.proc = _popen_utf8(
            argv,
            stdin=subprocess.PIPE,
            stdout=subprocess.PIPE,
            stderr=subprocess.DEVNULL,
            env=env,
            bufsize=1,
            **_spsa_pgrp_kwargs(),
        )
        self._alive = True
        self._go_sent = 0
        self._bm_seen = 0
        self._bm_arrived = 0
        self._last_ack_gen = None
        self._bm_gen = None
        self._last_rec = None
        self._last_drained_bm = None
        self._dup_drained_bm = False
        self._send_lock = threading.Lock()
        self._q = _queue.Queue()
        _self = self
        def _reader_thread(proc=self.proc, q=self._q):
            try:
                for line in proc.stdout:
                    _rl_line = line.rstrip("\n")
                    q.put(_rl_line)
                    if _rl_line.startswith("bestmove") and _self.proc is proc:
                        _self._bm_arrived += 1
            except (KeyboardInterrupt, SystemExit):
                raise
            except Exception as _rde:
                try:
                    _flog(f"[reader-thread] {getattr(_self, 'name', '?')} "
                          f"raised {type(_rde).__name__}: {_rde!r}")
                except Exception:
                    pass
            finally:
                if _self.proc is proc:
                    _self._alive = False
                q.put(None)
        threading.Thread(target=_reader_thread, daemon=True,
                    name="%s_reader_%s" % (reader_name_prefix, label)).start()

    def send(self, cmd: str) -> None:
        if not self._alive or not self.proc or not self.proc.stdin:
            _flog(f"[{getattr(self, 'name', 'spsa-child')}] send skipped "
                  f"(not alive): {cmd.split()[0] if cmd else cmd}")
            return
        with self._send_lock:
            try:
                self.proc.stdin.write(cmd + "\n")
                self.proc.stdin.flush()
                if cmd.startswith("go"):
                    self._go_sent += 1
            except (BrokenPipeError, OSError) as _sp_se:
                self._alive = False
                _flog(f"[{getattr(self, 'name', 'spsa-child')}] send "
                      f"{type(_sp_se).__name__} (process exited): "
                      f"{cmd.split()[0] if cmd else cmd}")

    def setoption(self, key, val):
        self.send(f"setoption name {key} value {val}")

    def readline(self, timeout: float = 60.0):
        import queue as _queue
        try:
            line = self._note_line(self._q.get(timeout=timeout))
            if line is None:
                self._alive = False
                self._q.put(None)
                return None
            return line
        except _queue.Empty:
            return ""

    def wait_for(self, keyword: str, timeout: float = 60.0) -> bool:
        deadline = time.perf_counter() + timeout
        while time.perf_counter() < deadline:
            line = self.readline(timeout=max(0.1, deadline - time.perf_counter()))
            if line is None:
                break
            if not line:
                continue
            if keyword in line:
                return True
        return False

    flush_until_ready = USIEngine.flush_until_ready
    flush_with_stop   = USIEngine.flush_with_stop
    _note_line    = USIEngine._note_line
    bm_is_current     = USIEngine.bm_is_current
    classify_bestmove = USIEngine.classify_bestmove
    search_outstanding = USIEngine.search_outstanding
    _force_accept_resync = USIEngine._force_accept_resync

    def preserve_wedge_diag(self, tag: str = "WEDGE") -> None:
        if os.environ.get("SPSA_PRESERVE_CHILD_DIAG", "0").strip().lower() \
                not in ("1", "true", "yes"):
            return
        _n = getattr(self, "_wedge_snaps", 0)
        if _n >= 5:
            return
        try:
            _src = os.path.join(self._tmpdir, "diagnosis.txt")
            if not os.path.isfile(_src):
                return
            self._wedge_snaps = _n + 1
            _dseq = next(_SpsaUsiEngine._DIAG_SEQ)
            _dst = os.path.join(
                _BASE_DIR, "spsa_child_diag_%s_%s_%04d.txt"
                % (tag, self.name, _dseq))
            with open(_src, "rb") as _f:
                _f.seek(0, os.SEEK_END)
                _sz = _f.tell()
                _f.seek(max(0, _sz - 512 * 1024))
                _data = _f.read()
            with open(_dst, "wb") as _w:
                _w.write(_data)
            _flog("[%s] wedge diag preserved (%d bytes) -> %s"
                  % (self.name, len(_data), os.path.basename(_dst)))
        except Exception as _we:
            _flog("[ignored] wedge diag preserve (%s): %r" % (self.name, _we))

    def restart(self) -> bool:
        _flog("[%s] restarting (halt failure recovery)..." % self.name)
        self.preserve_wedge_diag("WEDGE")
        self._alive = False
        _spsa_kill_proc_tree(self.proc)
        try:
            self.proc.wait(timeout=5)
        except Exception:
            pass
        self._wsl_reap()
        _rseq = next(_SpsaUsiEngine._REAP_SEQ)
        self._reap_key = "%dz%dz%d" % (os.getpid(), _rseq, time.time_ns())
        env = _build_child_env("spsa_worker", tmpdir=self._tmpdir,
                               stats_path=self._stats_path, reap_key=self._reap_key)
        argv = _spsa_engine_argv("--spsa-worker")
        self._start_worker_process(argv, env, self.name)
        self.send("usi")
        if not self.wait_for("usiok", timeout=60.0):
            _flog("[%s] restart: usiok timeout" % self.name)
            return False
        if _spsa_ponder_enabled():
            self.setoption("USI_Ponder", "true")
        if not self.flush_until_ready(timeout=120.0):
            _flog("[%s] restart: readyok timeout" % self.name)
            return False
        _flog("[%s] restart complete" % self.name)
        return True

    def _pre_tmpdir_cleanup(self) -> None:
        if os.environ.get("SPSA_PRESERVE_CHILD_DIAG", "0").strip().lower() \
                in ("1", "true", "yes"):
            try:
                _src = os.path.join(self._tmpdir, "diagnosis.txt")
                if os.path.exists(_src):
                    import shutil as _sh_diag
                    _dseq = next(_SpsaUsiEngine._DIAG_SEQ)
                    _had_resign = False
                    try:
                        with open(_src, encoding="utf-8", errors="replace") as _df:
                            _diag_body = _df.read()
                        _had_resign = any(_mk in _diag_body for _mk in (
                            "PH-FINAL] CRITICAL", "[META-RESIGN]",
                            "resign 不可避"))
                    except Exception:
                        _had_resign = False
                    _tag = "RESIGN_" if _had_resign else ""
                    _dst = os.path.join(
                        _BASE_DIR,
                        "spsa_child_diag_%s%s_%04d.txt"
                        % (_tag, self.name, _dseq))
                    _sh_diag.copy2(_src, _dst)
            except Exception as _de:
                _flog("[ignored] child diag preserve: %r" % _de)
        return None

    def _wsl_reap(self) -> None:
        _rk = getattr(self, "_reap_key", None)
        if not (sys.platform == "win32" and _rk):
            return
        _ds = []
        try:
            _r = subprocess.run(
                ["wsl", "-l", "-q"], timeout=3, capture_output=True,
                creationflags=0x08000000)
            _raw = _decode_wsl_list(_r.stdout or b"")
            _ds = [_d.strip() for _d in _raw.splitlines() if _d.strip()]
        except Exception:
            pass
        _pat = f"PYFMTAG_.*_{_rk}_"
        _targets = [(d, ["wsl", "-d", d, "--", "pkill", "-9", "-f", _pat])
                 for d in _ds] or [(None, ["wsl", "--", "pkill", "-9", "-f", _pat])]
        for _d, _av in _targets:
            try:
                subprocess.run(
                    _av, timeout=5,
                    stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL,
                    creationflags=0x08000000)
            except Exception as _we:
                _flog(f"[WSL-REAP] pkill failed for distro={_d or 'default'} "
                      f"(non-fatal): {_we!r}")

    def quit(self) -> None:
        self._alive = False
        try:
            self.send("quit")
            self.proc.wait(timeout=8)
        except Exception as _fe:
            _dlog(f"[ignored] worker quit: {_fe}")
        _spsa_kill_proc_tree(self.proc)
        try:
            self.proc.wait(timeout=5)
        except Exception:
            pass
        self._wsl_reap()
        try:
            self._pre_tmpdir_cleanup()
        except Exception as _fe:
            _flog(f"[ignored] _pre_tmpdir_cleanup: {_fe!r}")
        try:
            import shutil as _sh
            _sh.rmtree(self._tmpdir, ignore_errors=True)
        except Exception as _fe:
            _flog(f"[ignored] {__file__}:10760: {_fe}")


class _OpponentEngine(_SpsaUsiEngine):
    def __init__(self, exe_path, label, hash_mb=None, threads=None, extra_opts=None):
        import tempfile as _tmpmod
        self.name = label
        self._ponder_capable = False
        self._opponent_exe = exe_path
        if hash_mb is None:
            try:
                hash_mb = _opponent_default_hash_mb()
            except Exception:
                hash_mb = 2048
        if threads is None:
            threads = max(1, _safe_cpu_count() // 2)
        self._opponent_opts = {"USI_Hash": str(int(hash_mb)), "Hash": str(int(hash_mb)),
                          "Threads": str(int(threads)), "USI_Ponder": "false"}
        if extra_opts:
            self._opponent_opts.update(extra_opts)
        self._tmpdir = _tmpmod.mkdtemp(prefix="opp_%s_" % label)
        env = os.environ.copy()
        self._start_worker_process([exe_path], env, label, reader_name_prefix="opponent")

    def quit(self) -> None:
        self._alive = False
        try:
            self.send("quit")
            self.proc.wait(timeout=5)
        except Exception as _fe:
            _flog(f"[ignored] opponent quit: {_fe!r}")
        _spsa_kill_proc_tree(self.proc)
        try:
            self.proc.wait(timeout=5)
        except Exception:
            pass
        try:
            import shutil as _sh
            _sh.rmtree(self._tmpdir, ignore_errors=True)
        except Exception as _fe:
            _flog(f"[ignored] opponent rmtree: {_fe!r}")


def _opponent_default_hash_mb() -> int:
    _total, _avail = _sys_ram_info()
    if _avail and _avail > 0:
        h = max(1024, int(_avail) // 2)
        if _DIRECTML_SHARED_RAM:
            h = h // 2
        return h
    return 8192


def _opponent_init(eng: "_OpponentEngine") -> bool:
    eng.send("usi")
    if not eng.wait_for("usiok", timeout=60):
        _flog("[vs-OPPONENT][%s] usiok timeout" % eng.name)
        _LIVE.reset()
        print("[!] opponent %s: usiok timeout" % eng.name, flush=True)
        return False
    for _k, _v in getattr(eng, "_opponent_opts", {}).items():
        eng.setoption(_k, _v)
    eng.send("isready")
    if not eng.wait_for("readyok", timeout=120):
        _flog("[vs-OPPONENT][%s] readyok timeout" % eng.name)
        _LIVE.reset()
        print("[!] opponent %s: readyok timeout" % eng.name, flush=True)
        return False
    _flog("[vs-OPPONENT][%s] ready: %s" % (eng.name, getattr(eng, "_opponent_opts", {})))
    return True


def _spsa_ponder_enabled() -> bool:
    return os.environ.get("SPSA_PONDER", "1").strip().lower() not in (
        "0", "false", "no", "")


def _ponder_predicted_key(board, ponder_move):
    if board is None:
        return None
    if hasattr(board, "is_legal_lite") and not board.is_legal_lite(ponder_move):
        return None
    try:
        _tmp = board.clone()
        _tmp.apply_usi(ponder_move)
        return _tmp._board_key()
    except Exception as _pe:
        _flog("[PNDR] predicted board-key calc failed for %r (%s)"
              % (ponder_move, _pe))
        return None


def _ponder_is_hit(ponder_board_key, board) -> bool:
    if ponder_board_key is None or board is None:
        return False
    return ponder_board_key == board._board_key()


def _bestmove_is_for_board(usi_move: str, board) -> bool:
    if usi_move in ("resign", "win", "", None):
        return True
    if not board.move_belongs_to_side(usi_move):
        return False
    if not board.is_legal_lite(usi_move):
        return False
    if "*" in usi_move and board.illegal_drop_reason(usi_move) is not None:
        return False
    return True


def _sp_echo_reject(ctx, move: str, tag: str) -> bool:
    if not move:
        return False
    board = _get_tracking_board(ctx)
    if board is not None and not _bestmove_is_for_board(move, board):
        _flog(f"[{tag}/SP-echo] {move!r} is not a move for the current board — rejecting")
        _spd = ctx.game_progress.sp_move_diag
        if _spd is not None:
            _spd["sp_echo_rejected"] = _spd.get("sp_echo_rejected", 0) + 1
        return True
    return False


def _line_freshness(line: str, board, pv_seen: bool) -> tuple:
    if "dl_live_policy" in line:
        return False, pv_seen
    if not line.startswith("info") or board is None:
        return True, pv_seen
    if " pv " in line:
        m = _RE_PV_FULL.search(line)
        if m:
            try:
                fresh = _bestmove_is_for_board(m.group(1).split()[0], board)
            except Exception:
                fresh = True
            return fresh, (pv_seen or fresh)
    return pv_seen, pv_seen


def _spsa_init_engine(eng: "_SpsaUsiEngine") -> bool:
    eng.send("usi")
    if not eng.wait_for("usiok", timeout=60):
        _flog("[SPSA-W][%s] usiok timeout" % eng.name)
        _LIVE.reset()
        print("[!] engine %s: usiok timeout (engine failed to start)" % eng.name, flush=True)
        return False
    if _spsa_ponder_enabled():
        eng.setoption("USI_Ponder", "true")
    eng.send("isready")
    if not eng.wait_for("readyok", timeout=120):
        _flog("[SPSA-W][%s] readyok timeout" % eng.name)
        _LIVE.reset()
        print("[!] engine %s: readyok timeout (engine not responding)" % eng.name, flush=True)
        return False
    return True


_SELFPLAY_TC_MAIN_MS_LIST = [180000]
_SELFPLAY_TC_INC_MS = 2000
_SELFPLAY_PAIR_MULT = 3
_SELFPLAY_OPENING = ("startpos moves 2g2f 3c3d 7g7f 4a3b 2f2e 8c8d "
                     "6i7h 2b8h+ 7i8h 3a2b 3i4h")


def _selfplay_opening():
    _env = os.environ.get("SPSA_OPENING")
    if _env is not None:
        _env = _env.strip()
        if _env.lower() in ("", "off", "none", "startpos"):
            return None
        return _env
    return _SELFPLAY_OPENING


def _selfplay_games_per_iter():
    return 2 * len(_spsa_parse_tc_spec()) * _SELFPLAY_PAIR_MULT


def _spsa_kifu_path() -> str:
    _env = os.environ.get("SPSA_KIFU_PATH", None)
    if _env is None:
        return os.path.join(_BASE_DIR, "spsa_selfplay.sfen")
    _env = _env.strip()
    if _env.lower() in ("", "off", "none"):
        return ""
    return _env


_spsa_kifu_lock = threading.Lock()

_SPSA_RUNNER_ACTIVE = [False]

_SPSA_INFRA_VOID_REASONS = frozenset({
    "worker_died", "bestmove_timeout_within_budget",
    "engine_restart_failed", "illegal_usi",
    "opening_resign_void", "restart_storm", "fast_bestmove_void",
    "time_loss_infra_void", "silence_mute_void"})

_SPSA_VOID_MARKS: list = []

_HIRATE_SFEN = "lnsgkgsnl/1r5b1/ppppppppp/9/9/9/PPPPPPPPP/1B5R1/LNSGKGSNL b - 1"

_SFEN_KIFU_RESULTS = frozenset({"sente_win", "gote_win", "draw"})
_SFEN_KIFU_REASONS = frozenset({
    "resign", "win_declare", "sennichite", "perpetual_check", "flag_fall",
    "adjudication", "move_limit", "game_timeout", "illegal", "jishogi",
    "rep_draw", "win"})


def _sfen_kifu_append(path, prefix, moves, result, reason) -> None:
    if not path or not moves or result not in _SFEN_KIFU_RESULTS:
        return
    line = (prefix + " moves " + " ".join(moves)
            + ((" " + reason) if reason else "") + " " + result)
    try:
        with _spsa_kifu_lock:
            with open(path, "a", encoding="utf-8") as w:
                w.write(line + "\n")
    except OSError as e:
        _flog(f"[SFEN-KIFU] append failed (ignored): {e}")


def _spsa_append_kifu(moves: list, result: str, reason: str = None) -> None:
    if result == "void":
        _flog("[SPSA-KIFU] void game (infra) — not appended (%d moves)" % len(moves))
        return
    _sfen_kifu_append(_spsa_kifu_path(), "startpos", moves, result, reason)


class _SpsaTimeControl:
    __slots__ = ("kind", "main_ms", "inc_ms", "byoyomi_ms", "overhead_ms", "label")

    def __init__(self, kind, main_ms, inc_ms=0, byoyomi_ms=0,
                 overhead_ms=200, label=None):
        self.kind        = kind
        self.main_ms     = int(main_ms)
        self.inc_ms      = int(inc_ms)
        self.byoyomi_ms  = int(byoyomi_ms)
        self.overhead_ms = int(overhead_ms)
        self.label       = label or self._auto_label()
        if kind == "fischer" and byoyomi_ms:
            raise ValueError(
                f"fischer TC に byoyomi={byoyomi_ms} は指定不可 "
                "(go 行に乗らず driver 予算だけ膨らむ)")

    def _auto_label(self):
        if self.kind == "fischer":
            return "fischer(main=%dms,inc=%dms)" % (self.main_ms, self.inc_ms)
        return "byoyomi(main=%dms,byo=%dms)" % (self.main_ms, self.byoyomi_ms)


class _EngineSession:
    __slots__ = ("state", "probe_s", "stop_window_s",
                 "probe_stage", "last_fresh", "_stop_entered")

    def __init__(self, probe_s: float, stop_window_s: float):
        self.state = "SEARCHING"
        self.probe_s = probe_s
        self.stop_window_s = stop_window_s
        self.probe_stage = 0
        self.last_fresh = time.perf_counter()
        self._stop_entered = 0.0

    def note_fresh(self):
        self.last_fresh = time.perf_counter()

    def enter_stopping(self):
        self.state = "STOPPING"
        self._stop_entered = time.perf_counter()


_SelfplayBudget = namedtuple("_SelfplayBudget",
    ["budget_ms", "main_budget_ms", "stop_cushion_ms", "wait_s", "flag_limit_ms"])

def _selfplay_derive_budget(tc, remaining_ms: float) -> _SelfplayBudget:
    inc_grant_ms = tc.inc_ms if tc.kind == "fischer" else 0
    budget_ms = remaining_ms + inc_grant_ms + (tc.byoyomi_ms if tc.kind == "byoyomi" else 0)
    stop_cushion_ms = max(50.0, float(tc.overhead_ms) + 300.0)
    main_budget_ms = max(0.0, budget_ms - stop_cushion_ms)
    wait_s = max(0.05, main_budget_ms / 1000.0)
    flag_limit_ms = budget_ms + stop_cushion_ms
    return _SelfplayBudget(budget_ms, main_budget_ms, stop_cushion_ms,
                           wait_s, flag_limit_ms)


def _spsa_default_tcs(overhead: int) -> list:
    out = []
    for _m in _SELFPLAY_TC_MAIN_MS_LIST:
        out.append(_SpsaTimeControl(
            "fischer", _m, inc_ms=_SELFPLAY_TC_INC_MS, overhead_ms=overhead,
            label="fischer(%dmin+%ds)" % (_m // 60000, _SELFPLAY_TC_INC_MS // 1000)))
    return out


def _parse_tc_kv(kv: str) -> dict:
    fields = {}
    for pair in kv.split(";"):
        pair = pair.strip()
        if not pair or "=" not in pair:
            continue
        k, _, v = pair.partition("=")
        try:
            fields[k.strip().lower()] = int(v.strip())
        except ValueError:
            pass
    return fields


def _sprt_parse_tc_core(spec, overhead_ms: int = 200) -> "_SpsaTimeControl":
    s = (spec or "").strip()
    if not s:
        return _SpsaTimeControl("byoyomi", 0, byoyomi_ms=2000,
                                overhead_ms=overhead_ms,
                                label="byoyomi(default,byo=2000ms)")
    if s.isdigit():
        return _SpsaTimeControl("byoyomi", 0, byoyomi_ms=int(s),
                                overhead_ms=overhead_ms)
    kind, _, kv = s.partition(":")
    kind = kind.strip().lower()
    if kind not in ("fischer", "byoyomi"):
        kind, kv = "byoyomi", s
    fields = _parse_tc_kv(kv)
    return _SpsaTimeControl(
        kind,
        main_ms=fields.get("main", 0),
        inc_ms=fields.get("inc", 0),
        byoyomi_ms=fields.get("byoyomi", 0),
        overhead_ms=fields.get("overhead", overhead_ms),
    )


def _spsa_parse_tc_spec() -> list:
    _raw_oh = os.environ.get("SPSA_TC_OVERHEAD_MS", "200")
    try:
        overhead = int(_raw_oh)
    except ValueError:
        _flog(f"[E-27] SPSA_TC_OVERHEAD_MS={_raw_oh!r} は非数値 — 200 にフォールバック")
        overhead = 200
    raw = os.environ.get("SPSA_TC", "").strip()
    if not raw:
        return _spsa_default_tcs(overhead)
    specs = []
    for chunk in raw.split(","):
        chunk = chunk.strip()
        if not chunk:
            continue
        try:
            specs.append(_sprt_parse_tc_core(chunk, overhead_ms=overhead))
        except ValueError as _tc_err:
            _flog(f"[E-25] TC chunk {chunk!r} skipped: {_tc_err}")
    if not specs:
        return _spsa_default_tcs(overhead)
    return specs


def _spsa_build_go_line(tc: "_SpsaTimeControl",
                        btime_ms: int, wtime_ms: int) -> str:
    b = max(0, int(btime_ms))
    w = max(0, int(wtime_ms))
    if tc.kind == "fischer":
        return "go btime %d wtime %d binc %d winc %d" % (b, w, tc.inc_ms, tc.inc_ms)
    return "go btime %d wtime %d byoyomi %d" % (b, w, tc.byoyomi_ms)


def _send_gameover(eng_s, eng_g, result):
    eng_s.send("gameover " + (
        "win"  if result == "sente_win" else
        "lose" if result == "gote_win"  else "draw"))
    eng_g.send("gameover " + (
        "lose" if result == "sente_win" else
        "win"  if result == "gote_win"  else "draw"))


def _selfplay_game(eng_sente: "_SpsaUsiEngine",
                    eng_gote:  "_SpsaUsiEngine",
                    game_timeout_s: float = 2000.0,
                    tc: "_SpsaTimeControl" = None,
                    opening: "str | None" = None,
                    sennichite_check: bool = True,
                    info: "dict | None" = None) -> str:
    _prefix, _base_moves = _sprt_split_opening_core(opening)
    _board = None
    _check_flags: list = []
    _sp_last_ja = ""
    if sennichite_check or _base_moves or _prefix != "startpos":
        try:
            _board = ShogiBoard(sfen=_prefix)
            for _bm in _base_moves:
                _check_flags.append(_board.gives_check(_bm))
                try:
                    _sp_last_ja = _sr_usi_to_ja(_board, _bm)
                except Exception:
                    _sp_last_ja = _bm
                _board.push(_bm)
        except Exception as _oe:
            _flog("[SPSA-W] opening rejected %r (%s) → startpos" % (opening, _oe))
            _LIVE.reset()
            print("[!] opening rejected (%s) — falling back to startpos" % _oe,
                  flush=True)
            _prefix, _base_moves, _check_flags = "startpos", [], []
            _board = ShogiBoard() if sennichite_check else None
            _sp_last_ja = ""
    _start_is_sente = (_board.side == "b") if _board is not None else True
    _sp_move_base = len(_base_moves)

    _LIVE.reset()
    _zenrei_live_reset()
    moves: list = []
    _restart_count = 0

    def _fill_info(reason: str, extra: "dict | None" = None,
                    result: str = "") -> None:
        if info is not None:
            info["reason"] = reason
            info["plies"]  = len(moves)
            info["opening_prefix"] = _prefix
            info["base_moves"] = list(_base_moves)
            info.setdefault("sennichite", False)
            if extra:
                info.update(extra)
        if (result and (_SPSA_MODE or _SPSA_RUNNER_ACTIVE[0])
                and reason in _SPSA_INFRA_VOID_REASONS):
            _flog("[STATS-VOID] infra-void game — parent record suppressed "
                  "(reason=%s, %d moves)" % (reason, len(moves)))
            _SPSA_VOID_MARKS.append(time.time())
            return
        if result and (_SPSA_MODE or _SPSA_RUNNER_ACTIVE[0]):
            try:
                _rec = {"ts": time.time(), "source": "spsa_parent",
                        "result": result, "reason": reason,
                        "usi_moves": list(_base_moves) + list(moves),
                        "opening_prefix": _prefix,
                        "tc": tc.label if tc is not None else "",
                        "sente": eng_sente.name, "gote": eng_gote.name}
                if extra:
                    _rec.update(extra)
                _atomic_append(
                    os.path.join(_BASE_DIR, "stats.txt"),
                    json.dumps(_rec, ensure_ascii=False) + "\n",
                    lock=_stats_write_lock)
            except Exception as _e:
                _flog("[STATS-PARENT] write failed: %s" % _e)

    def _kifu(result: str, reason: str = None) -> None:
        if _prefix == "startpos":
            _spsa_append_kifu(_base_moves + moves, result, reason)
        else:
            _flog("[SPSA-W] kifu skipped (non-startpos opening)")

    def _flag_fall_result() -> str:
        if _last_wr_sente is not None and _last_wr_sente > 0.5:
            return "sente_win"
        return "gote_win"

    eng_sente.setoption("Book_Turn_Hint", "+")
    eng_gote.setoption("Book_Turn_Hint", "-")
    eng_sente.send("usinewgame")
    eng_gote.send("usinewgame")

    deadline = time.perf_counter() + game_timeout_s

    btime_ms = tc.main_ms
    wtime_ms = tc.main_ms

    _USI_MOVE_RE = re.compile(
        r'^([1-9][a-i][1-9][a-i]\+?|[PLNSBRGplnsbrgK]\*[1-9][a-i])$'
    )

    _ponder_on = _spsa_ponder_enabled()
    _ponder_map: dict = {}
    _ponder_hits = _ponder_miss = 0
    _ponder_preempted: set = set()

    def _ponder_halt(eng) -> bool:
        if eng not in _ponder_map:
            return True
        try:
            _ok = eng.flush_with_stop(timeout=15.0)
            if not _ok:
                _flog("[SPSA-W][PNDR] halt: flush_with_stop did not complete (%s) — "
                      "_ponder_map に残置 (次回先打ち stop の対象)"
                      % getattr(eng, "name", "?"))
                return False
            _ponder_map.pop(eng, None)
        except (KeyboardInterrupt, SystemExit, MemoryError):
            raise
        except Exception as _ponderhit_exc:
            _flog("[SPSA-W][PNDR] halt error (%s): %r — _ponder_map に残置"
                  % (getattr(eng, "name", "?"), _ponderhit_exc))
            return False
        return True

    _adj_streak_sente = 0
    _adj_streak_gote = 0
    _adj_last_obs_move = None
    _adj_score_obs = None
    _sp_rec = None
    _last_wr_sente = None
    _fast_bm_streak = 0
    _FAST_BM_THRESHOLD_MS = 100
    _FAST_BM_STREAK_LIMIT = 3
    _FAST_BM_MIN_MOVE = 10
    _infra_intervened = False
    try:
      for move_no in range(512):
        if time.perf_counter() > deadline:
            _flog("[SPSA-W] game timeout → draw")
            _LIVE.reset()
            print("[!] game timeout — counted as draw", flush=True)
            _kifu("void")
            _fill_info("game_timeout", result="draw")
            return "draw"

        is_sente = (_start_is_sente == (move_no % 2 == 0))
        thinker  = eng_sente if is_sente else eng_gote
        side     = "sente"   if is_sente else "gote"
        our_remaining = btime_ms if is_sente else wtime_ms

        _all_moves = _base_moves + moves
        pos = "position " + _prefix + (
            (" moves " + " ".join(_all_moves)) if _all_moves else "")
        _barrier_ok = True
        _t_hit = None
        _sp_pre_drained = False
        _ph_skip_send = False
        bestmove = ""
        _ponder_hint = ""
        _was_preempted = thinker in _ponder_preempted
        _ponder_preempted.discard(thinker)
        if thinker in _ponder_map:
            _pred, _pred_key = _ponder_map[thinker]
            if (not _was_preempted) and _ponder_is_hit(_pred_key, _board):
                _ponder_map.pop(thinker, None)
                _sp_pre_drained = False
                _sp_pre_bm, _sp_pre_pd, _sp_pre_ni = _drain_sp_early_bestmove(
                    thinker, caller="sp-ponderhit-pre", grace_s=0.05)
                if _sp_pre_bm:
                    _sp_pre_drained = True
                    if _board is not None and _bestmove_is_for_board(_sp_pre_bm, _board):
                        _flog("[P6-1] SP pre-drain hit: %s — adopting directly" % _sp_pre_bm)
                        bestmove = _sp_pre_bm
                        _ponder_hint = _sp_pre_pd or ""
                    else:
                        _flog("[P6-1/FIX-BH] pre-drain bm %r not for board — "
                              "child idle, suppressing ponderhit" % _sp_pre_bm)
                        _ph_skip_send = True
                elif _sp_pre_ni.get("__search_complete__"):
                    _sp_pre_drained = True
                    _ph_skip_send = True
                    _flog("[P6-1/FIX-BH] pre-drain consumed terminal bestmove — "
                          "child idle, suppressing ponderhit")
                _t_hit = time.perf_counter()
                _ponderhit_clock = _extract_clock_tokens(
                    _spsa_build_go_line(tc, btime_ms, wtime_ms))
                if not bestmove and not _ph_skip_send:
                    _sp_race_bm, _sp_race_pd, _sp_race_ni = (
                        _drain_sp_early_bestmove(
                            thinker, caller="sp-ponderhit-race", grace_s=0.0))
                    if _sp_race_bm:
                        _sp_pre_drained = True
                        if (_board is not None
                                and _bestmove_is_for_board(_sp_race_bm, _board)):
                            _flog("[P6-1-RACE] SP pre-drain race caught at send: "
                                  "%s (ponder=%s) — ponderhit suppressed"
                                  % (_sp_race_bm, _sp_race_pd))
                            bestmove = _sp_race_bm
                            _ponder_hint = _sp_race_pd or ""
                        else:
                            _flog("[P6-1-RACE/FIX-BH] race-caught bm %r not for "
                                  "board — child idle, suppressing ponderhit"
                                  % _sp_race_bm)
                            _ph_skip_send = True
                    elif _sp_race_ni.get("__search_complete__"):
                        _sp_pre_drained = True
                        _ph_skip_send = True
                        _flog("[P6-1-RACE/FIX-BH] race-caught terminal bestmove — "
                              "child idle, suppressing ponderhit")
                if (not bestmove and not _ph_skip_send
                        and getattr(thinker, "_go_sent", 0) > 0
                        and getattr(thinker, "_bm_arrived", 0)
                            >= thinker._go_sent):
                    _ph_skip_send = True
                    _flog("[P6-1-IDLE/FIX-BH] child answered all gos "
                          "(go_sent=%d bm_arrived=%d) — ponderhit suppressed "
                          "(structural idle gate)"
                          % (thinker._go_sent, thinker._bm_arrived))
                if not bestmove and not _ph_skip_send:
                    thinker.send(("ponderhit " + _ponderhit_clock) if _ponderhit_clock else "ponderhit")
                _ponder_hits += 1
            else:
                _non_thinker = eng_gote if is_sente else eng_sente
                if _non_thinker in _ponder_map and not _was_preempted:
                    _ponder_preempted.add(_non_thinker)
                    try:
                        _non_thinker.send("stop")
                    except Exception as _preempt_send_exc:
                        _flog("[SPSA-W][PNDR-PREEMPT] non_thinker stop "
                              "send raised (preempted already registered) "
                              "(%s): %r"
                              % (getattr(_non_thinker, "name", "?"),
                                 _preempt_send_exc))
                    if not getattr(_non_thinker, "_alive", True):
                        _ponder_map.pop(_non_thinker, None)
                        _ponder_preempted.discard(_non_thinker)
                        _flog("[SPSA-W][PNDR-PREEMPT] non_thinker dead at "
                              "preempt (%s): removed from _ponder_map"
                              % getattr(_non_thinker, "name", "?"))
                _barrier_ok = _ponder_halt(thinker)
                _ponder_miss += 1
                if not _barrier_ok:
                    _restart_count += 1
                    if _restart_count > 2:
                        _flog("[SPSA-W][PNDR] halt failed %d times this game — "
                              "voiding game (restart storm guard)" % _restart_count)
                        _LIVE.reset()
                        print("[!] engine halt failure x%d — game voided (draw)"
                              % _restart_count, flush=True)
                        _kifu("void")
                        _fill_info("restart_storm", result="draw")
                        return "draw"
                    _flog("[SPSA-W][PNDR] halt failed — restarting %s (%d/2 this game)"
                          % (getattr(thinker, "name", "?"), _restart_count))
                    if thinker.restart():
                        _barrier_ok = True
                        _ponder_map.pop(thinker, None)
                        thinker.send("usinewgame")
                    else:
                        _flog("[SPSA-W][PNDR] restart failed → draw")
                        _LIVE.reset()
                        print("[!] engine restart failed — counted as draw",
                              flush=True)
                        _kifu("void")
                        _fill_info("engine_restart_failed", result="draw")
                        return "draw"
        _fast_first = False
        if _t_hit is None:
            if not _all_moves and _prefix == "startpos" and is_sente:
                bestmove = "2g2f"
                _ponder_hint = ""
                _fast_first = True
            else:
                if not _ponder_on:
                    (eng_gote if is_sente else eng_sente).send(pos)
                thinker.send(pos)
                thinker.send(_spsa_build_go_line(tc, btime_ms, wtime_ms))

        _spb = _selfplay_derive_budget(tc, our_remaining)
        budget_ms = _spb.budget_ms
        _stop_cushion_ms = _spb.stop_cushion_ms
        _main_budget_ms = _spb.main_budget_ms
        wait_s = _clamp(deadline - time.perf_counter(), 0.05, _spb.wait_s)

        if _fast_first or bestmove:
            wait_s = 0
        _t_think0 = _t_hit if _t_hit is not None else time.perf_counter()
        _t_think0_orig = _t_think0
        _is_hit_path = (_t_hit is not None)
        _stale_miss_reissue_count = 0
        _intervention_ms = 0.0
        _hit_wd_base_pre_isready = None
        _sp_echo_prev_t = None
        _mute_after_rescue = False

        def _consume_bestmove(_line: str) -> bool:
            nonlocal bestmove, _ponder_hint
            _bm_toks = _line.split() + ["", "", ""]
            _cand = _bm_toks[1]
            if not _cand:
                return False
            bestmove = _cand
            _ponder_hint = _bm_toks[3] if _bm_toks[2] == "ponder" else ""
            return True

        _sp_echo_seen = False
        _sp_live_active = (_board is not None and _LIVE._ready())
        if _sp_live_active:
            _sp_live_premoves = _base_moves + moves
            _sp_live_pos = "position " + _prefix + (
                (" moves " + " ".join(_sp_live_premoves)) if _sp_live_premoves else "")
            _sp_live_gp = _game_phase_value_state(_board) if _board is not None else None
            _sp_live_rec = {"source": "selfplay", "handler": side, "game_phase": _sp_live_gp}
            _sp_carry_policy = None
            _sp_prev = _LIVE._think
            if _sp_prev is not None and isinstance(_sp_prev[0], dict):
                _sp_prev_rec = _sp_prev[0]
                for _ck in ("confidence", "depth_quality", "confidence_dq",
                            "sharpness", "momentum",
                            "council_wr_nnue",
                            "council_wr_dl", "council_wr_dl2",
                            "dl_top_score", "dl_used",
                            "nnue_score_cp", "nnue_depth",
                            "regime_label", "regime_conviction"):
                    if _sp_prev_rec.get(_ck) is not None and _ck not in _sp_live_rec:
                        _sp_live_rec[_ck] = _sp_prev_rec[_ck]
            _LIVE.set_think(_sp_live_rec, _sp_live_pos, _sp_carry_policy,
                            live=True)
            _sp_live_last_emit = 0.0
            _LIVE.show(_board, move_no=_sp_move_base + move_no,
                       last_move=_sp_last_ja,
                       sente_time=_sr_fmt_clock(btime_ms),
                       gote_time=_sr_fmt_clock(wtime_ms))
        dl2 = _t_think0 + wait_s
        _reader_revive_count = 0
        try:
            _use_session_fsm = _cfg_bool("Selfplay_Session_FSM")
        except (ValueError, TypeError, AttributeError):
            _use_session_fsm = False

        if _use_session_fsm:
            _fsm = _EngineSession(
                probe_s=_clamp(0.25 * _main_budget_ms / 1000.0, 1.0, 20.0),
                stop_window_s=max(3.0, 2.0 * float(tc.overhead_ms) / 1000.0),
            )
            if _is_hit_path and _sp_pre_drained:
                _fsm.probe_s = min(_fsm.probe_s, 2.0)
            elif _is_hit_path and _ph_skip_send:
                _fsm.probe_s = min(_fsm.probe_s, 2.0)
            _fsm_fresh_pv = False
            _sp_live_fresh = False
            while not bestmove:
                _now_f = time.perf_counter()
                if _fsm.state == "SEARCHING":
                    if _now_f >= dl2:
                        _flog("[WO-3][%s] budget expired — sending stop" % side)
                        try:
                            thinker.send("stop")
                        except Exception:
                            pass
                        _fsm.enter_stopping()
                        _ov_s = max(0.05, float(tc.overhead_ms) / 1000.0)
                        _el_s = _now_f - _t_think0
                        _rem_lim = max(0.0, (budget_ms + _stop_cushion_ms) / 1000.0
                                       - _el_s - 0.05)
                        _sw = min(_stop_cushion_ms / 1000.0 + 2.0 * _ov_s,
                                  _rem_lim)
                        dl2 = _now_f + max(_ov_s, min(
                            _sw, max(0.0, deadline - _now_f)))
                        continue
                    if _now_f - _fsm.last_fresh >= _fsm.probe_s:
                        if _fsm.probe_stage >= 2:
                            _flog("[WO-3][%s] DEAD: no response after reissue"
                                  % side)
                            break
                        _flog("[WO-3][%s] no fresh output %.1fs — stop probe"
                              % (side, _now_f - _fsm.last_fresh))
                        try:
                            thinker.send("stop")
                        except Exception as _fse:
                            _flog("[WO-3][%s] stop probe failed: %s"
                                  % (side, _fse))
                        _fsm.enter_stopping()
                        _fsm.probe_stage += 1
                        continue
                elif _fsm.state == "STOPPING":
                    if _now_f >= dl2:
                        break
                    if _now_f - _fsm._stop_entered >= _fsm.stop_window_s:
                        if _fsm.probe_stage < 2:
                            _flog("[WO-3][%s] stop window expired — reissuing"
                                  % side)
                            _fsm.probe_stage = 2
                            thinker.send(pos)
                            thinker.send(_spsa_build_go_line(
                                tc, btime_ms, wtime_ms))
                            _is_hit_path = False
                            _fsm_fresh_pv = False
                            _fsm.state = "SEARCHING"
                            _t_think0 = _now_f
                            _infra_intervened = True
                            dl2 = _now_f + min(
                                budget_ms / 1000.0,
                                max(0.05, deadline - _now_f))
                            _fsm.note_fresh()
                            _flog("[WO-3][%s] reissue rebased "
                                  "(fresh main=%.0fms)"
                                  % (side, _main_budget_ms))
                            continue
                        break
                elif _fsm.state == "DEAD":
                    break
                _rl_to = max(0.1, dl2 - _now_f)
                if _fsm.state == "SEARCHING":
                    _rl_to = max(0.1, min(
                        _rl_to,
                        _fsm.probe_s - (_now_f - _fsm.last_fresh)))
                elif _fsm.state == "STOPPING":
                    _rl_to = max(0.1, min(
                        _rl_to,
                        _fsm.stop_window_s - (_now_f - _fsm._stop_entered)))
                line = thinker.readline(timeout=_rl_to)
                if line is None:
                    _thp_n = _get_proc(thinker)
                    _nd = (_thp_n is not None
                           and _thp_n.poll() is not None)
                    _flog("[WO-3][%s] readline=None proc_dead=%s"
                          % (side, _nd))
                    if _nd:
                        break
                    _reader_revive_count += 1
                    if _reader_revive_count > 3:
                        _flog("[WO-3][%s] reader revive limit" % side)
                        break
                    import queue as _rq
                    _fq = _rq.Queue()
                    thinker._q = _fq
                    thinker._alive = True
                    _tp = thinker.proc
                    _tself = thinker
                    def _fsm_rr(_p=_tp, _q=_fq, _s=_tself):
                        try:
                            for _l in _p.stdout:
                                _q.put(_l.rstrip("\n"))
                        except Exception as _rre:
                            try:
                                _flog("[WO-3] recovery_reader: %s" % _rre)
                            except Exception:
                                pass
                        finally:
                            if _s.proc is _p:
                                _s._alive = False
                            _q.put(None)
                    threading.Thread(target=_fsm_rr, daemon=True,
                                    name="fsm_recovery_%s" % side).start()
                    _flog("[WO-3][%s] reader revived (%d/3)"
                          % (side, _reader_revive_count))
                    time.sleep(0.1)
                    continue
                if not line:
                    _thp_p = _get_proc(thinker)
                    if (_thp_p is not None
                            and _thp_p.poll() is not None):
                        _flog("[WO-3][%s] engine dead (rc=%s)"
                              % (side, _thp_p.returncode))
                        break
                    continue
                _wf, _fsm_fresh_pv = _line_freshness(
                    line, _board, _fsm_fresh_pv)
                if _wf:
                    _fsm.note_fresh()
                if not line.startswith("bestmove"):
                    if _sp_live_active and "dl_live_policy " in line:
                        try:
                            _dli = line.index("dl_live_policy ") + len("dl_live_policy ")
                            _dlr = line[_dli:]
                            _dlt = None
                            if _dlr and not _dlr.startswith("["):
                                _ste = _dlr.index(" ")
                                _dlt = _dlr[:_ste]
                                _dlr = _dlr[_ste + 1:]
                            _dlp = json.loads(_dlr)
                            _dph = hashlib.md5(
                                (_sp_live_pos or "").encode()
                                ).hexdigest()[:8] if _sp_live_pos else None
                            if _dlt and _dph and _dlt == _dph:
                                pass
                            elif _dlp and _board is not None:
                                _dlp = [
                                    (m, s) for (m, s) in _dlp
                                    if _bestmove_is_for_board(m, _board)
                                ] or None
                            if _dlp:
                                _LIVE.update_think_pv(
                                    policy=_dlp, pos=_sp_live_pos)
                        except Exception:
                            pass
                    elif _sp_live_active and _is_scored_info(line):
                        _sp_now = time.perf_counter()
                        if _sp_now - _sp_live_last_emit < 0.2:
                            continue
                        _dm_sp = _RE_DEPTH.search(line)
                        if _dm_sp:
                            _scp_sp = 0
                            _sm_sp = _RE_SCORE_CP.search(line)
                            if _sm_sp:
                                _scp_sp = int(_sm_sp.group(1))
                            else:
                                _mm_sp = _RE_MATE.search(line)
                                if _mm_sp:
                                    _scp_sp = _mate_sign_score(
                                        int(_mm_sp.group(1)))
                            _pv_sp = None
                            if " pv " in line:
                                _fpv_sp = _RE_PV_FULL.search(line)
                                if _fpv_sp:
                                    _pv_sp = _fpv_sp.group(1).split()
                            if _pv_sp:
                                _pv_n_ok = 0
                                try:
                                    _pv_wb = _board.clone()
                                    for _pv_mv in _pv_sp:
                                        if (_pv_mv in ("resign", "win")
                                                or not _bestmove_is_for_board(
                                                    _pv_mv, _pv_wb)):
                                            break
                                        _pv_wb.apply_usi(_pv_mv)
                                        _pv_n_ok += 1
                                except Exception:
                                    pass
                                if _pv_n_ok == 0:
                                    continue
                                if _pv_n_ok < len(_pv_sp):
                                    _pv_sp = _pv_sp[:_pv_n_ok]
                                _sp_live_fresh = True
                            elif not _sp_live_fresh:
                                continue
                            try:
                                _LIVE.update_think_pv(
                                    pv=_pv_sp, score_cp=_scp_sp,
                                    pos=_sp_live_pos)
                                _sp_live_last_emit = _sp_now
                            except Exception:
                                pass
                    continue
                if not _consume_bestmove(line):
                    continue
                _bm_class = thinker.classify_bestmove()
                _is_stale = (
                    _bm_class == "stale"
                    or (_bm_class == "unknown"
                        and not _bestmove_is_for_board(bestmove, _board)))
                if _is_stale:
                    _sp_echo_seen = True
                    _stale_miss_reissue_count += 1
                    _flog("[WO-3][%s] SP-echo drained (class=%s, count=%d): %r"
                          % (side, _bm_class, _stale_miss_reissue_count,
                             bestmove))
                    if _stale_miss_reissue_count > 5:
                        _flog("[WO-3][%s] SP-echo cap reached (%d>5) — "
                              "stop+flush and abandon"
                              % (side, _stale_miss_reissue_count))
                        try:
                            thinker.send("stop")
                        except Exception:
                            pass
                        try:
                            thinker.flush_until_ready(timeout=5.0)
                        except Exception:
                            pass
                        _infra_intervened = True
                        bestmove = ""
                        _ponder_hint = ""
                        break
                    bestmove = ""
                    _ponder_hint = ""
                    if _is_hit_path:
                        _fsm.state = "SEARCHING"
                        _fsm.probe_stage = 0
                        _fsm_fresh_pv = False
                        _fsm.note_fresh()
                        continue
                    thinker.send(pos)
                    thinker.send(_spsa_build_go_line(
                        tc, btime_ms, wtime_ms))
                    _is_hit_path = False
                    _infra_intervened = True
                    _nw = time.perf_counter()
                    _rs = max(0.05,
                              _main_budget_ms / 1000.0
                              - (_nw - _t_think0))
                    dl2 = _nw + min(
                        _rs, max(0.05, deadline - _nw))
                    _fsm.note_fresh()
                    continue
                if (_bm_class != "current"
                        and bestmove in ("resign", "win")
                        and not _barrier_ok):
                    bestmove = ""
                    _ponder_hint = ""
                    continue
                if _fsm.state == "STOPPING":
                    _flog("[WO-3][%s] stop bestmove=%s"
                          % (side, bestmove))
                break
            dl2 = 0

        _hit_lines_seen = 0
        _wd_fresh_seen = False
        _hit_probe_stage = 0
        _hit_probe1_lines = 0
        _hit_isready_probed = False
        _wd_reissue_prev_gen = None
        _hit_probe_s = _clamp(0.25 * _main_budget_ms / 1000.0, 1.0, 20.0)
        _hit_probe_s = min(_hit_probe_s,
                           max(1.0, 0.10 * our_remaining / 1000.0))
        if _is_hit_path and _sp_pre_drained:
            _hit_probe_s = min(_hit_probe_s, 2.0)
        elif _is_hit_path and _ph_skip_send:
            _hit_probe_s = min(_hit_probe_s, 2.0)
        _hit_probe2_deadline = 0.0
        _hit_probe1_ext_total = 0.0
        _hit_wd_base = _t_think0
        try:
            _silence_wd_s = _cfloat(_cfg, "Tuning_Silence_Watchdog_S", 120)
        except (ValueError, TypeError):
            _silence_wd_s = 120.0
        if _silence_wd_s > 0:
            _silence_wd_s = min(_silence_wd_s,
                                max(10.0, 0.5 * _main_budget_ms / 1000.0))
            _silence_wd_s = min(_silence_wd_s,
                                max(2.0, 0.25 * our_remaining / 1000.0))
        _silence_last_t = time.perf_counter()
        _silence_rescue_fired = False
        _heartbeat_interval_s = 15.0
        _heartbeat_next_t = time.perf_counter() + _heartbeat_interval_s
        _heartbeat_fail_count = 0
        _sp_live_fresh = False
        _time_loss_grant_ms = float(
            (tc.inc_ms if tc.kind == "fischer" else tc.byoyomi_ms)
            + _stop_cushion_ms)
        while not bestmove and time.perf_counter() < dl2:
            _real_wall_ms = (time.perf_counter() - _t_think0_orig) * 1000.0
            if _real_wall_ms > our_remaining + _time_loss_grant_ms + _intervention_ms:
                if _infra_intervened:
                    _flog("[SPSA-W][%s] time_loss after harness rescue: real "
                          "wall %.0fms > remaining %.0fms + grant %.0fms + "
                          "intervention %.0fms → infra void (not θ's fault)"
                          % (side, _real_wall_ms, our_remaining,
                             _time_loss_grant_ms, _intervention_ms))
                    _LIVE.reset()
                    print("[!] %s: time forfeit after rescue — infra void"
                          % side, flush=True)
                    try:
                        thinker.preserve_wedge_diag("TIMELOSS")
                    except Exception:
                        pass
                    _kifu("void")
                    _fill_info("time_loss_infra_void", {
                        "real_wall_ms": int(_real_wall_ms),
                        "remaining_ms": int(our_remaining),
                        "wr_sente": _last_wr_sente},
                        result="draw")
                    return "draw"
                _flog("[SPSA-W][%s] time_loss: real wall %.0fms > remaining "
                      "%.0fms + grant %.0fms + intervention %.0fms "
                      "(orig_t0 not rebased)"
                      % (side, _real_wall_ms, our_remaining,
                         _time_loss_grant_ms, _intervention_ms))
                _LIVE.reset()
                print("[!] %s: time forfeit (実時計超過)" % side, flush=True)
                _result = _flag_fall_result()
                _kifu(_result, "flag_fall")
                _fill_info("time_loss", {
                    "real_wall_ms": int(_real_wall_ms),
                    "remaining_ms": int(our_remaining),
                    "wr_sente": _last_wr_sente},
                    result=_result)
                return _result
            _rl_to = max(0.1, dl2 - time.perf_counter())
            _tl_rem_s = ((our_remaining + _time_loss_grant_ms + _intervention_ms)
                         / 1000.0 - (time.perf_counter() - _t_think0_orig))
            if _tl_rem_s < _rl_to:
                _rl_to = max(0.25, _tl_rem_s)
            if (_silence_wd_s > 0 and not _is_hit_path
                    and time.perf_counter() >= _heartbeat_next_t):
                try:
                    thinker.send("isready")
                except Exception as _hb_e:
                    _flog("[P6-2][%s] heartbeat send failed: %s" % (side, _hb_e))
                _heartbeat_fail_count += 1
                if _heartbeat_fail_count >= 2:
                    _flog("[P6-2][%s] heartbeat: readyok 不達 (%d/2)"
                          % (side, _heartbeat_fail_count))
                _heartbeat_next_t = time.perf_counter() + _heartbeat_interval_s
                if _heartbeat_fail_count >= 2:
                    _flog("[P6-2][%s] heartbeat: 2 consecutive failures — "
                          "triggering immediate rescue" % side)
                    _silence_last_t = time.perf_counter() - _silence_wd_s
            if _silence_wd_s > 0 and (
                    not _is_hit_path
                    or (_hit_lines_seen > 0 and _hit_probe_stage == 0)):
                _sil_s = time.perf_counter() - _silence_last_t
                if _sil_s >= _silence_wd_s:
                    _sil_credit_s = min(
                        _sil_s,
                        max(0.0, time.perf_counter() - _t_think0_orig))
                    _intervention_ms += _sil_credit_s * 1000.0
                    if not _silence_rescue_fired:
                        _sw_p = _get_proc(thinker)
                        if ((_sw_p is not None and _sw_p.poll() is not None)
                                or not getattr(thinker, "_alive", True)):
                            _flog("[SPSA-W][%s] silence-watchdog: child dead "
                                  "(poll/_alive) — skipping rescue, abandoning "
                                  "main wait" % side)
                            break
                        _silence_rescue_fired = True
                        _infra_intervened = True
                        _t_intervention_start = time.perf_counter()
                        _flog("[SPSA-W][%s] silence-watchdog: %.1fs mute — "
                              "stop probe + reissuing position+go (one rescue)"
                              % (side, _sil_s))
                        try:
                            thinker.send("stop")
                        except Exception as _sw_se:
                            _flog("[SPSA-W][%s] silence-rescue stop send failed: %s"
                                  % (side, _sw_se))
                        time.sleep(max(0.4, 2.0 * float(tc.overhead_ms) / 1000.0))
                        if _wd_reissue_prev_gen is None:
                            _wd_reissue_prev_gen = thinker._go_sent
                        _rsq_active_ms = max(
                            0.0, (time.perf_counter() - _t_think0_orig) * 1000.0
                            - _intervention_ms)
                        _rsq_rem = max(0, int(our_remaining - _rsq_active_ms))
                        _rsq_b = _rsq_rem if is_sente else btime_ms
                        _rsq_w = wtime_ms if is_sente else _rsq_rem
                        thinker.send(pos)
                        thinker.send(_spsa_build_go_line(tc, _rsq_b, _rsq_w))
                        _is_hit_path = False
                        _intervention_ms += (time.perf_counter()
                                             - _t_intervention_start) * 1000.0
                        _t_think0 = time.perf_counter()
                        _tl_bound_s = max(1.0,
                                          (our_remaining + _time_loss_grant_ms
                                           + _intervention_ms) / 1000.0
                                          - (_t_think0 - _t_think0_orig))
                        dl2 = _t_think0 + min(budget_ms / 1000.0,
                                              _tl_bound_s,
                                              max(0.05, deadline - _t_think0))
                        _silence_last_t = time.perf_counter()
                        _sp_echo_prev_t = _silence_last_t
                        continue
                    _mute_after_rescue = True
                    _flog("[SPSA-W][%s] silence-watchdog: no output for %.1fs "
                          "(>= %.0fs) — abandoning main wait (stop window next)"
                          % (side, _sil_s, _silence_wd_s))
                    break
                _rl_to = _clamp(_silence_wd_s - _sil_s, 0.1, _rl_to)
            if _is_hit_path and _hit_probe_stage < 2 and (
                    _hit_lines_seen == 0 or _hit_probe_stage == 1):
                _now_wd = time.perf_counter()
                if _hit_probe_stage == 0:
                    _wd_next = _hit_wd_base + _hit_probe_s
                    if _now_wd >= _wd_next and not _hit_isready_probed:
                        _hit_isready_probed = True
                        _flog("[SPSA-W][%s] hit-watchdog: no output %.1fs after "
                              "ponderhit — sending isready probe (non-destructive)"
                              % (side, _now_wd - _hit_wd_base))
                        try:
                            thinker.send("isready")
                        except Exception as _wd_ie:
                            _flog("[SPSA-W][%s] hit-watchdog isready send failed: %s"
                                  % (side, _wd_ie))
                        if _hit_wd_base_pre_isready is None:
                            _hit_wd_base_pre_isready = _hit_wd_base
                        _hit_wd_base = _now_wd + 3.0 - _hit_probe_s
                        _rl_to = _clamp(3.0, 0.1, _rl_to)
                    elif _now_wd >= _wd_next:
                        _flog("[SPSA-W][%s] hit-watchdog: no output %.1fs after "
                              "ponderhit — sending stop probe"
                              % (side, _now_wd - _hit_wd_base))
                        try:
                            thinker.send("stop")
                        except Exception as _wd_se:
                            _flog("[SPSA-W][%s] hit-watchdog stop send failed: %s"
                                  % (side, _wd_se))
                        _hit_probe_stage = 1
                        _hit_probe1_lines = 0
                        _hit_probe2_deadline = _now_wd + max(
                            5.0, 2.0 * float(tc.overhead_ms) / 1000.0)
                        _rl_to = _clamp(
                            _hit_probe2_deadline - _now_wd, 0.1, _rl_to)
                    else:
                        _rl_to = _clamp(_wd_next - _now_wd, 0.1, _rl_to)
                elif _hit_probe_stage == 1:
                    if _now_wd >= _hit_probe2_deadline:
                        _ext_w = max(5.0, 2.0 * float(tc.overhead_ms) / 1000.0)
                        _ext_cap = max(5.0, min(30.0,
                                                0.25 * our_remaining / 1000.0))
                        if (_hit_probe1_lines > 0
                                and _hit_probe1_ext_total + _ext_w <= _ext_cap):
                            _hit_probe1_ext_total += _ext_w
                            _flog("[SPSA-W][%s] hit-watchdog: child produced "
                                  "%d lines after stop probe — busy, not idle; "
                                  "extending deadline (%.0fs/%.0fs used)"
                                  % (side, _hit_probe1_lines,
                                     _hit_probe1_ext_total, _ext_cap))
                            _hit_probe1_lines = 0
                            _hit_probe2_deadline = _now_wd + _ext_w
                            _rl_to = _clamp(
                                _hit_probe2_deadline - _now_wd, 0.1, _rl_to)
                            continue
                        if _hit_probe1_lines > 0:
                            _flog("[SPSA-W][%s] hit-watchdog: busy-extension "
                                  "cap %.0fs reached (still no bestmove) — "
                                  "escalating to reissue" % (side, _ext_cap))
                        else:
                            _flog("[SPSA-W][%s] hit-watchdog: still silent after "
                                  "stop probe — child idle, reissuing position+go"
                                  % side)
                        _s2_p = _get_proc(thinker)
                        if ((_s2_p is not None and _s2_p.poll() is not None)
                                or not getattr(thinker, "_alive", True)):
                            _flog("[SPSA-W][%s] hit-watchdog: child dead at "
                                  "stage2 (poll/_alive) — abandoning main wait"
                                  % side)
                            break
                        _hit_probe_stage = 2
                        _infra_intervened = True
                        _hwb_credit = (_hit_wd_base_pre_isready
                                       if _hit_wd_base_pre_isready is not None
                                       else _hit_wd_base)
                        _intervention_ms += (_now_wd - _hwb_credit) * 1000.0
                        if _wd_reissue_prev_gen is None:
                            _wd_reissue_prev_gen = thinker._go_sent
                        _rs2_active_ms = max(
                            0.0, (_now_wd - _t_think0_orig) * 1000.0
                            - _intervention_ms)
                        _rs2_rem = max(0, int(our_remaining - _rs2_active_ms))
                        _rs2_b = _rs2_rem if is_sente else btime_ms
                        _rs2_w = wtime_ms if is_sente else _rs2_rem
                        thinker.send(pos)
                        thinker.send(_spsa_build_go_line(tc, _rs2_b, _rs2_w))
                        _is_hit_path = False
                        _flog("[SPSA-W][%s] hit-watchdog: reissue window rebased "
                              "(dead=%.0fms → fresh main=%.0fms)"
                              % (side, (_now_wd - _t_think0) * 1000.0,
                                 _main_budget_ms))
                        _t_think0 = _now_wd
                        _tl_bound_s = max(1.0,
                                          (our_remaining + _time_loss_grant_ms
                                           + _intervention_ms) / 1000.0
                                          - (_now_wd - _t_think0_orig))
                        dl2 = _now_wd + min(budget_ms / 1000.0,
                                            _tl_bound_s,
                                            max(0.05, deadline - _now_wd))
                        _silence_last_t = _now_wd
                        _heartbeat_next_t = _now_wd + _heartbeat_interval_s
                        continue
                    _rl_to = _clamp(_hit_probe2_deadline - _now_wd, 0.1, _rl_to)
            line = thinker.readline(timeout=_rl_to)
            if line is None:
                _thp_none = _get_proc(thinker)
                _none_dead = (_thp_none is not None and _thp_none.poll() is not None)
                _flog("[SPSA-W][%s] readline=None "
                      "elapsed=%.3fs dl2_rem=%.3fs proc_dead=%s"
                      % (side, time.perf_counter() - _t_think0,
                         dl2 - time.perf_counter(), _none_dead))
                if _none_dead:
                    break
                _reader_revive_count += 1
                if _reader_revive_count > 3:
                    _flog("[SPSA-W][%s] reader revive limit reached" % side)
                    break
                import queue as _rq
                _prev_alive = getattr(thinker, "_alive", "?")
                _prev_q_size = 0
                try:
                    _prev_q_size = thinker._q.qsize()
                except Exception:
                    pass
                _fresh_q = _rq.Queue()
                thinker._q = _fresh_q
                thinker._alive = True
                _target_proc = thinker.proc
                _target_self = thinker
                def _recovery_reader(_p=_target_proc, _rqq=_fresh_q, _ts=_target_self):
                    try:
                        for _rl in _p.stdout:
                            _rqq.put(_rl.rstrip("\n"))
                    except Exception as _rr_exc:
                        try:
                            _flog(f"[SPSA-W] recovery_reader error: {type(_rr_exc).__name__}: {_rr_exc!r}")
                        except Exception:
                            pass
                    finally:
                        if _ts.proc is _p:
                            _ts._alive = False
                        _rqq.put(None)
                threading.Thread(target=_recovery_reader, daemon=True,
                                 name="spsa_recovery_%s" % side).start()
                _flog("[SPSA-W][%s] reader revived (%d/3) prev_alive=%s q_size=%d"
                      % (side, _reader_revive_count, _prev_alive, _prev_q_size))
                time.sleep(0.1)
                continue
            if not line:
                _thp_poll = _get_proc(thinker)
                if _thp_poll is not None and _thp_poll.poll() is not None:
                    _flog("[SPSA-W][%s] engine dead during main wait (rc=%s)"
                          % (side, _thp_poll.returncode))
                    break
                continue
            _silence_last_t = time.perf_counter()
            _heartbeat_next_t = _silence_last_t + _heartbeat_interval_s
            _heartbeat_fail_count = 0
            if (_is_hit_path and _hit_probe_stage == 0 and _hit_isready_probed
                    and _hit_lines_seen == 0 and line.strip() == "readyok"):
                _flog("[SPSA-W][%s] hit-watchdog: bare readyok after isready "
                      "probe — child dispatch idle (ponderhit black hole); "
                      "escalating to stop probe now" % side)
                _ph_bh_race_n = getattr(thinker, "_ph_bh_race_count", 0) + 1
                thinker._ph_bh_race_count = _ph_bh_race_n
                _flog("[PH-BH-RACE][%s] bare-readyok idle after ponderhit "
                      "(#%d elapsed=%.1fs) — residual pipe-arrival race "
                      "(Patch1 では閉じない window)"
                      % (side, _ph_bh_race_n,
                         time.perf_counter() - _t_think0))
                try:
                    thinker.send("stop")
                except Exception as _wd_se2:
                    _flog("[SPSA-W][%s] hit-watchdog stop send failed: %s"
                          % (side, _wd_se2))
                _hit_probe_stage = 1
                _hit_probe1_lines = 0
                _hit_probe2_deadline = time.perf_counter() + max(
                    5.0, 2.0 * float(tc.overhead_ms) / 1000.0)
                continue
            _wd_line_fresh = True
            if _is_hit_path and _hit_probe_stage == 0 and _board is not None:
                _wd_line_fresh, _wd_fresh_seen = _line_freshness(
                    line, _board, _wd_fresh_seen)
            if _wd_line_fresh:
                _hit_lines_seen += 1
                if _hit_probe_stage == 1:
                    _hit_probe1_lines += 1
            if not line.startswith("bestmove"):
                if _is_scored_info(line) and _RE_DEPTH.search(line):
                    _adj_sm = _RE_SCORE_CP.search(line)
                    if _adj_sm:
                        _adj_score_obs = (move_no, int(_adj_sm.group(1)))
                    else:
                        _adj_sm = _RE_MATE.search(line)
                        if _adj_sm:
                            _adj_score_obs = (
                                move_no,
                                _mate_sign_score(int(_adj_sm.group(1))))
                if _sp_live_active and "dl_live_policy " in line:
                    try:
                        _dl_idx = line.index("dl_live_policy ") + len("dl_live_policy ")
                        _dl_rest = line[_dl_idx:]
                        _dl_tag_match = None
                        if _dl_rest and not _dl_rest.startswith("["):
                            _sp_tag_end = _dl_rest.index(" ")
                            _dl_tag_match = _dl_rest[:_sp_tag_end]
                            _dl_rest = _dl_rest[_sp_tag_end + 1:]
                        _dl_pol = json.loads(_dl_rest)
                        _dl_pos_hash = hashlib.md5(
                            (_sp_live_pos or "").encode()).hexdigest()[:8] if _sp_live_pos else None
                        if _dl_tag_match and _dl_pos_hash and _dl_tag_match == _dl_pos_hash:
                            pass
                        elif _dl_pol and _board is not None:
                            _dl_pol = [(m, s) for (m, s) in _dl_pol
                                       if _bestmove_is_for_board(m, _board)] or None
                        if _dl_pol:
                            _LIVE.update_think_pv(policy=_dl_pol, pos=_sp_live_pos)
                    except Exception:
                        pass
                elif _sp_live_active and _is_scored_info(line):
                    _sp_now = time.perf_counter()
                    if _sp_now - _sp_live_last_emit < 0.2:
                        continue
                    _dm_sp = _RE_DEPTH.search(line)
                    if _dm_sp:
                        _scp_sp = 0
                        _sm_sp = _RE_SCORE_CP.search(line)
                        if _sm_sp:
                            _scp_sp = int(_sm_sp.group(1))
                        else:
                            _mm_sp = _RE_MATE.search(line)
                            if _mm_sp:
                                _scp_sp = _mate_sign_score(int(_mm_sp.group(1)))
                        _pv_sp = None
                        if " pv " in line:
                            _fpv_sp = _RE_PV_FULL.search(line)
                            if _fpv_sp:
                                _pv_sp = _fpv_sp.group(1).split()
                        if _pv_sp:
                            _pv_n_ok = 0
                            try:
                                _pv_wb = _board.clone()
                                for _pv_mv in _pv_sp:
                                    if (_pv_mv in ("resign", "win")
                                            or not _bestmove_is_for_board(_pv_mv, _pv_wb)):
                                        break
                                    _pv_wb.apply_usi(_pv_mv)
                                    _pv_n_ok += 1
                            except Exception as _pv_wexc:
                                _flog("[LIVE-BOARD][SELFPLAY] live pv walk error "
                                      "at %d: %s" % (_pv_n_ok, _pv_wexc))
                            if _pv_n_ok == 0:
                                continue
                            if _pv_n_ok < len(_pv_sp):
                                _flog("[LIVE-BOARD][SELFPLAY] live pv truncated "
                                      "%d/%d (stale tail): head=%r"
                                      % (_pv_n_ok, len(_pv_sp), _pv_sp[0]))
                                _pv_sp = _pv_sp[:_pv_n_ok]
                            _sp_live_fresh = True
                        elif not _sp_live_fresh:
                            continue
                        try:
                            _LIVE.update_think_pv(pv=_pv_sp, score_cp=_scp_sp,
                                                  pos=_sp_live_pos)
                            _sp_live_last_emit = _sp_now
                        except Exception:
                            pass
                continue
            if not _consume_bestmove(line):
                continue
            if (moves and bestmove not in ("resign", "win")
                    and bestmove == moves[-1]):
                _flog("[SP-GEN-DESYNC] duplicate-of-last-move echo — discarded"
                      " (class-independent)")
                bestmove = ""
                _ponder_hint = ""
                continue
            _bm_class = thinker.classify_bestmove()
            _la_rec = getattr(thinker, "_last_rec", None)
            _la_veto = (isinstance(_la_rec, dict)
                        and _la_rec.get("pos_hash")
                        and (_la_rec.get("council_winner") == bestmove
                             or _la_rec.get("bestmove") == bestmove)
                        and _la_rec.get("pos_hash") != _pos_hash8(pos))
            if (_bm_class == "stale" and _wd_reissue_prev_gen is not None
                    and thinker._bm_gen is not None
                    and thinker._bm_gen >= _wd_reissue_prev_gen
                    and thinker._bm_gen <= thinker._go_sent
                    and bestmove not in ("resign", "win")
                    and not (moves and bestmove == moves[-1])
                    and _bestmove_is_for_board(bestmove, _board)
                    and not _la_veto):
                _flog("[SPSA-W][%s] late answer for pre-reissue go adopted "
                      "(gen=%s go_sent=%s)"
                      % (side, thinker._bm_gen, thinker._go_sent))
                _wd_reissue_prev_gen = None
                _bm_class = "current"
            elif _la_veto and _bm_class == "stale" and _wd_reissue_prev_gen is not None:
                _flog("[SPSA-W][%s] late-adopt vetoed: rec pos_hash=%s != want %s "
                      "for %r — leaving stale (bounded drain/reissue)"
                      % (side, _la_rec.get("pos_hash"), _pos_hash8(pos), bestmove))
            if (_bm_class != "current"
                    and bestmove not in ("resign", "win")
                    and _board is not None
                    and _bestmove_is_for_board(bestmove, _board)):
                _ra_rec = getattr(thinker, "_last_rec", None)
                if (isinstance(_ra_rec, dict)
                        and _ra_rec.get("pos_hash")
                        and (_ra_rec.get("council_winner") == bestmove
                             or _ra_rec.get("bestmove") == bestmove)
                        and _ra_rec.get("pos_hash") == _pos_hash8(pos)):
                    _flog("[SPSA-W][%s] [FIX-REC-ADOPT] rec-verified answer "
                          "adopted (class=%s→current pos_hash=%s bm_gen=%s "
                          "go_sent=%s): %r"
                          % (side, _bm_class, _ra_rec.get("pos_hash"),
                             thinker._bm_gen, thinker._go_sent, bestmove))
                    with thinker._send_lock:
                        if thinker._bm_gen is not None:
                            thinker._go_sent = thinker._bm_gen
                        else:
                            thinker._go_sent = thinker._bm_seen
                        thinker._bm_seen = thinker._go_sent
                    _wd_reissue_prev_gen = None
                    _bm_class = "current"
            _ca_rec = getattr(thinker, "_last_rec", None)
            _ca_pos_mismatch = (isinstance(_ca_rec, dict)
                                and _ca_rec.get("pos_hash")
                                and (_ca_rec.get("council_winner") == bestmove
                                     or _ca_rec.get("bestmove") == bestmove)
                                and _ca_rec.get("pos_hash") != _pos_hash8(pos))
            if (_bm_class == "current"
                    and bestmove not in ("resign", "win")
                    and (not _bestmove_is_for_board(bestmove, _board)
                         or _ca_pos_mismatch)):
                _flog("[SPSA-W][%s] current-class bestmove %r drained "
                      "(gen-resync residue; board_illegal=%s pos_hash_mismatch=%s)"
                      % (side, bestmove,
                         not _bestmove_is_for_board(bestmove, _board),
                         bool(_ca_pos_mismatch)))
                bestmove = ""
                _ponder_hint = ""
                continue
            _is_stale = (_bm_class == "stale" or
                         (_bm_class == "unknown"
                          and not _bestmove_is_for_board(bestmove, _board)))
            if _is_stale:
                _stale_miss_reissue_count += 1
                if (not _is_hit_path
                        and _stale_miss_reissue_count > 2
                        and thinker._bm_gen is not None
                        and thinker._bm_gen < thinker._go_sent
                        and move_no >= 2
                        and _bestmove_is_for_board(bestmove, _board)):
                    _sa_rec = getattr(thinker, "_last_rec", None)
                    _sa_veto = (isinstance(_sa_rec, dict)
                                and _sa_rec.get("pos_hash")
                                and (_sa_rec.get("council_winner") == bestmove
                                     or _sa_rec.get("bestmove") == bestmove)
                                and _sa_rec.get("pos_hash") != _pos_hash8(pos))
                    if _sa_veto:
                        _flog("[SP-GEN-DESYNC] stale acceptance vetoed: rec "
                              "pos_hash=%s != want %s for %r — drained instead"
                              % (_sa_rec.get("pos_hash"), _pos_hash8(pos),
                                 bestmove))
                    else:
                        _flog("[SP-GEN-DESYNC] move %d: accepting stale bestmove "
                              "%r after %d stale misses (bm_gen=%s go_sent=%s "
                              "bm_seen=%s) — resyncing gen counters"
                              % (move_no, bestmove, _stale_miss_reissue_count,
                                 thinker._bm_gen, thinker._go_sent,
                                 thinker._bm_seen))
                        with thinker._send_lock:
                            if thinker._bm_gen is not None:
                                thinker._go_sent = thinker._bm_gen
                            else:
                                thinker._go_sent = thinker._bm_seen
                            thinker._bm_seen = thinker._go_sent
                        break
                if _stale_miss_reissue_count > 5:
                    _flog("[SPSA-W][%s] SP-echo miss cap reached (%d>5) — "
                          "stop+flush child residue and abandon main wait "
                          "(class=%s bm=%r)"
                          % (side, _stale_miss_reissue_count, _bm_class,
                             bestmove))
                    if _sp_echo_prev_t is not None:
                        _intervention_ms += (
                            (time.perf_counter() - _sp_echo_prev_t) * 1000.0)
                    try:
                        thinker.send("stop")
                    except Exception:
                        pass
                    try:
                        thinker.flush_until_ready(timeout=5.0)
                    except Exception as _capfe:
                        _flog("[SPSA-W][%s] SP-echo cap flush failed: %s"
                              % (side, _capfe))
                    _infra_intervened = True
                    bestmove = ""
                    _ponder_hint = ""
                    break
                _sp_echo_seen = True
                _flog("[SPSA-W][%s] SP-echo drained%s (class=%s, miss_count=%d): %r"
                      % (side, " on ponderhit" if _is_hit_path else "",
                         _bm_class, _stale_miss_reissue_count, bestmove))
                bestmove = ""
                _ponder_hint = ""
                if _is_hit_path:
                    _flog("[SPSA-W][%s] SP-echo on ponderhit: stale residue "
                          "drained — re-arming hit-watchdog (no immediate "
                          "reissue)" % side)
                    _hit_lines_seen = 0
                    _wd_fresh_seen = False
                    _hit_isready_probed = False
                    _hit_wd_base = time.perf_counter()
                    _hit_wd_base_pre_isready = None
                    continue
                if thinker._go_sent > thinker._bm_seen:
                    _flog("[SPSA-W][%s] SP-echo on miss: outstanding go exists "
                          "(go_sent=%d bm_seen=%d miss_count=%d) — waiting "
                          "for child response instead of reissuing"
                          % (side, thinker._go_sent, thinker._bm_seen,
                             _stale_miss_reissue_count))
                    continue
                _flog("[SPSA-W][%s] SP-echo on miss: child consumed "
                      "go with stale result — reissuing go (miss_count=%d)"
                      % (side, _stale_miss_reissue_count))
                _now = time.perf_counter()
                if _sp_echo_prev_t is not None:
                    _intervention_ms += (_now - _sp_echo_prev_t) * 1000.0
                _sp_echo_prev_t = _now
                _infra_intervened = True
                thinker.send(pos)
                thinker.send(
                    _spsa_build_go_line(tc, btime_ms, wtime_ms))
                _is_hit_path = False
                _rem_s = max(0.05,
                            _main_budget_ms / 1000.0
                            - (_now - _t_think0))
                dl2 = _now + min(
                    _rem_s, max(0.05, deadline - _now))
                continue
            if _bm_class != "current" and bestmove in ("resign", "win") and not _barrier_ok:
                _flog("[SPSA-W][%s] resign/win drained%s as SP-echo "
                      "(class=%s sp_echo_seen=%s barrier_ok=%s): %r"
                      % (side, " on ponderhit" if _is_hit_path else "",
                         _bm_class, _sp_echo_seen, _barrier_ok, bestmove))
                bestmove = ""
                _ponder_hint = ""
                continue
            break

        if not bestmove:
            _thp_chk = _get_proc(thinker)
            _proc_running = not (_thp_chk is not None and _thp_chk.poll() is not None)
            if _proc_running:
                try:
                    thinker.send("stop")
                except Exception as _se:
                    _flog("[SPSA-W][%s] stop send failed (non-fatal): %s" % (side, _se))
                _elapsed_main_s = time.perf_counter() - _t_think0
                _rem_after_main_s = (budget_ms / 1000.0) - _elapsed_main_s
                _ov_s = max(0.05, float(tc.overhead_ms) / 1000.0)
                _rem_to_limit_s = max(
                    0.0, (budget_ms + _stop_cushion_ms) / 1000.0
                         - _elapsed_main_s - 0.05)
                _stop_window = min(_stop_cushion_ms / 1000.0 + 2.0 * _ov_s,
                                   _rem_to_limit_s)
                try:
                    if thinker._go_sent > thinker._bm_seen:
                        _stop_window = max(_stop_window,
                                           min(5.0, _rem_to_limit_s))
                except Exception:
                    pass
                if _stop_window < _ov_s:
                    _stop_window = _ov_s
                _stop_window = min(_stop_window,
                                   max(0.0, deadline - time.perf_counter()))
                if _rem_after_main_s < (2.0 * _ov_s):
                    _flog("[SPSA-W][%s] stop window scaled by budget: "
                          "%.2fs -> %.2fs (budget=%dms main_elapsed=%.0fms cushion=%dms)"
                          % (side, 2.0 * _ov_s, _stop_window, budget_ms,
                             _elapsed_main_s * 1000.0, _stop_cushion_ms))
                _stop_deadline = time.perf_counter() + _stop_window
                while time.perf_counter() < _stop_deadline:
                    _sline = thinker.readline(
                        timeout=max(0.05, _stop_deadline - time.perf_counter()))
                    if _sline is None:
                        _sw_thp = _get_proc(thinker)
                        if _sw_thp is not None and _sw_thp.poll() is not None:
                            break
                        continue
                    if not _sline:
                        continue
                    if not _sline.startswith("bestmove"):
                        continue
                    if not _consume_bestmove(_sline):
                        continue
                    _sw_class = thinker.classify_bestmove()
                    _sw_stale = (_sw_class == "stale" or
                                 (_sw_class == "unknown"
                                  and not _bestmove_is_for_board(bestmove, _board)))
                    if _sw_stale:
                        _sp_echo_seen = True
                        _infra_intervened = True
                        _flog("[SPSA-W][%s] SP-echo drained in stop window "
                              "(class=%s): %r" % (side, _sw_class, bestmove))
                        bestmove = ""
                        _ponder_hint = ""
                        continue
                    if (_sw_class != "current"
                            and bestmove in ("resign", "win")
                            and not _barrier_ok):
                        _flog("[SPSA-W][%s] resign/win drained in stop window as "
                              "SP-echo (class=%s barrier_ok=%s): %r"
                              % (side, _sw_class, _barrier_ok, bestmove))
                        bestmove = ""
                        _ponder_hint = ""
                        continue
                    _flog("[SPSA-W][%s] stop bestmove=%s" % (side, bestmove))
                    break
        if _use_session_fsm:
            _hit_probe_stage = _fsm.probe_stage
            _silence_rescue_fired = (_fsm.probe_stage >= 1)
            _infra_intervened = _infra_intervened or _silence_rescue_fired
        elapsed_ms = int((time.perf_counter() - _t_think0) * 1000)

        if not bestmove:
            _flag_limit = _spb.flag_limit_ms
            _thp = _get_proc(thinker)
            _proc_dead = (_thp is not None and _thp.poll() is not None)
            if _proc_dead:
                _flog("[SPSA-W][%s] no bestmove + process dead (rc=%s) → draw "
                      "(infra noise, not θ's fault)"
                      % (side, getattr(_thp, "returncode", "?")))
                _flog("[SPSA-W][%s] dead diag: elapsed=%dms remaining=%dms "
                      "budget=%dms sp_echo=%s barrier=%s hit_path=%s hit_wd=%d "
                      "thinker=%s pos=%.80s"
                      % (side, elapsed_ms, our_remaining,
                         budget_ms, _sp_echo_seen, _barrier_ok, _is_hit_path,
                         _hit_probe_stage,
                         getattr(thinker, "name", "?"),
                         pos))
                _LIVE.reset()
                print("[!] %s: engine process died — counted as draw" % side, flush=True)
                _kifu("void")
                _fill_info("worker_died", result="draw")
                return "draw"
            if _mute_after_rescue:
                _flog("[SPSA-W][%s] no bestmove and mute after silence-rescue "
                      "(elapsed=%dms) → infra void (silence_mute_void)"
                      % (side, elapsed_ms))
                _LIVE.reset()
                print("[!] %s: mute after rescue — infra void" % side,
                      flush=True)
                try:
                    thinker.preserve_wedge_diag("MUTE")
                except Exception:
                    pass
                _kifu("void")
                _fill_info("silence_mute_void", result="draw")
                return "draw"
            if (elapsed_ms >= _flag_limit and _hit_probe_stage != 2
                    and not _infra_intervened):
                _flog("[SPSA-W][%s] flag fall (no bestmove, elapsed=%dms >= limit=%dms, tc=%s)"
                      % (side, elapsed_ms, _flag_limit, tc.kind))
                _flog("[SPSA-W][%s] flagfall diag: remaining=%dms "
                      "budget=%dms main_budget=%dms cushion=%dms "
                      "main_wait=%.3fs sp_echo=%s barrier=%s hit_path=%s "
                      "hit_wd=%d thinker=%s pos=%.80s"
                      % (side, our_remaining,
                         budget_ms, _main_budget_ms, _stop_cushion_ms,
                         wait_s, _sp_echo_seen, _barrier_ok, _is_hit_path,
                         _hit_probe_stage,
                         getattr(thinker, "name", "?"),
                         pos))
                _LIVE.reset()
                print("[!] %s: time forfeit (持ち時間超過)" % side, flush=True)
                _result = _flag_fall_result()
                _kifu(_result, "flag_fall")
                _fill_info("flag_fall", result=_result)
                return _result
            _flog("[SPSA-W][%s] no bestmove but within budget+cushion "
                  "(alive, elapsed=%dms / limit=%dms) → draw (case ③)"
                  % (side, elapsed_ms, _flag_limit))
            _flog("[SPSA-W][%s] case③ diag: tc=%s remaining=%dms "
                  "budget=%dms main_budget=%dms cushion=%dms "
                  "main_wait=%.3fs sp_echo=%s barrier=%s hit_path=%s "
                  "hit_wd=%d thinker=%s pos=%.80s"
                  % (side, tc.kind, our_remaining,
                     budget_ms, _main_budget_ms, _stop_cushion_ms,
                     wait_s, _sp_echo_seen, _barrier_ok, _is_hit_path,
                     _hit_probe_stage,
                     getattr(thinker, "name", "?"),
                     pos))
            _LIVE.reset()
            print("[!] %s: bestmove timeout (予算内・draw 扱い)" % side, flush=True)
            try:
                thinker.preserve_wedge_diag("CASE3")
            except Exception:
                pass
            _kifu("void")
            _fill_info("bestmove_timeout_within_budget", result="draw")
            return "draw"

        if tc.kind == "fischer":
            if elapsed_ms > our_remaining + tc.inc_ms + tc.overhead_ms + _stop_cushion_ms:
                _flog("[SPSA-W][%s] flag fall (fischer, elapsed=%dms > "
                      "remaining=%dms + inc=%dms + overhead=%dms + cushion=%dms)"
                      % (side, elapsed_ms, our_remaining, tc.inc_ms, tc.overhead_ms, _stop_cushion_ms))
                _LIVE.reset()
                print("[!] %s: time forfeit (持ち時間切れ)" % side, flush=True)
                _result = _flag_fall_result()
                _kifu(_result, "flag_fall")
                _fill_info("flag_fall", result=_result)
                return _result
            new_remaining = max(0, our_remaining + tc.inc_ms - elapsed_ms)
        else:
            over = elapsed_ms - our_remaining
            if over > tc.byoyomi_ms + tc.overhead_ms + _stop_cushion_ms:
                _flog("[SPSA-W][%s] flag fall (byoyomi, elapsed=%dms remaining=%dms byo=%dms cushion=%dms)"
                      % (side, elapsed_ms, our_remaining, tc.byoyomi_ms, _stop_cushion_ms))
                _LIVE.reset()
                print("[!] %s: time forfeit (秒読み切れ)" % side, flush=True)
                _result = _flag_fall_result()
                _kifu(_result, "flag_fall")
                _fill_info("flag_fall", result=_result)
                return _result
            new_remaining = our_remaining - elapsed_ms
            if new_remaining < 0:
                new_remaining = 0
        if is_sente:
            btime_ms = new_remaining
        else:
            wtime_ms = new_remaining

        if bestmove not in ("resign", "win") and not _USI_MOVE_RE.match(bestmove):
            _flog("[SPSA-W][%s] illegal/malformed bestmove %r → draw" % (side, bestmove))
            _LIVE.reset()
            print("[!] %s: illegal move %r — counted as draw (反則負け無効)" % (side, bestmove), flush=True)
            _kifu("void")
            _fill_info("illegal_usi", {"move": bestmove}, result="draw")
            return "draw"
        if (not _fast_first and move_no >= _FAST_BM_MIN_MOVE
                and elapsed_ms < _FAST_BM_THRESHOLD_MS):
            _fast_bm_streak += 1
            if _fast_bm_streak >= _FAST_BM_STREAK_LIMIT:
                _flog("[SPSA-W][%s][FAST-BM] %d consecutive moves in <%dms "
                      "(move %d, elapsed=%dms) — sub-engine likely dead, "
                      "voiding game"
                      % (side, _fast_bm_streak, _FAST_BM_THRESHOLD_MS,
                         move_no + 1, elapsed_ms))
                _LIVE.reset()
                print("[!] %s: abnormal fast response (%d moves in <%dms) "
                      "— sub-engine dead?" % (side, _fast_bm_streak,
                      _FAST_BM_THRESHOLD_MS), flush=True)
                _kifu("void")
                _fill_info("fast_bestmove_void", {
                    "streak": _fast_bm_streak,
                    "threshold_ms": _FAST_BM_THRESHOLD_MS,
                    "move_no": move_no + 1,
                    "elapsed_ms": elapsed_ms}, result="draw")
                return "draw"
        elif elapsed_ms >= _FAST_BM_THRESHOLD_MS:
            _fast_bm_streak = 0
        if bestmove == "resign":
            if (move_no + 1) <= (12 if (_prefix == "startpos" and not _base_moves)
                                 else 6):
                _flog("[SPSA-W][%s][OPENING-RESIGN-GUARD] move %d の投了は構造的に "
                      "異常(谜投了の疑い) — draw 扱いにし SPSA 汚染を回避" % (side, move_no + 1))
                _LIVE.reset()
                print("[!] %s: 序盤投了 (move %d) を異常検出 — draw 化 "
                      "(谜投了の疑い・要 WSL reap 確認)" % (side, move_no + 1), flush=True)
                _kifu("void")
                _fill_info("opening_resign_void", {"move_no": move_no + 1},
                           result="draw")
                return "draw"
            _flog("[SPSA-W][%s] resign (move %d)" % (side, move_no + 1))
            _result = "gote_win" if is_sente else "sente_win"
            _kifu(_result, "resign")
            _fill_info("resign", result=_result)
            return _result
        if bestmove == "win":
            _flog("[SPSA-W][%s] win declaration (move %d)" % (side, move_no + 1))
            _result = "sente_win" if is_sente else "gote_win"
            moves.append(bestmove)
            _kifu(_result, "win_declare")
            moves.pop()
            _fill_info("win_declare", result=_result)
            return _result

        if _board is not None:
            if not _board.is_legal_lite(bestmove):
                _flog("[SPSA-W][%s] is_legal_lite=False for %r "
                      "(board desync diagnostic — move applied anyway)"
                      % (side, bestmove))
            if sennichite_check:
                _check_flags.append(_board.gives_check(bestmove))
            _ja_sp = bestmove
            _board_pre = None
            if _sp_live_active:
                try:
                    _ja_sp = _sr_usi_to_ja(_board, bestmove)
                except Exception:
                    pass
                try:
                    _board_pre = _board.clone()
                except Exception:
                    pass
            _sp_last_ja = _ja_sp
            _board.push(bestmove)
            try:
                _sp_rec = {"source": "selfplay", "council_winner": bestmove,
                           "nnue_bestmove": bestmove}
                _sp_pos_hash_want = _pos_hash8(pos)
                _wo2_rec = getattr(thinker, "_last_rec", None)
                if not (isinstance(_wo2_rec, dict)
                        and _wo2_rec.get("pos_hash") == _sp_pos_hash_want):
                    _wo2_deadline = time.perf_counter() + 0.30
                    _wo2_prefix = "info string pyfa_rec "
                    while time.perf_counter() < _wo2_deadline:
                        try:
                            with thinker._q.mutex:
                                _wo2_snap = list(thinker._q.queue)
                        except Exception:
                            break
                        _wo2_hit = None
                        for _wo2_ln in _wo2_snap:
                            if (isinstance(_wo2_ln, str)
                                    and _wo2_ln.startswith(_wo2_prefix)):
                                try:
                                    _wo2_cand = json.loads(
                                        _wo2_ln[len(_wo2_prefix):])
                                except (json.JSONDecodeError, ValueError):
                                    continue
                                if _wo2_cand.get("pos_hash") == _sp_pos_hash_want:
                                    _wo2_hit = _wo2_cand
                        if _wo2_hit is not None:
                            _wo2_rec = _wo2_hit
                            break
                        time.sleep(0.01)
                _wo2_used = False
                if isinstance(_wo2_rec, dict):
                    _wo2_ph = _wo2_rec.get("pos_hash")
                    if _wo2_ph and _wo2_ph == _sp_pos_hash_want:
                        _sp_rec = dict(_wo2_rec)
                        _sp_rec["_orig_source"] = _sp_rec.get("source")
                        _sp_rec["source"] = "selfplay"
                        _sp_rec.setdefault("council_winner", bestmove)
                        if "nnue_bestmove" not in _sp_rec:
                            _flog("[SETTLE-CARRY] nnue_bestmove not in pyfa_rec — "
                                  "falling back to bestmove (emit gap?) "
                                  "source=%s handler=%s ply=%s"
                                  % (_sp_rec.get("_orig_source", "?"),
                                     _sp_rec.get("handler", "?"),
                                     move_no))
                            _sp_rec["nnue_bestmove"] = bestmove
                        _wo2_used = True
                        _flog("[LIVE-BOARD][SELFPLAY] stats loaded via pyfa_rec: "
                              "conf=%s shrp=%s mom=%s"
                              % (("%.2f" % _sp_rec["confidence"]) if isinstance(_sp_rec.get("confidence"), (int, float)) else "—",
                                 ("%.2f" % _sp_rec["sharpness"]) if isinstance(_sp_rec.get("sharpness"), (int, float)) else "—",
                                 ("%.2f" % _sp_rec["momentum"]) if isinstance(_sp_rec.get("momentum"), (int, float)) else "—"))
                thinker._last_rec = None
                if not _wo2_used:
                    _sp_stats = getattr(thinker, "_stats_path", None) if _sp_live_active else None
                    if _sp_stats and os.path.isfile(_sp_stats):
                        try:
                            _sp_ply_want = _count_moves(pos)
                            _sp_ply_warned = False
                            for _sp_poll in range(80):
                                _sp_candidates = []
                                try:
                                    with open(_sp_stats, "rb") as _sf_b:
                                        _sf_b.seek(0, 2)
                                        _fsize = _sf_b.tell()
                                        _sf_b.seek(max(0, _fsize - 65536))
                                        _tail = _sf_b.read().decode("utf-8", errors="replace")
                                    for _sln in _tail.splitlines():
                                        _sln = _sln.strip()
                                        if _sln and not _sln.startswith("#") and _sln.endswith("}"):
                                            _sp_candidates.append(_sln)
                                except Exception:
                                    pass
                                _sp_found = False
                                for _sln in reversed(_sp_candidates[-20:]):
                                    try:
                                        _sp_cand = json.loads(_sln)
                                    except (json.JSONDecodeError, ValueError):
                                        continue
                                    _sp_cand_mv = (_sp_cand.get("council_winner")
                                                   or _sp_cand.get("bestmove"))
                                    if _sp_cand_mv != bestmove:
                                        continue
                                    _ph = _sp_cand.get("pos_hash")
                                    if _ph and _ph == _sp_pos_hash_want:
                                        _sp_rec = _sp_cand
                                        _sp_found = True
                                        break
                                    if _sp_cand.get("ply") == _sp_ply_want:
                                        _sp_rec = _sp_cand
                                        _sp_found = True
                                        break
                                    if not _sp_ply_warned:
                                        _sp_ply_warned = True
                                        _flog("[LIVE-BOARD][SELFPLAY] stale rec "
                                              "rejected: winner=%s rec_ply=%s "
                                              "want=%d — fresh rec を待機"
                                              % (bestmove, _sp_cand.get("ply"),
                                                 _sp_ply_want))
                                if _sp_found:
                                    break
                                time.sleep(0.01)
                            _sp_rec["_orig_source"] = _sp_rec.get("source")
                            _sp_rec["source"] = "selfplay"
                            _flog("[LIVE-BOARD][SELFPLAY] stats loaded (file fallback): src=%s "
                                  "conf=%s shrp=%s mom=%s"
                                  % (_sp_rec.get("_orig_source"),
                                     ("%.2f" % _sp_rec["confidence"]) if isinstance(_sp_rec.get("confidence"), (int, float)) else "—",
                                     ("%.2f" % _sp_rec["sharpness"]) if isinstance(_sp_rec.get("sharpness"), (int, float)) else "—",
                                     ("%.2f" % _sp_rec["momentum"]) if isinstance(_sp_rec.get("momentum"), (int, float)) else "—"))
                        except Exception as _sp_stats_err:
                            _flog("[LIVE-BOARD][SELFPLAY] stats read error: %s" % _sp_stats_err)
                _sp_premoves = _base_moves + moves
                _sp_pos = "position " + _prefix + (
                    (" moves " + " ".join(_sp_premoves)) if _sp_premoves else "")
                _sp_pv = None
                _sp_pv_raw = _sp_rec.get("nnue_pv")
                if isinstance(_sp_pv_raw, str) and _sp_pv_raw.strip():
                    _sp_pv = _sp_pv_raw.split()
                else:
                    _sp_dl1 = _sp_rec.get("dl_1_pv")
                    if isinstance(_sp_dl1, list) and _sp_dl1:
                        _sp_pv = _sp_dl1
                _sp_policy = _sp_rec.get("dl_display_policy")
                if isinstance(_sp_policy, list):
                    _sp_policy = [(m, s) for m, s in _sp_policy] if _sp_policy else None
                else:
                    _sp_policy = None
                _sp_mode = None
                _sp_gp = _sp_rec.get("game_phase")
                if isinstance(_sp_gp, (int, float)) and _sp_gp >= 0.85:
                    _sp_mode = "endgame"
                if _sp_pv and _board_pre is not None:
                    _sp_wb = _board_pre.clone()
                    _sp_ok = 0
                    for _sp_mv in _sp_pv:
                        if (_sp_mv in ("resign", "win")
                                or not _bestmove_is_for_board(_sp_mv, _sp_wb)):
                            break
                        _sp_wb.apply_usi(_sp_mv)
                        _sp_ok += 1
                    if _sp_ok == 0:
                        _flog("[LIVE-BOARD][SELFPLAY] stale pv dropped: %r "
                              "(move=%s)" % (_sp_pv[0], bestmove))
                        _sp_pv = None
                    elif _sp_ok < len(_sp_pv):
                        _flog("[LIVE-BOARD][SELFPLAY] stale pv tail truncated: "
                              "%d/%d kept (head=%r move=%s)"
                              % (_sp_ok, len(_sp_pv), _sp_pv[0], bestmove))
                        _sp_pv = _sp_pv[:_sp_ok]
                if _sp_policy and _board_pre is not None:
                    _sp_policy = [(m, s) for (m, s) in _sp_policy
                                  if _bestmove_is_for_board(m, _board_pre)] or None
                _LIVE.set_think(_sp_rec, _sp_pos, _sp_policy, _sp_pv, None,
                               mode=_sp_mode)
                _sp_wr = None
                _sp_wr_raw = _sp_rec.get("council_wr_nnue")
                if isinstance(_sp_wr_raw, (int, float)):
                    _sp_wr = (_sp_wr_raw if is_sente else (1.0 - _sp_wr_raw)) * 100.0
                elif _sp_rec.get("nnue_score_cp") is not None:
                    _sp_cp = _sp_rec["nnue_score_cp"]
                    _sp_wr_f = _cp_to_winrate(_sp_cp, _SR_WR_SLOPE)
                    _sp_wr = (_sp_wr_f if is_sente else (1.0 - _sp_wr_f)) * 100.0
                if _sp_wr is None and isinstance(_last_wr_sente, (int, float)):
                    _sp_wr = float(_last_wr_sente) * 100.0
                _LIVE.show(_board, move_no=_sp_move_base + move_no + 1,
                           last_move=_ja_sp,
                           winrate=_sp_wr,
                           sente_time=_sr_fmt_clock(btime_ms),
                           gote_time=_sr_fmt_clock(wtime_ms))
                _zenrei_live_push(_board)
                _LIVE.start_clock(_board, btime_ms, wtime_ms,
                                  active_sente=(not is_sente),
                                  move_no=_sp_move_base + move_no + 1,
                                  last_move=_ja_sp,
                                  winrate=_sp_wr)
            except (KeyboardInterrupt, SystemExit, MemoryError):
                raise
            except Exception:
                _flog("[LIVE-BOARD][SELFPLAY] render error:\n"
                      + _safe_format_exc().strip())
            _w = None
            if isinstance(_sp_rec, dict):
                _w = _sp_rec.get("council_wr_nnue")
                if not isinstance(_w, (int, float)) and _sp_rec.get("nnue_score_cp") is not None:
                    _w = _cp_to_winrate(_sp_rec["nnue_score_cp"], _SR_WR_SLOPE)
            if _w is None and _adj_score_obs is not None and _adj_score_obs[0] == move_no:
                _w = _cp_to_winrate(_adj_score_obs[1], _SR_WR_SLOPE)
            if isinstance(_w, (int, float)):
                _last_wr_sente = float(_w) if is_sente else 1.0 - float(_w)
            if sennichite_check and _board.is_sennichite():
                moves.append(bestmove)
                _verdict, _parity = _sprt_sennichite_verdict_core(
                    _board._history, _check_flags)
                if _verdict == "perpetual":
                    _checker_is_sente = (_start_is_sente == (_parity == 0))
                    _result = "gote_win" if _checker_is_sente else "sente_win"
                    _flog("[SPSA-W] perpetual-check sennichite → %s loses (move %d)"
                          % ("sente" if _checker_is_sente else "gote", move_no + 1))
                    _msg = ("[!] 連続王手の千日手 — %s の負け"
                            % ("先手" if _checker_is_sente else "後手"))
                    if _sp_live_active and hasattr(_LIVE, "safe_print"):
                        _LIVE.safe_print(_msg)
                    else:
                        print(_msg, flush=True)
                    _LIVE.reset()
                    _kifu(_result, "perpetual_check")
                    _fill_info("perpetual_check", {"sennichite": True},
                               result=_result)
                    return _result
                _flog("[SPSA-W] sennichite (4-fold) → gote win (move %d)" % (move_no + 1))
                _msg4 = "[!] 千日手 (同一局面4回) — 後手の勝ち"
                if _sp_live_active and hasattr(_LIVE, "safe_print"):
                    _LIVE.safe_print(_msg4)
                else:
                    print(_msg4, flush=True)
                _LIVE.reset()
                _kifu("draw", "sennichite")
                _fill_info("sennichite", {"sennichite": True},
                           result="gote_win")
                return "gote_win"

        moves.append(bestmove)

        if is_sente:
            _adj_wr_nnue = None
            _adj_wr_dl = None
            if isinstance(_sp_rec, dict):
                _adj_v = _sp_rec.get("council_wr_nnue")
                if isinstance(_adj_v, (int, float)):
                    _adj_wr_nnue = float(_adj_v)
                elif _sp_rec.get("nnue_score_cp") is not None:
                    try:
                        _adj_wr_nnue = float(_cp_to_winrate(
                            _sp_rec["nnue_score_cp"], _SR_WR_SLOPE))
                    except Exception:
                        _adj_wr_nnue = None
                _adj_v = _sp_rec.get("council_wr_dl")
                if isinstance(_adj_v, (int, float)):
                    _adj_wr_dl = float(_adj_v)
            if (_adj_wr_nnue is None and _adj_score_obs is not None
                    and _adj_score_obs[0] == move_no):
                try:
                    _adj_wr_nnue = float(_cp_to_winrate(
                        _adj_score_obs[1], _SR_WR_SLOPE))
                except Exception:
                    _adj_wr_nnue = None
            _adj_dir = None
            if _adj_wr_nnue is not None and _adj_wr_dl is not None:
                if _adj_wr_nnue >= _ADJ_WR_TH and _adj_wr_dl >= _ADJ_WR_TH:
                    _adj_dir = "sente"
                elif (_adj_wr_nnue <= (1.0 - _ADJ_WR_TH)
                      and _adj_wr_dl <= (1.0 - _ADJ_WR_TH)):
                    _adj_dir = "gote"
                else:
                    _adj_dir = "none"
            elif _adj_wr_nnue is not None:
                if _adj_wr_nnue >= _ADJ_WR_TH:
                    _adj_dir = "sente"
                elif _adj_wr_nnue <= (1.0 - _ADJ_WR_TH):
                    _adj_dir = "gote"
                else:
                    _adj_dir = "none"
            if _adj_dir is None:
                _adj_streak_sente = 0
                _adj_streak_gote = 0
            elif _adj_dir in ("sente", "gote"):
                _adj_is_consecutive = (
                    _adj_last_obs_move is not None
                    and _adj_last_obs_move == move_no - 2)
                if _adj_dir == "sente":
                    if _adj_is_consecutive and _adj_streak_gote == 0:
                        _adj_streak_sente += 1
                    else:
                        _adj_streak_sente = 1
                    _adj_streak_gote = 0
                else:
                    if _adj_is_consecutive and _adj_streak_sente == 0:
                        _adj_streak_gote += 1
                    else:
                        _adj_streak_gote = 1
                    _adj_streak_sente = 0
                _adj_last_obs_move = move_no
            elif _adj_dir == "none":
                _adj_streak_sente = 0
                _adj_streak_gote = 0
                _adj_last_obs_move = move_no
            if _adj_streak_sente >= 2 or _adj_streak_gote >= 2:
                _result = ("sente_win" if _adj_streak_sente >= 2
                           else "gote_win")
                _flog("[SPSA-W][ADJUDICATE] move %d: wr_nnue=%s wr_dl=%s "
                      "(streak s=%d g=%d prev_obs=%s th=%.0f%%) → %s"
                      % (move_no + 1,
                         ("%.3f" % _adj_wr_nnue) if _adj_wr_nnue is not None else "—",
                         ("%.3f" % _adj_wr_dl) if _adj_wr_dl is not None else "—",
                         _adj_streak_sente, _adj_streak_gote,
                         (_adj_last_obs_move + 1) if _adj_last_obs_move is not None else "—",
                         _ADJ_WR_TH * 100, _result))
                print("[!] 形勢判定終局 (move %d): %s"
                      % (move_no + 1,
                         "先手勝ち" if _result == "sente_win" else "後手勝ち"),
                      flush=True)
                _LIVE.reset()
                _kifu(_result, "adjudication")
                _fill_info("adjudication", {
                    "wr_nnue": _adj_wr_nnue, "wr_dl": _adj_wr_dl,
                    "move_no": move_no + 1}, result=_result)
                return _result

        if _hit_probe_stage == 2 or _silence_rescue_fired:
            if not thinker.flush_with_stop(timeout=5.0):
                _flog("[SPSA-W][%s] hit-watchdog: post-move barrier incomplete "
                      "(%s) — 残骸は次の flush/watchdog に委ねる"
                      % (side, getattr(thinker, "name", "?")))

        if (_ponder_on and tc.main_ms > 0 and _ponder_hint and move_no + 1 < 512
                and getattr(thinker, "_ponder_capable", True)
                and _USI_MOVE_RE.match(_ponder_hint)):
            _ppos = ("position " + _prefix + " moves "
                     + " ".join(_base_moves + moves + [_ponder_hint]))
            _pgl = _spsa_build_go_line(tc, btime_ms, wtime_ms)
            thinker.send(_ppos)
            thinker.send("go ponder" + _pgl[2:])
            _ponder_map[thinker] = (_ponder_hint, _ponder_predicted_key(_board, _ponder_hint))

      _flog("[SPSA-W] draw by move limit")
      _kifu("draw", "move_limit")
      _fill_info("move_limit", result="draw")
      return "draw"
    finally:
        for _eng in (eng_sente, eng_gote):
            try:
                if _eng_alive(_eng) and _eng in _ponder_map:
                    _eng.send("stop")
            except (KeyboardInterrupt, SystemExit, MemoryError):
                raise
            except Exception as _se:
                _flog(f"[PNDR-PARALLEL-STOP] preempt send failed for "
                      f"{getattr(_eng, 'name', '?')}: {_se!r}")
        _ponder_halt(eng_sente)
        _ponder_halt(eng_gote)
        if _ponder_on and (_ponder_hits or _ponder_miss):
            _tot = _ponder_hits + _ponder_miss
            _flog("[SPSA-W][PNDR] ponder hit %d/%d (%.0f%%)"
                  % (_ponder_hits, _tot, 100.0 * _ponder_hits / _tot))


def _spsa_game_plan_core(global_game_idx: int, n_tc: int,
                         swap_colors: bool = True, tc_shuffle_seed: int = 0):
    _g = int(global_game_idx)
    _n = max(1, int(n_tc))
    tc_idx = _g % _n
    if tc_shuffle_seed > 0 and _n > 1:
        _round = _g // _n
        _perm = list(range(_n))
        import random as _rnd_tc
        _rnd_tc.Random(tc_shuffle_seed + _round).shuffle(_perm)
        tc_idx = _perm[tc_idx]
    swap = swap_colors and (((_g // _n) + tc_idx) % 2 == 1)
    return swap, tc_idx


_SPSA_WSL_SUSPECT = {"flag": False}


def _spsa_wsl_bridge_in_use() -> bool:
    for _wb_p in {nnue_1_PATH, nnue_2_PATH}:
        try:
            if (_wb_p and os.path.splitext(_wb_p)[1].lower()
                    in (".bat", ".cmd") and os.path.isfile(_wb_p)
                    and "wsl" in open(_wb_p, "r", encoding="utf-8",
                                      errors="replace").read().lower()):
                return True
        except Exception:
            continue
    return False


def _spsa_wsl_health_reset(caller: str = "[FIX-WSL-CLEAN]") -> bool:
    if not _spsa_wsl_bridge_in_use():
        _flog("%s nnue に WSL bridge なし — shutdown/probe スキップ" % caller)
        return True
    _wsl_ok = (_hp_run(["wsl", "-e", "true"], 10)[0] == 0)
    if _wsl_ok:
        _sd_rc, _ = _hp_run(["wsl", "--shutdown"], 30)
        _flog("%s wsl --shutdown rc=%s (clean slate)" % (caller, _sd_rc))
        _wsl_ok = False
        _rdy_end = time.monotonic() + 60.0
        _rdy_n = 0
        while time.monotonic() < _rdy_end:
            _rdy_n += 1
            if _hp_run(["wsl", "-e", "true"], 20)[0] == 0:
                _wsl_ok = True
                break
            time.sleep(2.0)
        _flog("[FIX-WSL-READY] shutdown 後の VM 復帰 %s (probe=%d)"
              % ("OK" if _wsl_ok else "未確認", _rdy_n))
    else:
        _flog("%s wsl 無応答 — wslservice wedge 疑い。"
              "shutdown はスキップし自己修復を試行" % caller)
        _hp_run(["taskkill", "/F", "/IM", "wsl.exe"], 15)
        _rs_rc, _ = _hp_run(
            ["powershell", "-NoProfile", "-Command",
             "Restart-Service -Name WSLService -Force"], 45)
        _flog("[FIX-WSL-HEAL] WSLService restart rc=%s" % (_rs_rc,))
        _wsl_ok = (_hp_run(["wsl", "-e", "true"], 30)[0] == 0)
        _flog("[FIX-WSL-HEAL] 修復後 probe: %s" % ("OK" if _wsl_ok else "NG"))
    return _wsl_ok


def _spsa_builtin_worker(
    config_plus:  str,
    config_minus: str,
    stats_plus:   str,
    stats_minus:  str,
    games_per_iter: int   = 2,
    swap_colors:    bool  = True,
    timeout_s:      float = 1800.0,
    game_offset:    int   = 0,
    _caller_manages_loop: bool = False,
) -> bool | None:
    if not _caller_manages_loop:
        games_per_iter = int(os.environ.get("SPSA_GAMES", str(games_per_iter)))
    game_timeout_s = timeout_s / max(games_per_iter, 1)

    _tc_specs = _spsa_parse_tc_spec()
    _tc_shuffle_seed = int(os.environ.get("SPSA_TC_SHUFFLE_SEED", "0"))
    _flog("[SPSA-W] TC specs (%d): %s  shuffle_seed=%d" % (
        len(_tc_specs), ", ".join(t.label for t in _tc_specs), _tc_shuffle_seed))

    plus_wins = minus_wins = 0

    _sente_losses = {"plus": 0, "minus": 0}
    _total_losses = {"plus": 0, "minus": 0}

    if _SPSA_WSL_SUSPECT["flag"]:
        _SPSA_WSL_SUSPECT["flag"] = False
        _flog("[SPSA-W][FIX-WSL-ITER-RESET] 前 iteration がエンジン死で終了 — "
              "worker 起動前に WSL 健全化を実行")
        if not _spsa_wsl_health_reset(caller="[SPSA-W]"):
            _flog("[SPSA-W] WSL 復旧不能 — init を試みず iteration を中止")
            _SPSA_WSL_SUSPECT["flag"] = True
            return None

    eng_plus = _SpsaUsiEngine(config_plus, stats_plus, "plus")
    eng_minus = _SpsaUsiEngine(config_minus, stats_minus, "minus")

    _init_ok = [False, False]
    def _init_p():
        _init_ok[0] = _spsa_init_engine(eng_plus)
    def _init_m():
        _init_ok[1] = _spsa_init_engine(eng_minus)
    _ti_p = threading.Thread(target=_init_p, daemon=True, name="spsa-init-p")
    _ti_m = threading.Thread(target=_init_m, daemon=True, name="spsa-init-m")
    _ti_p.start(); _ti_m.start()
    _ti_p.join(); _ti_m.join()
    if not all(_init_ok):
        _flog("[SPSA-W] init failed → skip all games")
        _LIVE.reset()
        print("[!] engine init failed — skipping iteration", flush=True)
        _qi_p = threading.Thread(target=eng_plus.quit, daemon=True, name="spsa-qi-p")
        _qi_m = threading.Thread(target=eng_minus.quit, daemon=True, name="spsa-qi-m")
        _qi_p.start(); _qi_m.start()
        _qi_p.join(timeout=20.0); _qi_m.join(timeout=20.0)
        for _qi, _eng in ((_qi_p, eng_plus), (_qi_m, eng_minus)):
            if _qi.is_alive():
                try:
                    _spsa_kill_proc_tree(getattr(_eng, "proc", None))
                except Exception:
                    pass
            try:
                _eng._wsl_reap()
            except Exception:
                pass
        _SPSA_WSL_SUSPECT["flag"] = True
        return None

    _engine_dead = False
    _consecutive_void = 0
    _VOID_CIRCUIT_LIMIT = 4
    for game_idx in range(games_per_iter):
        _g_global = game_offset + game_idx
        swap, _tc_idx = _spsa_game_plan_core(
            _g_global, len(_tc_specs), swap_colors, tc_shuffle_seed=_tc_shuffle_seed)
        eng_s = eng_minus if swap else eng_plus
        eng_g = eng_plus  if swap else eng_minus
        s_lbl = "minus"   if swap else "plus"
        g_lbl = "plus"    if swap else "minus"
        _tc_game = _tc_specs[_tc_idx]

        if game_idx > 0:
            if _engine_dead:
                _flog("[SPSA-W] engine dead from previous game — skip remaining")
                break
            eng_plus.send("usinewgame")
            eng_minus.send("usinewgame")
            for _sge in (eng_plus, eng_minus):
                _sge._go_sent = 0
                _sge._bm_seen = 0
                _sge._bm_arrived = 0
                _sge._last_ack_gen = None
                _sge._bm_gen = None
                _sge._last_rec = None
                _sge._last_drained_bm = None
                _sge._dup_drained_bm = False
            _ig_ok = [False, False]
            def _ig_flush(_idx, _eng):
                if _eng.flush_until_ready(timeout=30.0):
                    _ig_ok[_idx] = True
                    return
                _flog("[SPSA-W] inter-game flush failed (%s) — "
                      "restarting before next game"
                      % getattr(_eng, "name", "?"))
                if _eng.restart():
                    _eng.send("usinewgame")
                    _ig_ok[_idx] = True
                else:
                    _flog("[SPSA-W] inter-game restart failed (%s) — "
                          "skip remaining" % getattr(_eng, "name", "?"))
            _ig_tp = threading.Thread(target=_ig_flush, args=(0, eng_plus),
                                      daemon=True, name="ig-flush-p")
            _ig_tm = threading.Thread(target=_ig_flush, args=(1, eng_minus),
                                      daemon=True, name="ig-flush-m")
            _ig_tp.start(); _ig_tm.start()
            _ig_tp.join(); _ig_tm.join()
            if not all(_ig_ok):
                _engine_dead = True
            if _engine_dead:
                break

        _INFRA_REASONS = _SPSA_INFRA_VOID_REASONS
        for _attempt in range(2):
            _ginfo: dict = {}
            result = _selfplay_game(eng_s, eng_g,
                                     game_timeout_s=game_timeout_s,
                                     tc=_tc_game, info=_ginfo,
                                     opening=_selfplay_opening())
            _flog("[SPSA-W]   → %s (reason=%s attempt=%d)"
                  % (result, _ginfo.get("reason"), _attempt))
            _send_gameover(eng_s, eng_g, result)
            if not (result == "draw"
                    and _ginfo.get("reason") in _INFRA_REASONS):
                break
            if _attempt == 0:
                _flog("[SPSA-W] infra-void game (reason=%s) — recover engines "
                      "and replay once" % _ginfo.get("reason"))
                _force_restart = _ginfo.get("reason") in (
                    "fast_bestmove_void", "silence_mute_void",
                    "time_loss_infra_void")
                _re_ok = [False, False]
                def _re_flush(_idx, _eng):
                    _need_restart = _force_restart
                    if not _need_restart:
                        if not _eng.flush_until_ready(timeout=30.0):
                            _need_restart = True
                        elif getattr(_eng, "_dup_drained_bm", False):
                            _flog("[SPSA-W][%s] same bestmove re-drained across "
                                  "consecutive flushes — wedged child suspected, "
                                  "forcing restart"
                                  % getattr(_eng, "name", "?"))
                            _need_restart = True
                    if _need_restart and not _eng.restart():
                        return
                    _eng._go_sent = 0
                    _eng._bm_seen = 0
                    _eng._bm_arrived = 0
                    _eng._last_ack_gen = None
                    _eng._bm_gen = None
                    _eng._last_rec = None
                    _eng._last_drained_bm = None
                    _eng._dup_drained_bm = False
                    _eng.send("usinewgame")
                    _re_ok[_idx] = True
                _re_tp = threading.Thread(target=_re_flush, args=(0, eng_plus),
                                          daemon=True, name="re-flush-p")
                _re_tm = threading.Thread(target=_re_flush, args=(1, eng_minus),
                                          daemon=True, name="re-flush-m")
                _re_tp.start(); _re_tm.start()
                _re_tp.join(); _re_tm.join()
                if not all(_re_ok):
                    _engine_dead = True
                if _engine_dead:
                    break

        if (result == "draw"
                and _ginfo.get("reason") in _INFRA_REASONS):
            _consecutive_void += 1
            if _consecutive_void >= _VOID_CIRCUIT_LIMIT:
                _flog("[SPSA-W][CIRCUIT-BREAKER] %d consecutive infra-void "
                      "draws — engine unrecoverable, aborting iteration"
                      % _consecutive_void)
                _engine_dead = True
                break
        else:
            _consecutive_void = 0

        if result == "sente_win":
            if s_lbl == "plus": plus_wins  += 1
            else:               minus_wins += 1
        elif result == "gote_win":
            if g_lbl == "plus": plus_wins  += 1
            else:               minus_wins += 1

        _loser_lbl = None
        if result == "sente_win":
            _loser_lbl = g_lbl
        elif result == "gote_win":
            _loser_lbl = s_lbl
            _sente_losses[s_lbl] += 1
        if _loser_lbl is not None:
            _total_losses[_loser_lbl] += 1
            if _sente_losses[_loser_lbl] >= 2:
                _remaining = games_per_iter - (game_idx + 1)
                if _loser_lbl == "plus":
                    minus_wins += _remaining
                    if minus_wins <= plus_wins:
                        minus_wins = plus_wins + 1
                else:
                    plus_wins += _remaining
                    if plus_wins <= minus_wins:
                        plus_wins = minus_wins + 1
                _flog("[SPSA-W][EARLY-STOP] %s lost 2 games as SENTE — "
                      "adjudicated LOSS (remaining %d game(s) forfeited) "
                      "→ next iteration" % (_loser_lbl, _remaining))
                break
            if _total_losses[_loser_lbl] >= 4:
                _flog("[SPSA-W][EARLY-STOP] %s reached 4 losses (any color) "
                      "→ next iteration" % _loser_lbl)
                break

        _pp = getattr(eng_plus, "proc", None)
        _pm = getattr(eng_minus, "proc", None)
        if (_pp is not None and _pp.poll() is not None) or \
           (_pm is not None and _pm.poll() is not None):
            _engine_dead = True

    if _engine_dead:
        _SPSA_WSL_SUSPECT["flag"] = True

    _t_quit = time.perf_counter()
    _quit_engines(eng_plus, eng_minus, label="SPSA-W")
    _dur_update_quit("spsa-worker", (time.perf_counter() - _t_quit) / 2.0)

    _flog("[SPSA-W] match: plus=%d minus=%d" % (plus_wins, minus_wins))
    return (plus_wins, minus_wins)


def _spsa_salvage_stats(src_path: str, side: str, game_idx: int = -1,
                        dest_path: str = "") -> None:
    try:
        if not src_path or not os.path.exists(src_path):
            return
        _dst = dest_path or os.path.join(_BASE_DIR, "stats.txt")
        _kept = []
        with open(src_path, encoding="utf-8", errors="replace") as _f:
            for _raw in _f:
                _raw = _raw.strip()
                if not _raw:
                    continue
                try:
                    _rec = json.loads(_raw)
                except json.JSONDecodeError:
                    continue
                if not (isinstance(_rec, dict) and "moves" in _rec):
                    continue
                _rec["spsa_side"] = side
                _rts = _rec.get("ts")
                try:
                    if isinstance(_rts, str):
                        _rts = time.mktime(
                            time.strptime(_rts, "%Y-%m-%dT%H:%M:%S"))
                except Exception:
                    _rts = None
                if (isinstance(_rts, (int, float)) and _SPSA_VOID_MARKS
                        and any(abs(_rts - _vm) <= 10.0
                                for _vm in _SPSA_VOID_MARKS)):
                    _rec["infra_void"] = True
                if game_idx >= 0:
                    _rec["spsa_game_idx"] = game_idx + len(_kept)
                _kept.append(json.dumps(_rec, ensure_ascii=False))
        if not _kept:
            _flog("[STATS-SALVAGE] %s: 0 game record(s) — child never wrote "
                  "a summary (wedge/kill?)" % side)
            return
        _atomic_append(_dst, "\n".join(_kept) + "\n", lock=_stats_write_lock)
        _flog("[STATS-SALVAGE] %s: %d game record(s) → %s"
              % (side, len(_kept), os.path.basename(_dst)))
    except (KeyboardInterrupt, SystemExit, MemoryError):
        raise
    except Exception as _se:
        _flog("[STATS-SALVAGE] failed (%s, non-fatal): %r" % (side, _se))


def _spsa_run_match(cfg_plus: dict, cfg_minus: dict, match_cmd: str | None = None,
                    timeout_s: float = 1800.0,
                    game_idx: int = 0,
                    games_per_iter: int = 1) -> bool | None:
    import tempfile as _tmpmod2
    _match_tmpdir = _tmpmod2.mkdtemp(prefix="spsa_match_")
    stats_plus = stats_minus = ""
    _g_salvage: list = []
    _SPSA_RUNNER_ACTIVE[0] = True
    try:
        plus_path  = os.path.join(_match_tmpdir, "cfg_plus.json")
        minus_path = os.path.join(_match_tmpdir, "cfg_minus.json")
        stats_plus  = os.path.join(_match_tmpdir, "stats_plus.jsonl")
        stats_minus = os.path.join(_match_tmpdir, "stats_minus.jsonl")

        def _write_temp_cfg(path, cfg_dict):
            with open(path, "w", encoding="utf-8") as f:
                json.dump(cfg_dict, f, indent=2, ensure_ascii=False)
                f.write("\n")

        try:
            _write_temp_cfg(plus_path, cfg_plus)
            _write_temp_cfg(minus_path, cfg_minus)
        except Exception as e:
            _flog("[SPSA-MATCH] config write error: %s" % e)
            _LIVE.reset()
            print("[!] SPSA: config write error: %s" % e, flush=True)
            return None

        env = os.environ.copy()
        env["SPSA_CONFIG_PLUS"]  = plus_path
        env["SPSA_CONFIG_MINUS"] = minus_path
        env["SPSA_STATS_PLUS"]   = stats_plus
        env["SPSA_STATS_MINUS"]  = stats_minus
        env["SPSA_GAME_IDX"]     = str(game_idx)

        if match_cmd is None:
            import math as _math_d1
            _spsa_groups = int(os.environ.get("SPSA_PARALLEL_GROUPS", "1"))
            if _spsa_groups < 1:
                _spsa_groups = 1
            if _spsa_groups == 1:
                _flog("[SPSA-MATCH] no match_cmd → using built-in worker")
                _bw_ret = _spsa_builtin_worker(
                    plus_path, minus_path, stats_plus, stats_minus,
                    games_per_iter=games_per_iter,
                    timeout_s=timeout_s,
                    game_offset=game_idx,
                    _caller_manages_loop=True,
                )
                _pw, _mw = _bw_ret if _bw_ret is not None else (0, 0)
            else:
                _flog("[SPSA-MATCH] parallel groups=%d games=%d"
                      % (_spsa_groups, games_per_iter))
                _g_size = _math_d1.ceil(games_per_iter / _spsa_groups)
                _g_results: list[tuple[int, int]] = [(0, 0)] * _spsa_groups
                def _run_spsa_group(_gi):
                    _g_games = min(_g_size, games_per_iter - _gi * _g_size)
                    if _g_games <= 0:
                        return
                    _g_sp = os.path.join(_match_tmpdir, "stats_plus_g%d.jsonl" % _gi)
                    _g_sm = os.path.join(_match_tmpdir, "stats_minus_g%d.jsonl" % _gi)
                    _g_off = game_idx + _gi * _g_size
                    _g_salvage.append((_g_sp, "plus", _g_off))
                    _g_salvage.append((_g_sm, "minus", _g_off))
                    _g_ret = _spsa_builtin_worker(
                        plus_path, minus_path, _g_sp, _g_sm,
                        games_per_iter=_g_games,
                        timeout_s=timeout_s,
                        game_offset=_g_off,
                        _caller_manages_loop=True,
                    )
                    _g_results[_gi] = _g_ret if _g_ret is not None else (0, 0)
                _g_threads = []
                for _gi in range(_spsa_groups):
                    _gt = threading.Thread(target=_run_spsa_group, args=(_gi,),
                                           daemon=True, name="spsa-g%d" % _gi)
                    _g_threads.append(_gt)
                for _gt in _g_threads:
                    _gt.start()
                for _gt in _g_threads:
                    _gt.join()
                _pw = sum(r[0] for r in _g_results)
                _mw = sum(r[1] for r in _g_results)
                _flog("[SPSA-MATCH] parallel total: plus=%d minus=%d" % (_pw, _mw))
            return (_pw - _mw) / games_per_iter if games_per_iter > 0 else 0.0

        _flog("[SPSA-MATCH] launching: %s" % match_cmd)

        try:
            proc = _popen_utf8(
                match_cmd,
                shell=True,
                stdout=subprocess.PIPE,
                stderr=subprocess.PIPE,
                env=env, cwd=_BASE_DIR,
                **_spsa_pgrp_kwargs(),
            )
        except Exception as e:
            _flog("[SPSA-MATCH] launch error: %s" % e)
            _LIVE.reset()
            print("[!] SPSA: external match launch error: %s" % e, flush=True)
            return 0.0
    
        try:
            stdout_data, stderr_data = proc.communicate(timeout=timeout_s)
        except subprocess.TimeoutExpired:
            _flog("[SPSA-MATCH] TIMEOUT after %ds — killing process tree" % timeout_s)
            _LIVE.reset()
            print("[!] SPSA: match timeout after %ds" % timeout_s, flush=True)
            _spsa_kill_proc_tree(proc, sig=signal.SIGTERM, ctrl_break=True)
            try:
                proc.communicate(timeout=10)
            except Exception as _fe:
                _flog(f"[ignored] {__file__}:11016: {_fe}")
            return None
        except Exception as e:
            _flog("[SPSA-MATCH] communicate error: %s" % e)
            _spsa_kill_proc_tree(proc, sig=signal.SIGTERM, ctrl_break=True)
            return 0.0

        if proc.returncode != 0:
            _flog("[SPSA-MATCH] non-zero exit: %d\nstderr: %s"
                  % (proc.returncode, (stderr_data or "")[:500]))
            return 0.0

        output = stdout_data or ""
        _flog("[SPSA-MATCH] stdout (last 500): %s" % output[-500:])

        for line_out in reversed(output.splitlines()):
            low = line_out.strip().lower()
            if "result:" in low:
                if "plus" in low:
                    _flog("[SPSA-MATCH] result: PLUS wins")
                    return 1.0
                elif "minus" in low:
                    _flog("[SPSA-MATCH] result: MINUS wins")
                    return -1.0
                elif "draw" in low:
                    _flog("[SPSA-MATCH] result: DRAW — score=0")
                    return 0.0
    
        if os.path.exists(stats_plus) and os.path.exists(stats_minus):
            try:
                ab_text = _ab_compare_stats(stats_plus, stats_minus)
                _flog("[SPSA-MATCH] A/B fallback:\n%s" % ab_text)
            except Exception as e:
                _flog("[SPSA-MATCH] A/B comparison error: %s" % e)

        _flog("[SPSA-MATCH] no clear result parsed — returning 0.0")
        return 0.0
    finally:
        _SPSA_RUNNER_ACTIVE[0] = False
        _spsa_salvage_stats(stats_plus,  "plus",  game_idx)
        _spsa_salvage_stats(stats_minus, "minus", game_idx)
        for _gs_p, _gs_side, _gs_off in _g_salvage:
            _spsa_salvage_stats(_gs_p, _gs_side, _gs_off)
        try:
            import shutil as _sh2
            _sh2.rmtree(_match_tmpdir, ignore_errors=True)
        except Exception as _fe:
            _flog(f"[ignored] {__file__}:11062: {_fe}")
def _grid_search_cli():
    import argparse as _argparse
    import itertools as _itertools
    import tempfile as _tempfile

    _gparser = _argparse.ArgumentParser(description="Engine Index Grid Search")
    _gparser.add_argument("--total-games", type=int, default=1024,
                          help="全対局数 (デフォルト 1024)")
    _gparser.add_argument("--baseline", default=None,
                          help="ベースライン spsa_config.txt のパス (省略時: 同ディレクトリ)")
    _gparser.add_argument("--out",
                          default=os.path.join(_BASE_DIR, "grid_results.txt"),
                          help="結果 JSON の出力先 (デフォルト <base_dir>/grid_results.txt)")
    _gargs = _gparser.parse_args(sys.argv[2:])

    _script_dir = os.path.dirname(os.path.abspath(__file__))
    _baseline = _gargs.baseline or os.path.join(_script_dir, "spsa_config.txt")

    if not os.path.isfile(_baseline):
        print(f"[INFO] ベースライン config が見つかりません: {_baseline}")
        print("[INFO] 現在のロード済み config をベースラインとして使用します。")
        _base_cfg = dict(_cfg)
        _baseline = "(current config)"
    else:
        with open(_baseline, encoding="utf-8") as _f:
            _base_cfg = json.load(_f)

    _INDEX_RANGES = {}
    _dl_pool_max_g   = max(_dl_pool_indices)   if _dl_pool_indices   else 0
    _nnue_pool_max_g = max(_nnue_pool_indices) if _nnue_pool_indices else 0
    if _dl_pool_max_g > 0:
        _all_dl_idx_g = list(range(_dl_pool_max_g + 1))
        for _slot in ("DL_1", "DL_2", "DL_3"):
            _INDEX_RANGES[f"{_slot}_Engine_Index"] = _dl_slot_allowed_indices(_slot, _all_dl_idx_g)
    if _nnue_pool_max_g > 0:
        for _slot in ("nnue_1", "nnue_2"):
            _key = f"{_slot}_Engine_Index"
            try:
                _fixed = int(_base_cfg.get(_key, _CONFIG_DEFAULTS.get(_key, 1)))
            except (TypeError, ValueError):
                _fixed = int(_CONFIG_DEFAULTS.get(_key, 1))
            if not (0 <= _fixed <= _nnue_pool_max_g):
                _fixed = 0
            _INDEX_RANGES[_key] = [_fixed]

    if not _INDEX_RANGES:
        print("[ERROR] プールが定義されていません。DL_Pool_*/nnue_Pool_* を config に追加してください。")
        sys.exit(1)

    _INDEX_KEYS = list(_INDEX_RANGES.keys())
    _combos = list(_itertools.product(*[_INDEX_RANGES[k] for k in _INDEX_KEYS]))
    _combos = [dict(zip(_INDEX_KEYS, c)) for c in _combos]
    _n_combos = len(_combos)

    _TC_LIST = [
        {"base_ms": _m, "inc_ms": _SELFPLAY_TC_INC_MS, "weight": 1,
         "label": ("Fischer %d分+%d秒" % (_m // 60000, _SELFPLAY_TC_INC_MS // 1000))
                  if _m else ("Byoyomi 0分+%d秒" % (_SELFPLAY_TC_INC_MS // 1000))}
        for _m in _SELFPLAY_TC_MAIN_MS_LIST
    ]
    _TC_TOTAL_WEIGHT = sum(tc["weight"] for tc in _TC_LIST)
    _unit_games   = max(1, _gargs.total_games // _TC_TOTAL_WEIGHT // _n_combos)
    _games_per_tc = [max(1, _unit_games * tc["weight"]) for tc in _TC_LIST]

    class _GUsiEngine(_SpsaUsiEngine):
        def __init__(self, cfg, label):
            self.name = label
            self._tmpdir = _tempfile.mkdtemp(prefix=f"gs_{label}_")
            patched = _SpsaUsiEngine._halve_cfg_dict(cfg, halve=True)
            _cfg_path = os.path.join(self._tmpdir, "config.txt")
            with open(_cfg_path, "w", encoding="utf-8") as _cf:
                json.dump(patched, _cf, indent=2, ensure_ascii=False)
                _cf.write("\n")
            self._stats_path = os.path.join(self._tmpdir, "stats.jsonl")
            _rseq = next(_SpsaUsiEngine._REAP_SEQ)
            self._reap_key = "%dz%dz%d" % (os.getpid(), _rseq, time.time_ns())
            _env = _build_child_env("grid_worker", tmpdir=self._tmpdir,
                                    stats_path=self._stats_path, reap_key=self._reap_key)
            _argv = _spsa_engine_argv("--spsa-worker")
            self._start_worker_process(_argv, _env, label,
                                       reader_name_prefix="grid")


        def _pre_tmpdir_cleanup(self):
            _spsa_salvage_stats(
                self._stats_path, self.name,
                dest_path=os.path.join(_BASE_DIR, "grid_stats.jsonl"))
            super()._pre_tmpdir_cleanup()


    def _grid_tc_to_spsa(tc):
        _inc = int(tc["inc_ms"])
        _base = int(tc["base_ms"])
        if _base == 0:
            return _SpsaTimeControl("byoyomi", 0, byoyomi_ms=_inc,
                                    label="grid_byoyomi(%dms)" % _inc)
        return _SpsaTimeControl("fischer", _base, inc_ms=_inc,
                                label="grid_fischer(main=%dms,inc=%dms)"
                                      % (_base, _inc))

    def _grun_match(cfg_cand, cfg_base, n_games, tc):
        _tc_spsa = _grid_tc_to_spsa(tc)
        wins = losses = draws = 0
        for game_idx in range(n_games):
            swap = (game_idx % 2 == 1)
            s_cfg, g_cfg = (cfg_base, cfg_cand) if swap else (cfg_cand, cfg_base)
            s_lbl, g_lbl = ("base", "cand")     if swap else ("cand", "base")
            eng_s = _GUsiEngine(s_cfg, f"s{game_idx}")
            eng_g = _GUsiEngine(g_cfg, f"g{game_idx}")
            if not (_spsa_init_engine(eng_s) and _spsa_init_engine(eng_g)):
                _gi_s = threading.Thread(target=eng_s.quit, daemon=True, name="grid-qi-s")
                _gi_g = threading.Thread(target=eng_g.quit, daemon=True, name="grid-qi-g")
                _gi_s.start(); _gi_g.start()
                _gi_s.join(timeout=20.0); _gi_g.join(timeout=20.0)
                for _gi_t, _gi_e in ((_gi_s, eng_s), (_gi_g, eng_g)):
                    if _gi_t.is_alive():
                        try:
                            _spsa_kill_proc_tree(getattr(_gi_e, "proc", None))
                        except Exception:
                            pass
                    try:
                        _gi_e._wsl_reap()
                    except Exception:
                        pass
                draws += 1
                continue
            result = _selfplay_game(eng_s, eng_g, tc=_tc_spsa,
                                     opening=_selfplay_opening())
            _send_gameover(eng_s, eng_g, result)
            _quit_engines(eng_s, eng_g, label="grid")
            if result == "sente_win":
                if s_lbl == "cand": wins += 1
                else:               losses += 1
            elif result == "gote_win":
                if g_lbl == "cand": wins += 1
                else:               losses += 1
            else:
                draws += 1
        return {"wins": wins, "losses": losses, "draws": draws}

    def _gsave(path, results, games_per_tc):
        _tc_desc = [
            {"label": tc["label"], "games": g}
            for tc, g in zip(_TC_LIST, games_per_tc)
        ]
        out = {
            "games_per_tc":        _tc_desc,
            "total_games_per_combo": sum(games_per_tc),
            "baseline_keys":       {k: _base_cfg.get(k) for k in _INDEX_KEYS},
            "results": sorted(results, key=lambda x: x["elo"], reverse=True),
        }
        try:
            with open(path, "w", encoding="utf-8") as f:
                json.dump(out, f, indent=2, ensure_ascii=False)
                f.write("\n")
        except OSError as e:
            print(f"[WARN] 結果保存失敗: {e}")

    _total_per_combo = sum(_games_per_tc)
    print("=" * 60)
    print("Engine Index Grid Search (engine.py grid)")
    print(f"  組み合わせ数 : {_n_combos}")
    print(f"  総対局数     : {_total_per_combo * _n_combos}  ({_total_per_combo} 局/組み合わせ)")
    for _tc, _ng in zip(_TC_LIST, _games_per_tc):
        print(f"    {_tc['label']}: {_ng} 局  (重み {_tc['weight']})")
    print(f"  ベースライン : {_baseline}")
    print("=" * 60)

    _results = []
    _t0 = time.perf_counter()
    for _i, _combo in enumerate(_combos):
        _cfg_cand = dict(_base_cfg)
        _cfg_cand.update(_combo)
        _label = "  ".join(f"{k.replace('_Engine_Index','')}={_pool_letter(v)}"
                           for k, v in _combo.items())
        print(f"\n[{_i+1}/{_n_combos}] {_label}")

        _tc_stats = []
        for _tc_i, _tc in enumerate(_TC_LIST):
            _n_tc = _games_per_tc[_tc_i]
            _s = _grun_match(_cfg_cand, _base_cfg, _n_tc, _tc)
            _tc_stats.append(_s)
            _tc_n = _s["wins"] + _s["losses"] + _s["draws"]
            _tc_elo = _sprt_elo_from_score((_s["wins"] + _s["draws"] * 0.5) / _tc_n) if _tc_n else 0.0
            print(f"  [{_tc['label']}] "
                  f"W{_s['wins']} L{_s['losses']} D{_s['draws']}  "
                  f"Elo{_tc_elo:+.1f}")

        _w = sum(s["wins"]   for s in _tc_stats)
        _l = sum(s["losses"] for s in _tc_stats)
        _d = sum(s["draws"]  for s in _tc_stats)
        _n_all = _w + _l + _d
        _elo_diff = _sprt_elo_from_score((_w + _d * 0.5) / _n_all) if _n_all else 0.0
        print(f"  [合算] W{_w} L{_l} D{_d}  Elo{_elo_diff:+.1f}")

        _results.append({
            "combo":   _combo,
            "label":   _label,
            "wins":    _w,
            "losses":  _l,
            "draws":   _d,
            "elo":     round(_elo_diff, 2),
            "tc_stats": [
                {
                    "label":   _TC_LIST[_ti]["label"],
                    "wins":    _tc_stats[_ti]["wins"],
                    "losses":  _tc_stats[_ti]["losses"],
                    "draws":   _tc_stats[_ti]["draws"],
                    "elo":     round(
                        _sprt_elo_from_score((_tc_stats[_ti]["wins"] + _tc_stats[_ti]["draws"] * 0.5)
                                             / max(1, _tc_stats[_ti]["wins"] + _tc_stats[_ti]["losses"] + _tc_stats[_ti]["draws"])), 2),
                }
                for _ti in range(len(_TC_LIST))
            ],
        })
        _gsave(_gargs.out, _results, _games_per_tc)
        _elapsed = time.perf_counter() - _t0
        if _i > 0:
            _eta = (_elapsed / (_i + 1)) * (_n_combos - _i - 1)
            print(f"  経過 {_elapsed:.0f}s  残り推定 {_eta:.0f}s ({_eta/3600:.1f}h)")

    _results.sort(key=lambda x: x["elo"], reverse=True)
    _gsave(_gargs.out, _results, _games_per_tc)
    print("\n" + "=" * 60)
    print("TOP 10 (合算 Elo差 降順)")
    print("=" * 60)
    for _rank, _r in enumerate(_results[:10], 1):
        print(f"{_rank:2}. Elo{_r['elo']:+6.1f}  "
              f"W{_r['wins']} L{_r['losses']} D{_r['draws']}  {_r['label']}")
        _tc_line = "  ".join(
            f"{ts['label']}={ts['elo']:+.1f}"
            for ts in _r.get("tc_stats", [])
        )
        if _tc_line:
            print(f"      TC別: {_tc_line}")
    print(f"\n結果を保存しました: {_gargs.out}")


def _spsa_cli(setup_mode: bool = False):
    args = sys.argv[1:]

    if "--report" in args:
        stats_path = _next_arg(args, "--report", _STATS_PATH)
        records, n_games, vc = _tuner_load_records(stats_path)
        _tuner_report(records, n_games, vc)
        return

    if "--ab-report" in args:
        idx = args.index("--ab-report")
        if idx + 2 < len(args):
            text = _ab_compare_stats(args[idx + 1], args[idx + 2])
            print(text)
        else:
            print("Usage: --spsa --ab-report <stats_A> <stats_B>")
        return

    if "--export" in args:
        state_path = _next_arg(args, "--export", None)
        if state_path and os.path.exists(state_path):
            with open(state_path, "r", encoding="utf-8") as f:
                raw = json.load(f)
            state = SpsaState.from_dict(raw)
        else:
            state = SpsaState(params=_spsa_default_params())
        spsa_save_config(state, cfg_path=(_SETUP_CONFIG_PATH if setup_mode
                                          else _SPSA_CONFIG_PATH))
        print("Exported %d params to %s"
              % (len(state.params),
                 _SETUP_CONFIG_PATH if setup_mode else _SPSA_CONFIG_PATH))
        return

    if "--status" in args:
        state_path = _next_arg(args, "--status", None)
        if state_path and os.path.exists(state_path):
            with open(state_path, "r", encoding="utf-8") as f:
                raw = json.load(f)
            print("SPSA State: iteration=%d  params=%d"
                  % (raw.get("k", 0), len(raw.get("params", []))))
            for p in raw.get("params", []):
                print("  %-40s  θ=%-12.4f  [%.4f, %.4f]"
                      % (p["name"], p["value"], p["min_val"], p["max_val"]))
        else:
            params = _spsa_default_params()
            print("SPSA Default Params: %d parameters" % len(params))
            for p in params:
                print("  %-40s  θ₀=%-12.4f  [%.4f, %.4f]  c=%.4f"
                      % (p.name, p.value, p.min_val, p.max_val, p.step))
        return

    if "--extract-openings" in args:
        _eo_book_path = _next_arg(args, "--extract-openings", None)
        if not _eo_book_path or not os.path.exists(_eo_book_path):
            print("Usage: --spsa --extract-openings <book.db> [--out openings.sfen] "
                  "[--max-cp 50] [--min-count 3] [--limit 500]")
            return
        _eo_out = _next_arg(args, "--out", "openings.sfen")
        _eo_max_cp = int(_next_arg(args, "--max-cp", "50") or "50")
        _eo_min_count = int(_next_arg(args, "--min-count", "3") or "3")
        _eo_limit = int(_next_arg(args, "--limit", "500") or "500")
        _eo_positions = []
        try:
            with open(_eo_book_path, "r", encoding="utf-8", errors="ignore") as _eof:
                _eof.readline()
                _eo_sfen = None
                for _eo_raw in _eof:
                    _eo_line = _eo_raw.strip()
                    if not _eo_line:
                        continue
                    if _eo_line.startswith("sfen "):
                        _eo_sfen = _eo_line[5:].strip()
                        continue
                    if _eo_sfen is None:
                        continue
                    _eo_toks = _eo_line.split()
                    _eo_val = int(_eo_toks[2]) if len(_eo_toks) > 2 else 0
                    _eo_cnt = int(_eo_toks[4]) if len(_eo_toks) > 4 else 1
                    if abs(_eo_val) <= _eo_max_cp and _eo_cnt >= _eo_min_count:
                        _eo_positions.append((_eo_sfen, _eo_cnt, abs(_eo_val)))
                    _eo_sfen = None
        except Exception as _eoe:
            print("[extract-openings] book 読み込みエラー: %s" % _eoe)
            return
        _eo_positions.sort(key=lambda x: (-x[1], x[2]))
        _eo_positions = _eo_positions[:_eo_limit]
        _eo_seen = set()
        with open(_eo_out, "w", encoding="utf-8") as _eow:
            _eow.write("# extracted from %s  max_cp=%d min_count=%d\n"
                        % (_eo_book_path, _eo_max_cp, _eo_min_count))
            for _eo_sf, _eo_c, _eo_v in _eo_positions:
                _eo_key = _eo_sf.rsplit(" ", 1)[0] if " " in _eo_sf else _eo_sf
                if _eo_key in _eo_seen:
                    continue
                _eo_seen.add(_eo_key)
                _eow.write("sfen %s\n" % _eo_sf)
        print("[S-6] %d 互角局面を %s に書き出しました (|eval| <= %d cp, count >= %d)"
              % (len(_eo_seen), _eo_out, _eo_max_cp, _eo_min_count))
        return

    if not setup_mode and "--run" not in args:
        print("Usage: python engine.py --spsa "
              "{--run [--match-cmd CMD] | --report | --ab-report A B "
              "| --status | --export}")
        return

    match_cmd = _next_arg(args, "--match-cmd", None)
    _use_builtin_worker = not match_cmd

    n_iter = int(_next_arg(args, "--iterations", "100") or "100")
    if setup_mode:
        _spsa_profile = "hw"
    else:
        _spsa_profile = (_next_arg(args, "--profile", "game") or "game").lower()
        if _spsa_profile == "hw":
            print("[spsa] デバイス依存キーの調整は setup コマンドに移行しました: "
                  "python engine.py setup")
            return
    _spsa_max_hours = float(_next_arg(args, "--max-hours", "0") or "0")
    _gpi_raw = _next_arg(args, "--games-per-iter", "")
    if _gpi_raw:
        games_per_iter = int(_gpi_raw)
    else:
        games_per_iter = _selfplay_games_per_iter()
    if games_per_iter < 1:
        games_per_iter = 1
    resume_path = _next_arg(args, "--resume", None)
    if setup_mode:
        state_save_path = os.path.join(_BASE_DIR, "setup_state.txt")
        _out_cfg_path   = _SETUP_CONFIG_PATH
        if resume_path is None and os.path.exists(state_save_path):
            resume_path = state_save_path
            print(f"[setup] 中断状態を検出 → 自動 resume: {state_save_path}",
                  flush=True)
    else:
        state_save_path = os.path.join(_BASE_DIR, "spsa_state.txt")
        _out_cfg_path   = _SPSA_CONFIG_PATH
    _per_game_timeout_s = 1800.0
    match_timeout_s = _per_game_timeout_s * games_per_iter
    _anchor_every = int(_next_arg(args, "--anchor-every", "0") or "0")
    _anchor_games = int(_next_arg(args, "--anchor-games", "4") or "4")
    _anchor_results = []

    _SPSA_RETIRED_KEYS = {
        "Resource_Threads_Share_NNUE1", "Resource_Threads_Share_DL1",
        "Resource_Threads_Share_DL2",   "Resource_Threads_Share_DL3",
    }
    if resume_path and os.path.exists(resume_path):
        with open(resume_path, "r", encoding="utf-8") as f:
            raw = json.load(f)
        state = SpsaState.from_dict(raw)
        if not raw.get("total_iters"):
            state.total_iters = n_iter
        _retired_seen = [p.name for p in state.params
                         if p.name in _SPSA_RETIRED_KEYS]
        if _retired_seen:
            state.params = [p for p in state.params
                            if p.name not in _SPSA_RETIRED_KEYS]
            print("Resumed state: dropped %d retired params: %s"
                  % (len(_retired_seen), " ".join(sorted(_retired_seen))))
            _flog("[SPSA-RETIRE] resume から除外: %s"
                  % " ".join(sorted(_retired_seen)))
        _kept, _dropped = _spsa_filter_profile_core(state.params, _spsa_profile)
        if _dropped:
            state.params = _kept
            print("Resumed with profile=%s: %d params (dropped %d)"
                  % (_spsa_profile, len(_kept), len(_dropped)))
            _flog("[SETUP/SPSA] resume プロファイル再適用 (%s): 除外 %s"
                  % (_spsa_profile, " ".join(sorted(_dropped))))
        print("Resumed %s state: iteration=%d  a0=%.4f  A=%d"
              % ("SETUP" if setup_mode else "SPSA", state.k, state.a0, state.A))
    else:
        _all_params = _spsa_default_params()
        _kept, _dropped = _spsa_filter_profile_core(_all_params, _spsa_profile)
        state = SpsaState(params=_kept)
        print("Initialized %s state: %d params (profile=%s%s)"
              % ("SETUP" if setup_mode else "SPSA",
                 len(state.params), _spsa_profile,
                 ", dropped %d" % len(_dropped) if _dropped else ""))
        if _dropped:
            _flog("[SETUP/SPSA] profile=%s: %d/%d キーに縮約。除外: %s"
                  % (_spsa_profile, len(_kept), len(_all_params),
                     " ".join(sorted(_dropped))))

    state.total_iters = n_iter
    if state.A == 0:
        state.A = max(10, int(round(n_iter * 0.10)))
    print("SPSA start: %d iter × %d games/iter  a0=%.4f  A=%d" % (n_iter, games_per_iter, state.a0, state.A), flush=True)
    _flog("SPSA config: iterations=%d  games_per_iter=%d  A=%d  a0=%.4f  timeout_per_iter=%.0fs"
          % (n_iter, games_per_iter, state.A, state.a0, match_timeout_s))

    try:
        _tc_specs_check = _spsa_parse_tc_spec()
        _n_tc_check = len(_tc_specs_check)
        if _n_tc_check > 0 and games_per_iter % (2 * _n_tc_check) != 0:
            _rec = ((games_per_iter // (2 * _n_tc_check)) + 1) * (2 * _n_tc_check)
            print("[SPSA-W] games_per_iter=%d は 2×n_tc=%d の倍数でありません。"
                  "イテレーション内の先後×TC が不均衡です。推奨: %d"
                  % (games_per_iter, 2 * _n_tc_check, _rec), flush=True)
            _flog("[S-4] TC coverage warning: gpi=%d 2*n_tc=%d recommended=%d"
                  % (games_per_iter, 2 * _n_tc_check, _rec))
    except Exception:
        pass

    _spsa_force = "--force" in args
    _spsa_param_names = {p.name for p in state.params}
    _shadow_collisions = []
    for _layer_path, _layer_label in [
        (os.path.join(_BASE_DIR, "config.txt"), "config.txt"),
        (_SETUP_CONFIG_PATH, "setup_config.txt"),
    ]:
        if os.path.exists(_layer_path):
            try:
                with open(_layer_path, encoding="utf-8") as _lf:
                    _layer_keys = set(json.load(_lf).keys())
                _overlap = _spsa_param_names & _layer_keys
                if _overlap:
                    _shadow_collisions.append((_layer_label, sorted(_overlap)))
            except Exception:
                pass
    if os.path.exists(_ENGINE_OPTIONS_PATH):
        try:
            _eo_keys = set(_load_engine_options(_ENGINE_OPTIONS_PATH).keys())
            _eo_overlap = _spsa_param_names & _eo_keys
            if _eo_overlap:
                _shadow_collisions.append(("engine_options.txt", sorted(_eo_overlap)))
        except Exception:
            pass
    if _shadow_collisions:
        print("[SPSA-SHADOW] 警告: 以下の SPSA 対象キーが上位層で固定されています。"
              "θ± の値が実対局に反映されず勾配が全てノイズになる恐れがあります:",
              flush=True)
        for _sl, _sk in _shadow_collisions:
            print("  %s: %s" % (_sl, ", ".join(_sk)), flush=True)
        _flog("[SPSA-SHADOW] 衝突検出: %s"
              % "; ".join("%s=%s" % (_sl, ",".join(_sk))
                          for _sl, _sk in _shadow_collisions))
        if not _spsa_force:
            raise SystemExit(
                "[SPSA-SHADOW] 上位層との衝突があるため起動を拒否しました。"
                "--force で警告のみに降格できます。")
        print("[SPSA-SHADOW] --force 指定のため続行します。", flush=True)

    if _use_builtin_worker:
        _flog("  match mode : built-in")
    else:
        _flog("  match mode : external  cmd=%s" % match_cmd)
    wins_plus = 0
    wins_minus = 0
    draws = 0
    _consecutive_zero_iters = 0
    _ZERO_ITER_CIRCUIT_LIMIT = 3
    _g_global_idx = state.k * games_per_iter

    _t_spsa_start = time.monotonic()
    for i in range(n_iter):
        if _spsa_max_hours > 0 and \
                (time.monotonic() - _t_spsa_start) > _spsa_max_hours * 3600.0:
            print("[SPSA] max-hours %.1fh reached at iter %d — graceful stop "
                  "(state saved as usual)" % (_spsa_max_hours, state.k), flush=True)
            _flog("[SPSA-HW] wall-clock cap %.1fh reached — stopping at iter %d"
                  % (_spsa_max_hours, state.k))
            break
        state.k += 1
        print("iter %d/%d" % (state.k, state.k - 1 + n_iter), flush=True)

        cfg_plus, cfg_minus = spsa_perturbation(state)
        for j, p in enumerate(state.params[:5]):
            plus_v = cfg_plus.get(p.name, "?")
            minus_v = cfg_minus.get(p.name, "?")
            _flog("  %s: θ=%.4f  θ+=%.4f  θ-=%.4f"
                  % (p.name, p.value, float(plus_v), float(minus_v)))
        if len(state.params) > 5:
            _flog("  ... and %d more params" % (len(state.params) - 5))

        full_plus = _merge_cfg_for_temp(cfg_plus)
        full_minus = _merge_cfg_for_temp(cfg_minus)

        result = _spsa_run_match(
            full_plus, full_minus, match_cmd,
            timeout_s=_per_game_timeout_s * games_per_iter,
            game_idx=_g_global_idx,
            games_per_iter=games_per_iter,
        )
        _g_global_idx += games_per_iter

        if result is None:
            result = 0.0

        if result > 0:
            wins_plus += 1
            print("  → θ+ score=%.3f  (total: +%d -%d =%d)" % (result, wins_plus, wins_minus, draws), flush=True)
        elif result < 0:
            wins_minus += 1
            print("  → θ- score=%.3f  (total: +%d -%d =%d)" % (result, wins_plus, wins_minus, draws), flush=True)
        else:
            draws += 1
            print("  → draw/error  (total: +%d -%d =%d)" % (wins_plus, wins_minus, draws), flush=True)

        if result == 0.0:
            _consecutive_zero_iters += 1
            if _consecutive_zero_iters >= _ZERO_ITER_CIRCUIT_LIMIT:
                _flog("[SPSA][CIRCUIT-BREAKER] %d consecutive zero-score "
                      "iterations — engines likely unrecoverable, aborting"
                      % _consecutive_zero_iters)
                print("[SPSA] %d consecutive zero-score iterations — aborting "
                      "(state saved)" % _consecutive_zero_iters, flush=True)
                break
        else:
            _consecutive_zero_iters = 0

        if result != 0.0:
            spsa_step(state, score=result)

        _spsa_save_state(state, state_save_path)

        if state.k % 10 == 0 and (wins_plus + wins_minus) > 0:
            spsa_save_config(state, cfg_path=_out_cfg_path)
            print("  [checkpoint] saved", flush=True)

        if _anchor_every > 0 and state.k % _anchor_every == 0:
            try:
                _anc_cfg_current = {}
                for p in state.params:
                    _anc_cfg_current[p.name] = p.value
                _anc_full_current = _merge_cfg_for_temp(_anc_cfg_current)
                _anc_full_baseline = _merge_cfg_for_temp({})
                _anc_result = _spsa_run_match(
                    _anc_full_current, _anc_full_baseline, match_cmd,
                    timeout_s=_per_game_timeout_s * _anchor_games,
                    game_idx=_g_global_idx,
                    games_per_iter=_anchor_games,
                )
                _g_global_idx += _anchor_games
                if _anc_result is None:
                    _anc_result = 0.0
                _anc_w = 1 if _anc_result > 0 else 0
                _anc_l = 1 if _anc_result < 0 else 0
                _anc_d = 1 if _anc_result == 0 else 0
                _anchor_results.append((_anc_w, _anc_d, _anc_l, _anc_result))
                _anc_tw = sum(r[0] for r in _anchor_results)
                _anc_td = sum(r[1] for r in _anchor_results)
                _anc_tl = sum(r[2] for r in _anchor_results)
                _anc_tn = _anc_tw + _anc_td + _anc_tl
                _anc_score = (_anc_tw + _anc_td * 0.5) / _anc_tn if _anc_tn > 0 else 0.5
                _anc_elo = _sprt_elo_from_score(_anc_score) if 0 < _anc_score < 1 else 0.0
                print("  [ANCHOR iter %d] score=%.3f  累計 W%d-D%d-L%d  "
                      "勝率 %.1f%%  Elo %+.1f"
                      % (state.k, _anc_result, _anc_tw, _anc_td, _anc_tl,
                         _anc_score * 100, _anc_elo), flush=True)
                for _aw_size in (10, 20, 40, 80):
                    if len(_anchor_results) >= _aw_size:
                        _aw_tail = _anchor_results[-_aw_size:]
                        _aw_w = sum(r[0] for r in _aw_tail)
                        _aw_d = sum(r[1] for r in _aw_tail)
                        _aw_l = sum(r[2] for r in _aw_tail)
                        _aw_n = _aw_w + _aw_d + _aw_l
                        _aw_s = (_aw_w + _aw_d * 0.5) / _aw_n if _aw_n > 0 else 0.5
                        _aw_e = _sprt_elo_from_score(_aw_s) if 0 < _aw_s < 1 else 0.0
                        print("    窓%d: W%d-D%d-L%d  %.1f%%  %+.1f Elo"
                              % (_aw_size, _aw_w, _aw_d, _aw_l,
                                 _aw_s * 100, _aw_e), flush=True)
            except Exception as _ance:
                _flog("[S-3] anchor error (non-fatal): %s" % _ance)

    if wins_plus + wins_minus == 0 and n_iter > 0:
        print("%s ABORTED: 勝敗が 1 つも付きませんでした (+0 -0 =%d) — "
              "config を書き出しません。エンジンパス/初期化失敗を確認してください"
              % ("SETUP" if setup_mode else "SPSA", draws), flush=True)
        _spsa_save_state(state, state_save_path)
        if len(sys.argv) > 1 and _norm_str(sys.argv[1]) in ("setup", "spsa"):
            sys.exit(1)
        return
    spsa_save_config(state, cfg_path=_out_cfg_path)
    _spsa_save_state(state, state_save_path)
    print("%s complete: %d iter × %d games  +%d -%d =%d"
          % ("SETUP" if setup_mode else "SPSA",
             n_iter, games_per_iter, wins_plus, wins_minus, draws), flush=True)
    if setup_mode:
        print("[setup] 結果を %s に出力しました — 次回起動から自動読み込み"
              % _out_cfg_path, flush=True)
    for p in state.params:
        _flog("  %-40s  θ=%.6f" % (p.name, p.value))
def _spsa_save_state(state: SpsaState, path: str) -> None:
    data = {
        "k": state.k,
        "a0": state.a0,
        "c0": state.c0,
        "A": state.A,
        "alpha": state.alpha,
        "gamma": state.gamma,
        "total_iters": state.total_iters,
        "params": [
            {
                "name": p.name,
                "value": p.value,
                "min_val": p.min_val,
                "max_val": p.max_val,
                "step": p.step,
                "is_int": p.is_int,
            }
            for p in state.params
        ],
    }
    try:
        tmp = path + ".tmp"
        with open(tmp, "w", encoding="utf-8") as f:
            json.dump(data, f, indent=2, ensure_ascii=False)
        os.replace(tmp, path)
    except Exception as e:
        _flog("[SPSA] state save error: %s" % e)


def _next_arg(args: list, flag: str, default: str | None) -> str | None:
    try:
        idx = args.index(flag)
        if idx + 1 < len(args) and not args[idx + 1].startswith("--"):
            return args[idx + 1]
    except ValueError:
        pass
    return default





_SPRT_PENTA_SCORES = (0.0, 0.25, 0.5, 0.75, 1.0)
_SPRT_Z95 = 1.959964


def _sprt_score_from_elo(elo: float) -> float:
    return 1.0 / (1.0 + 10.0 ** (-float(elo) / 400.0))


def _sprt_elo_from_score(score: float, eps: float = 1e-9) -> float:
    s = min(max(float(score), eps), 1.0 - eps)
    return -400.0 * math.log10(1.0 / s - 1.0)


def _sprt_llr_pentanomial_core(counts, elo0: float, elo1: float,
                               regularize: float = 0.5) -> float:
    n = sum(int(c) for c in counts)
    if n <= 0:
        return 0.0
    reg = [float(c) + regularize for c in counts]
    tot = sum(reg)
    probs = [c / tot for c in reg]
    s = sum(p * a for p, a in zip(probs, _SPRT_PENTA_SCORES))
    var = sum(p * a * a for p, a in zip(probs, _SPRT_PENTA_SCORES)) - s * s
    if var <= 1e-12:
        return 0.0
    s0 = _sprt_score_from_elo(elo0)
    s1 = _sprt_score_from_elo(elo1)
    return n * (s1 - s0) * (2.0 * s - s0 - s1) / (2.0 * var)


def _sprt_bounds_core(alpha: float = 0.05, beta: float = 0.05):
    return (math.log(beta / (1.0 - alpha)), math.log((1.0 - beta) / alpha))


def _sprt_decision_core(llr: float, alpha: float = 0.05,
                        beta: float = 0.05) -> str:
    lo, hi = _sprt_bounds_core(alpha, beta)
    if llr >= hi:
        return "H1"
    if llr <= lo:
        return "H0"
    return "continue"


def _sprt_game_score_core(result: str, test_is_sente: bool):
    if result == "draw":
        return 0.5
    if result == "sente_win":
        return 1.0 if test_is_sente else 0.0
    if result == "gote_win":
        return 0.0 if test_is_sente else 1.0
    return None


def _sprt_pair_bucket_core(score_g1, score_g2):
    if score_g1 is None or score_g2 is None:
        return None
    total = float(score_g1) + float(score_g2)
    b = int(round(total * 2.0))
    if 0 <= b <= 4:
        return b
    return None


def _sprt_elo_estimate_core(counts) -> dict:
    n = sum(int(c) for c in counts)
    if n <= 0:
        return {"elo": 0.0, "lo95": float("-inf"), "hi95": float("inf"),
                "score": 0.5, "pairs": 0}
    reg = [float(c) + 0.5 for c in counts]
    tot = sum(reg)
    probs = [c / tot for c in reg]
    s = sum(p * a for p, a in zip(probs, _SPRT_PENTA_SCORES))
    var = max(sum(p * a * a for p, a in zip(probs, _SPRT_PENTA_SCORES)) - s * s,
              1e-12)
    se = math.sqrt(var / n)
    lo = s - _SPRT_Z95 * se
    hi = s + _SPRT_Z95 * se
    return {
        "elo":   _sprt_elo_from_score(s),
        "lo95":  _sprt_elo_from_score(lo),
        "hi95":  _sprt_elo_from_score(hi),
        "score": s,
        "pairs": n,
    }


def _sprt_opening_index_core(pair_idx: int, n_openings: int) -> int:
    if n_openings <= 0:
        return 0
    return int(pair_idx) % int(n_openings)


def _sprt_split_opening_core(opening):
    s = (opening or "").strip()
    if not s:
        return ("startpos", [])
    toks = s.split()
    if toks and toks[0] == "position":
        toks = toks[1:]
    if not toks:
        return ("startpos", [])
    base_moves: list = []
    if "moves" in toks:
        mi = toks.index("moves")
        base_moves = toks[mi + 1:]
        toks = toks[:mi]
    if not toks or toks[0] == "startpos":
        rest = toks[1:] if toks else []
        return ("startpos", rest + base_moves)
    if toks[0] == "sfen":
        toks = toks[1:]
    if toks and "/" in toks[0]:
        board = toks[0]
        stm   = toks[1] if len(toks) >= 2 else "b"
        hand  = toks[2] if len(toks) >= 3 else "-"
        ply   = toks[3] if len(toks) >= 4 else "1"
        extra = toks[4:]
        return ("sfen %s %s %s %s" % (board, stm, hand, ply),
                extra + base_moves)
    return ("startpos", list(toks) + base_moves)


def _sprt_sennichite_verdict_core(key_history, check_flags):
    if not key_history:
        return ("draw", None)
    last = key_history[-1]
    try:
        i0 = key_history.index(last)
    except ValueError:
        return ("draw", None)
    flags_by_parity = {0: [], 1: []}
    for idx in range(i0 + 1, len(key_history)):
        fi = idx - 1
        f = check_flags[fi] if 0 <= fi < len(check_flags) else None
        flags_by_parity[(idx - 1) % 2].append(f)
    for parity in (0, 1):
        fl = flags_by_parity[parity]
        if fl and all(f is True for f in fl):
            return ("perpetual", parity)
    return ("draw", None)


def _sprt_resume_counts_core(records):
    counts = [0, 0, 0, 0, 0]
    next_pair = 0
    for rec in records:
        try:
            p = int(rec.get("pair", -1))
        except (TypeError, ValueError):
            continue
        if p >= next_pair:
            next_pair = p + 1
        b = rec.get("bucket", None)
        if isinstance(b, int) and 0 <= b <= 4:
            counts[b] += 1
    return (counts, next_pair)


def _sprt_load_openings(path: str) -> list:
    out: list = []
    with open(path, encoding="utf-8") as f:
        for ln, raw in enumerate(f, 1):
            line = raw.strip()
            if not line or line.startswith("#"):
                continue
            prefix, bm = _sprt_split_opening_core(line)
            try:
                b = ShogiBoard(sfen=prefix)
                for m in bm:
                    if not b.is_legal_lite(m):
                        raise ValueError("illegal-lite move %r" % m)
                    b.push(m)
            except Exception as e:
                print("[SPRT] openings line %d skipped: %s" % (ln, e), flush=True)
                continue
            out.append(prefix + ((" moves " + " ".join(bm)) if bm else ""))
    return out


def _sprt_psv_opening_filter_core(records, min_cp: int, max_cp: int,
                                  min_ply: int, max_ply: int,
                                  limit: int) -> list:
    seen = set()
    kept: list = []
    for rec in records:
        try:
            payload, score, ply = rec
        except (TypeError, ValueError):
            continue
        try:
            ply_i = int(ply)
            sc_a = abs(int(score))
        except (TypeError, ValueError):
            continue
        if not (min_ply <= ply_i <= max_ply):
            continue
        if not (min_cp <= sc_a <= max_cp):
            continue
        if payload is None or payload in seen:
            continue
        seen.add(payload)
        kept.append(payload)
    n = len(kept)
    if limit > 0 and n > limit:
        kept = [kept[(i * n) // limit] for i in range(limit)]
    return kept


def _psv_file_sanity(path: str):
    try:
        size = os.path.getsize(path)
    except OSError as e:
        return (False, "stat failed: %s" % e)
    if size == 0:
        return (False, "empty file")
    if size % _PSV_RECORD_SIZE != 0:
        return (False, "size %d not multiple of %d (hcpe 等の別形式?)"
                % (size, _PSV_RECORD_SIZE))
    try:
        with open(path, "rb") as f:
            raw = f.read(_PSV_RECORD_SIZE)
        data32 = _struct.unpack(_PSV_FMT, raw)[0]
        ShogiBoard(sfen="sfen " + _fast_psfen_to_sfen(data32))
    except Exception as e:
        return (False, "first record decode failed: %s" % e)
    return (True, "ok")


def _sprt_load_openings_psv(path: str, min_cp: int = 100, max_cp: int = 400,
                            min_ply: int = 8, max_ply: int = 60,
                            limit: int = 200, scan: int = 500000) -> list:
    ok, msg = _psv_file_sanity(path)
    if not ok:
        print("[SPRT] psv sanity NG: %s" % msg, flush=True)
        return []
    def _raw_iter():
        with open(path, "rb") as f:
            count = 0
            while count < scan:
                raw = f.read(_PSV_RECORD_SIZE)
                if len(raw) < _PSV_RECORD_SIZE:
                    break
                count += 1
                data32, score, _mv, ply, _res, _pad = _struct.unpack(
                    _PSV_FMT, raw)
                yield (data32, score, ply)

    cand = _sprt_psv_opening_filter_core(_raw_iter(), min_cp, max_cp,
                                         min_ply, max_ply, limit)
    out: list = []
    for data32 in cand:
        try:
            op = "sfen " + _fast_psfen_to_sfen(data32)
            ShogiBoard(sfen=op)
        except Exception as e:
            print("[SPRT] psv opening skipped (%s)" % e, flush=True)
            continue
        out.append(op)
    return out


def _sprt_write_test_config(base_path: str, overrides: str, dst_path: str) -> list:
    try:
        with open(base_path, encoding="utf-8") as f:
            cfg = json.load(f)
    except Exception:
        cfg = {}
    applied = []
    for chunk in (overrides or "").split(","):
        chunk = chunk.strip()
        if not chunk or "=" not in chunk:
            continue
        k, _, v = chunk.partition("=")
        k = k.strip()
        v = v.strip()
        old = cfg.get(k, None)
        if isinstance(old, int) and not isinstance(old, bool):
            try:
                v = int(v)
            except ValueError:
                pass
        cfg[k] = v
        applied.append((k, old, v))
    with open(dst_path, "w", encoding="utf-8") as f:
        json.dump(cfg, f, indent=2, ensure_ascii=False)
        f.write("\n")
    return applied


def _sprt_cli(args: list) -> None:
    kv = {}
    for a in args:
        if "=" in a:
            k, _, v = a.partition("=")
            kv[k.strip()] = v.strip()

    base_dir = _BASE_DIR
    base_cfg = kv.get("base") or os.path.join(base_dir, "config.txt")
    if not os.path.exists(base_cfg):
        print("[SPRT] base config not found: %s" % base_cfg, flush=True)
        return

    out_path = kv.get("out") or os.path.join(base_dir, "sprt_results.txt")
    resume = kv.get("resume", "1") not in ("0", "false", "no")

    test_cfg = kv.get("test", "")
    test_set = kv.get("test_set", "")
    if not test_cfg and not test_set:
        if kv.get("opponent", "").strip():
            test_cfg = base_cfg
        else:
            print("[SPRT] specify test=<config> or test_set=\"Key=Val,...\"",
                  flush=True)
            return
    if not test_cfg:
        test_cfg = out_path + ".test_config.txt"
        applied = _sprt_write_test_config(base_cfg, test_set, test_cfg)
        for k, old, new in applied:
            print("[SPRT] test override: %s: %r -> %r" % (k, old, new),
                  flush=True)
        if not applied:
            print("[SPRT] test_set produced no overrides — aborting", flush=True)
            return

    openings = [_selfplay_opening() or "startpos"]
    if kv.get("openings"):
        _op_path = kv["openings"]
        try:
            if _op_path.lower().endswith(".bin"):
                openings = _sprt_load_openings_psv(
                    _op_path,
                    min_cp=int(kv.get("psv_min_cp", "100")),
                    max_cp=int(kv.get("psv_max_cp", "400")),
                    min_ply=int(kv.get("psv_min_ply", "8")),
                    max_ply=int(kv.get("psv_max_ply", "60")),
                    limit=int(kv.get("psv_limit", "200")),
                    scan=int(kv.get("psv_scan", "500000")),
                ) or ["startpos"]
            else:
                openings = _sprt_load_openings(_op_path) or ["startpos"]
        except OSError as e:
            print("[SPRT] openings load failed (%s) — using startpos" % e,
                  flush=True)
    print("[SPRT] openings: %d" % len(openings), flush=True)

    tc = (_sprt_parse_tc_core(kv["tc"]) if kv.get("tc")
          else _spsa_parse_tc_spec()[0])
    elo0 = float(kv.get("elo0", "0"))
    elo1 = float(kv.get("elo1", "5"))
    alpha = float(kv.get("alpha", "0.05"))
    beta = float(kv.get("beta", "0.05"))
    max_pairs = int(kv.get("max_pairs", "0"))
    if not (elo0 < elo1):
        print(f"[SPRT] FATAL: elo0={elo0} must be strictly less than elo1={elo1} "
              "(degenerate H0==H1 would never decide)", flush=True)
        return
    if not (0.0 < alpha < 0.5) or not (0.0 < beta < 0.5):
        print(f"[SPRT] FATAL: alpha={alpha}, beta={beta} must be in (0, 0.5)", flush=True)
        return
    game_timeout_s = float(kv.get("game_timeout_s", "2000"))
    lo_b, hi_b = _sprt_bounds_core(alpha, beta)

    counts = [0, 0, 0, 0, 0]
    pair = 0
    if resume and os.path.exists(out_path):
        recs = []
        try:
            with open(out_path, encoding="utf-8") as f:
                for line in f:
                    line = line.strip()
                    if not line:
                        continue
                    try:
                        recs.append(json.loads(line))
                    except json.JSONDecodeError:
                        continue
        except OSError:
            recs = []
        counts, pair = _sprt_resume_counts_core(recs)
        if pair:
            print("[SPRT] resume: pair=%d penta=%s" % (pair, counts),
                  flush=True)
    elif (not resume) and os.path.exists(out_path):
        bak = out_path + time.strftime(".%Y%m%d-%H%M%S") + ("-%06d" % (int(time.time() * 1e6) % 1000000))
        try:
            os.replace(out_path, bak)
            print("[SPRT] existing results moved to %s" % bak, flush=True)
        except OSError as _bak_e:
            _flog(f"[SPRT-BAK-FAIL] os.replace({out_path!r}, {bak!r}): {_bak_e!r}")
            print(f"[SPRT] FATAL: backup of existing {out_path} failed: {_bak_e!r} "
                  "— refusing to overwrite. Resolve manually or use resume=1.", flush=True)
            return

    print("[SPRT] tc=%s  H0: elo<=%g  H1: elo>=%g  bounds=(%.3f, %.3f)"
          % (tc.label, elo0, elo1, lo_b, hi_b), flush=True)

    eng_base = eng_test = None
    decision = "continue"
    try:
        _opponent_path = kv.get("opponent", "").strip()
        if _opponent_path:
            if not os.path.exists(_opponent_path):
                print("[SPRT] opponent not found: %s" % _opponent_path, flush=True)
                return
            _opponent_threads = int(kv.get("opponent_threads",
                                      str(max(1, _safe_cpu_count() // 2))))
            _opponent_hash = int(kv.get("opponent_hash", str(_opponent_default_hash_mb())))
            eng_base = _OpponentEngine(_opponent_path, "opponent",
                                       hash_mb=_opponent_hash, threads=_opponent_threads)
            _test_full = out_path + ".test_config_full.txt"
            _sprt_write_test_config(test_cfg, "Tuning_Worker_Count=2", _test_full)
            eng_test = _SpsaUsiEngine(_test_full, out_path + ".stats_test", "test",
                                      halve=False)
            print("[SPRT] opponent=%s (Hash=%d Threads=%d, no-ponder) vs test=Pyfamate(full-budget)"
                  % (_opponent_path, _opponent_hash, _opponent_threads), flush=True)
            if not (_opponent_init(eng_base) and _spsa_init_engine(eng_test)):
                print("[SPRT] engine init failed — aborting", flush=True)
                return
        else:
            eng_base = _SpsaUsiEngine(base_cfg, out_path + ".stats_base", "base")
            eng_test = _SpsaUsiEngine(test_cfg, out_path + ".stats_test", "test")
            if not (_spsa_init_engine(eng_base) and _spsa_init_engine(eng_test)):
                print("[SPRT] engine init failed — aborting", flush=True)
                return

        while True:
            n_valid = sum(counts)
            if 0 < max_pairs <= n_valid:
                print("[SPRT] max_pairs=%d reached — inconclusive (continue)"
                      % max_pairs, flush=True)
                break
            op = openings[_sprt_opening_index_core(pair, len(openings))]
            games = []
            scores = []
            for gno, (es, eg, t_sente) in enumerate((
                    (eng_test, eng_base, True),
                    (eng_base, eng_test, False))):
                inf: dict = {}
                res = _selfplay_game(es, eg, tc=tc, opening=op,
                                      game_timeout_s=game_timeout_s,
                                      info=inf)
                sc = _sprt_game_score_core(res, t_sente)
                games.append({
                    "g": gno + 1, "result": res, "test_sente": t_sente,
                    "reason": inf.get("reason"), "plies": inf.get("plies"),
                })
                scores.append(sc)
            bucket = _sprt_pair_bucket_core(scores[0], scores[1])
            if bucket is not None:
                counts[bucket] += 1
            llr = _sprt_llr_pentanomial_core(counts, elo0, elo1)
            est = _sprt_elo_estimate_core(counts)
            decision = _sprt_decision_core(llr, alpha, beta)
            rec = {
                "ts": time.strftime("%Y-%m-%dT%H:%M:%S"),
                "pair": pair, "opening": op, "games": games,
                "bucket": bucket, "counts": list(counts),
                "llr": round(llr, 4), "elo": round(est["elo"], 2),
                "lo95": round(est["lo95"], 2) if est["pairs"] else None,
                "hi95": round(est["hi95"], 2) if est["pairs"] else None,
                "decision": decision,
            }
            try:
                with open(out_path, "a", encoding="utf-8") as f:
                    f.write(json.dumps(rec, ensure_ascii=False) + "\n")
            except OSError as e:
                _flog("[SPRT] result append failed: %s" % e)
            print("[SPRT] pair=%d n=%d penta=%s score=%.4f elo=%+.1f "
                  "[%+.1f,%+.1f] LLR=%.3f (%.2f,%.2f) %s"
                  % (pair, sum(counts), counts, est["score"], est["elo"],
                     est["lo95"], est["hi95"], llr, lo_b, hi_b, decision),
                  flush=True)
            pair += 1
            if decision != "continue":
                break
    except KeyboardInterrupt:
        print("\n[SPRT] interrupted — partial results kept in %s" % out_path,
              flush=True)
    finally:
        for e in (eng_base, eng_test):
            if e is not None:
                try:
                    e.quit()
                except Exception as _qe:
                    _flog("[ignored] sprt quit: %s" % _qe)

    est = _sprt_elo_estimate_core(counts)
    llr = _sprt_llr_pentanomial_core(counts, elo0, elo1)
    print("[SPRT] ===== summary =====", flush=True)
    print("[SPRT] pairs=%d penta=%s" % (sum(counts), counts), flush=True)
    print("[SPRT] elo=%+.1f [%+.1f, %+.1f]  LLR=%.3f  decision=%s"
          % (est["elo"], est["lo95"], est["hi95"], llr, decision), flush=True)
    if decision == "H1":
        print("[SPRT] → test 構成を採択 (elo >= %g を支持)" % elo1, flush=True)
    elif decision == "H0":
        print("[SPRT] → 改善なし (elo <= %g を支持)" % elo0, flush=True)
    else:
        print("[SPRT] → 判定未了 (resume=1 で再開可能)", flush=True)




def _corr_counts_core(errs_a, errs_b):
    n11 = n10 = n01 = n00 = 0
    for a, b in zip(errs_a, errs_b):
        if a is None or b is None:
            continue
        if a and b:
            n11 += 1
        elif a:
            n10 += 1
        elif b:
            n01 += 1
        else:
            n00 += 1
    return (n11, n10, n01, n00)


def _corr_joint_ratio_core(n11: int, n10: int, n01: int, n00: int):
    n = n11 + n10 + n01 + n00
    if n <= 0:
        return None
    pa = (n11 + n10) / n
    pb = (n11 + n01) / n
    if pa <= 0.0 or pb <= 0.0:
        return None
    return (n11 / n) / (pa * pb)


def _corr_kappa_core(n11: int, n10: int, n01: int, n00: int):
    n = n11 + n10 + n01 + n00
    if n <= 0:
        return None
    po = (n11 + n00) / n
    pa1 = (n11 + n10) / n
    pb1 = (n11 + n01) / n
    pe = pa1 * pb1 + (1.0 - pa1) * (1.0 - pb1)
    if abs(1.0 - pe) < 1e-12:
        return None
    return (po - pe) / (1.0 - pe)


def _corr_pearson_core(xs, ys):
    pairs = [(x, y) for x, y in zip(xs, ys) if x is not None and y is not None]
    n = len(pairs)
    if n < 3:
        return None
    mx = sum(p[0] for p in pairs) / n
    my = sum(p[1] for p in pairs) / n
    sxx = sum((p[0] - mx) ** 2 for p in pairs)
    syy = sum((p[1] - my) ** 2 for p in pairs)
    sxy = sum((p[0] - mx) * (p[1] - my) for p in pairs)
    if sxx <= 1e-12 or syy <= 1e-12:
        return None
    return sxy / math.sqrt(sxx * syy)


def _corr_error_vectors_core(rows, names, err_cp: int):
    pol = {nm: [] for nm in names}
    val = {nm: [] for nm in names}
    res = {nm: [] for nm in names}
    for row in rows:
        lm = row.get("label_move")
        lc = row.get("label_cp")
        eng = row.get("engines", {})
        for nm in names:
            e = eng.get(nm) or {}
            mv = e.get("move")
            cp = e.get("cp")
            pol[nm].append(None if (mv is None or not lm) else (mv != lm))
            if cp is None or lc is None:
                val[nm].append(None)
                res[nm].append(None)
            else:
                res[nm].append(cp - lc)
                val[nm].append(abs(cp - lc) > err_cp)
    return pol, val, res


def _corr_condition_mask_core(pol_errs: dict, names) -> list:
    if not names:
        return []
    length = len(next(iter(pol_errs.values()), []))
    return [any(pol_errs[nm][i] is False for nm in names) for i in range(length)]


def _corr_apply_mask_core(vec: list, mask: list) -> list:
    return [v if m else None for v, m in zip(vec, mask)]


def _corr_report_core(rows, names, err_cp: int = 150) -> dict:
    pol, _val, res = _corr_error_vectors_core(rows, names, err_cp)
    mask = _corr_condition_mask_core(pol, names)
    out = {"n": len(rows), "engines": {}, "pairs": []}
    for nm in names:
        known = [e for e in pol[nm] if e is not None]
        rs = [r for r in res[nm] if r is not None]
        out["engines"][nm] = {
            "n": len(known),
            "match_rate": ((len(known) - sum(known)) / len(known))
                          if known else None,
            "mean_abs_resid": (sum(abs(r) for r in rs) / len(rs))
                              if rs else None,
        }
    for i in range(len(names)):
        for j in range(i + 1, len(names)):
            a, b = names[i], names[j]
            c = _corr_counts_core(pol[a], pol[b])
            cc = _corr_counts_core(_corr_apply_mask_core(pol[a], mask),
                                   _corr_apply_mask_core(pol[b], mask))
            out["pairs"].append({
                "a": a, "b": b,
                "policy": {
                    "n11": c[0], "n10": c[1], "n01": c[2], "n00": c[3],
                    "ratio": _corr_joint_ratio_core(*c),
                    "kappa": _corr_kappa_core(*c),
                },
                "policy_cond": {
                    "n11": cc[0], "n10": cc[1], "n01": cc[2], "n00": cc[3],
                    "ratio": _corr_joint_ratio_core(*cc),
                    "kappa": _corr_kappa_core(*cc),
                },
                "resid_pearson": _corr_pearson_core(res[a], res[b]),
            })
    return out


_CORR_SCORE_RE = None


def _corr_collect_one(eng, sfen: str, byoyomi_ms: int,
                      wait_margin_s: float = 10.0):
    global _CORR_SCORE_RE
    if _CORR_SCORE_RE is None:
        _CORR_SCORE_RE = re.compile(r"score (cp|mate) (-?\d+)")
    eng.send("position sfen %s" % sfen)
    eng.send("go btime 0 wtime 0 byoyomi %d" % int(byoyomi_ms))
    deadline = time.perf_counter() + byoyomi_ms / 1000.0 + wait_margin_s
    cp = None
    move = None
    while time.perf_counter() < deadline:
        line = eng.readline(timeout=max(0.1, deadline - time.perf_counter()))
        if not line:
            continue
        m = _CORR_SCORE_RE.search(line)
        if m:
            kind, v = m.group(1), int(m.group(2))
            if kind == "cp":
                cp = v
            else:
                cp = (32000 - min(abs(v), 1000)) * (1 if v >= 0 else -1)
        if line.startswith("bestmove"):
            move = (line.split() + [""])[1] or None
            break
    return (move, cp)


def _corr_resolve_engines(spec: str) -> list:
    def _slot_path(slot: str) -> str:
        g = globals().get(slot + "_PATH")
        if g:
            return g
        pool = "DL_Pool_" if slot.startswith("DL") else "nnue_Pool_"
        try:
            return _resolve_pool_path(pool, None,
                                      slot + "_Engine_Index",
                                      slot + "_Path") or ""
        except Exception:
            return str(_cfg.get(slot + "_Path", "") or "")

    items = [s.strip() for s in (spec or "").split(",") if s.strip()] or \
            ["DL_1", "DL_2", "DL_3", "nnue_1", "nnue_2"]
    out = []
    for it in items:
        if "=" in it:
            nm, _, p = it.partition("=")
            out.append((nm.strip(), p.strip()))
            continue
        p = _slot_path(it)
        if p:
            out.append((it, p))
        else:
            print("[CORR] slot %s: path 未解決 — 除外" % it, flush=True)
    return out


def _corr_child_options(slot: str) -> dict:
    opts = {}
    pre = slot + "_"
    for k, v in _cfg.items():
        if not k.startswith(pre):
            continue
        suf = k[len(pre):]
        if suf in ("Path", "Engine_Index"):
            continue
        opts[suf] = v
    return opts


def _corr_cli(args: list) -> None:
    kv = {}
    for a in args:
        if "=" in a:
            k, _, v = a.partition("=")
            kv[k.strip()] = v.strip()
    path = kv.get("bin", "")
    if not path:
        print("[CORR] specify bin=<teacher.bin>", flush=True)
        return
    ok, msg = _psv_file_sanity(path)
    if not ok:
        print("[CORR] psv sanity NG: %s" % msg, flush=True)
        return
    positions = int(kv.get("positions", "300"))
    start = int(kv.get("start", "0"))
    stride = max(1, int(kv.get("stride", "1")))
    byoyomi = int(kv.get("byoyomi", "1000"))
    err_cp = int(kv.get("err_cp", "150"))
    out_path = kv.get("out") or os.path.join(_BASE_DIR,
                                             "corr_results.txt")
    engines = _corr_resolve_engines(kv.get("engines", ""))
    if len(engines) < 2:
        print("[CORR] 相関には 2 エンジン以上が必要 (解決済み: %s)"
              % [n for n, _ in engines], flush=True)
        return
    names = [n for n, _ in engines]
    print("[CORR] engines: %s" % names, flush=True)

    procs = []
    rows: list = []
    try:
        for nm, p in engines:
            eng = USIEngine(p, "corr_" + nm)
            eng.start()
            eng.initialize(_corr_child_options(nm))
            if eng.wait_for("readyok", timeout=300) is None:
                print("[CORR] %s: readyok timeout — 中止" % nm, flush=True)
                return
            eng.send("usinewgame")
            procs.append((nm, eng))

        recs = _parse_psv_records(path, positions,
                                   start=start, stride=stride)
        used = 0
        for idx, sfen, label_mv, label_cp, _ply, _res in recs:
            row = {"idx": idx, "sfen": sfen,
                   "label_move": label_mv, "label_cp": label_cp,
                   "engines": {}}
            for nm, eng in procs:
                mv, cp = _corr_collect_one(eng, sfen, byoyomi)
                row["engines"][nm] = {"move": mv, "cp": cp}
            rows.append(row)
            used += 1
            try:
                with open(out_path, "a", encoding="utf-8") as f:
                    f.write(json.dumps(row, ensure_ascii=False) + "\n")
            except OSError as e:
                _flog("[CORR] append failed: %s" % e)
            if used % 10 == 0:
                print("[CORR] %d/%d" % (used, positions), flush=True)
            if used >= positions:
                break
    except KeyboardInterrupt:
        print("\n[CORR] interrupted — %d 局面で集計します" % len(rows),
              flush=True)
    finally:
        for _nm, eng in procs:
            try:
                eng.quit()
            except Exception as _qe:
                _flog("[ignored] corr quit: %s" % _qe)

    if not rows:
        print("[CORR] 採取 0 件", flush=True)
        return
    rep = _corr_report_core(rows, names, err_cp=err_cp)
    print("[CORR] ===== report (n=%d, err_cp=%d) =====" % (rep["n"], err_cp),
          flush=True)
    for nm in names:
        e = rep["engines"][nm]
        mr = "%.3f" % e["match_rate"] if e["match_rate"] is not None else "-"
        ar = "%.0f" % e["mean_abs_resid"] if e["mean_abs_resid"] is not None else "-"
        print("[CORR] %-10s match=%s |resid|=%s (n=%d)"
              % (nm, mr, ar, e["n"]), flush=True)
    print("[CORR] pair                ratio  kappa | cond:ratio kappa | resid_r",
          flush=True)
    for pr in rep["pairs"]:
        def _f(x, fmt="%.2f"):
            return (fmt % x) if x is not None else "-"
        print("[CORR] %-9s x %-9s %5s  %5s |     %5s %5s | %s"
              % (pr["a"], pr["b"],
                 _f(pr["policy"]["ratio"]), _f(pr["policy"]["kappa"]),
                 _f(pr["policy_cond"]["ratio"]), _f(pr["policy_cond"]["kappa"]),
                 _f(pr["resid_pearson"])), flush=True)
    try:
        with open(out_path + ".report.txt", "w", encoding="utf-8") as f:
            json.dump(rep, f, indent=2, ensure_ascii=False)
        print("[CORR] report → %s.report.txt" % out_path, flush=True)
    except OSError as e:
        _flog("[CORR] report write failed: %s" % e)





