_GP_HAND_VALUES = {"P": 1, "L": 3, "N": 3, "S": 5, "G": 5, "B": 8, "R": 10}


def _game_phase_state_counts_core(board: "ShogiBoard") -> tuple:
    whand = (sum(cnt * _GP_HAND_VALUES.get(pc.upper(), 1)
                 for pc, cnt in board.sente_hand.items()) +
             sum(cnt * _GP_HAND_VALUES.get(pc.upper(), 1)
                 for pc, cnt in board.gote_hand.items()))
    promoted = 0
    enemy_camp = 0
    king_positions = {}
    cells = []
    for (c, r), pc in board.board.items():
        if pc.startswith("+"):
            promoted += 1
        base = pc.lstrip("+")
        if base == "K":
            king_positions["b"] = (c, r)
            continue
        elif base == "k":
            king_positions["w"] = (c, r)
            continue
        is_sente = base.isupper()
        cells.append((c, r, is_sente))
        if is_sente and r <= 3:
            enemy_camp += 1
        elif (not is_sente) and r >= 7:
            enemy_camp += 1
    ally_ring1 = 0
    for side, is_ally_sente in [("b", True), ("w", False)]:
        kp = king_positions.get(side)
        if kp is None:
            continue
        kc, kr = kp
        for cc, cr, piece_sente in cells:
            if piece_sente == is_ally_sente and max(abs(cc - kc), abs(cr - kr)) == 1:
                ally_ring1 += 1
    exposure = 16 - ally_ring1
    return (whand, promoted, enemy_camp, board.king_advance_signal(), exposure)


_GP_PARAM_VIEW_CFG_CACHE = None


def _game_phase_param_view(vec=None) -> "_GpParamView":
    if vec is not None:
        return _game_phase_fit_make_view(list(vec))
    global _GP_PARAM_VIEW_CFG_CACHE
    if _GP_PARAM_VIEW_CFG_CACHE is None:
        _GP_PARAM_VIEW_CFG_CACHE = _game_phase_fit_make_view(
            [_cfloat(_cfg, k, d)
             for k, d in zip(_GAME_PHASE_FIT_KEYS, _GAME_PHASE_DEFAULT_VEC)])
    return _GP_PARAM_VIEW_CFG_CACHE


def _game_phase_value_state(board: "ShogiBoard", vec=None, ply: int = 0) -> float:
    whand, promoted, enemy_camp, king, exposure = _game_phase_state_counts_core(board)
    return _calc_state_phase(whand, promoted, enemy_camp, king, exposure,
                             cfg=_game_phase_param_view(vec), ply=ply)


